/* AUTO-GENERATED — West Virginia Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["WV"] = {"code":"WV","name":"West Virginia","agency":"West Virginia DMV","agencyShort":"DMV","handbook":"https://transportation.wv.gov/DMV/DMVFormSearch/WV-CDL-Manual.pdf","links":{},"en":[{"q":"On West Virginia highways having a minimum lane width of ten feet (including designated and Interstate routes), what is the maximum allowable outside width of a vehicle or its load?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"answer":1,"explanation":"Under W.Va. Code 17C-17-2, total outside width may not exceed 96 inches, except a vehicle of 102 inches (8 feet 6 inches) may operate on U.S. DOT-designated highways or any highway with a minimum lane width of 10 feet. Source: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, including its load, on West Virginia highways?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"answer":2,"explanation":"W.Va. Code 17C-17-4 provides that a vehicle, including any load, may not exceed a height of 13 feet 6 inches on any West Virginia route. Source: W.Va. Code 17C-17-4; WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"In West Virginia, what is the maximum gross weight on a single axle?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"West Virginia limits a single axle to 20,000 pounds, consistent with the federal standard. Source: W.Va. Code 17C-17-8 / 17C-17-9; WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"In West Virginia, what is the maximum gross weight permitted on a tandem axle group?","options":["20,000 pounds","32,000 pounds","34,000 pounds","40,000 pounds"],"answer":2,"explanation":"West Virginia limits a tandem axle to 34,000 pounds, matching the federal axle-weight standard. Source: W.Va. Code 17C-17-8a / 17C-17-9; WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"What is the maximum legal gross vehicle weight for a vehicle or combination operating on the Interstate (national system of interstate and defense highways) in West Virginia, absent a permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"answer":1,"explanation":"W.Va. Code 17C-17-9 states the maximum gross weight on the national system of interstate and defense highways shall not exceed 80,000 pounds (subject to the bridge formula). Source: W.Va. Code 17C-17-9.","handbook":"","hbref":""},{"q":"In a West Virginia truck tractor-semitrailer combination, what is the maximum semitrailer length allowed when the kingpin-to-rear-axle spacing condition is met?","options":["45 feet","48 feet","53 feet","57 feet"],"answer":2,"explanation":"W.Va. Code 17C-17-4 caps a semitrailer at 48 feet, but allows up to 53 feet where the axle spacing from the truck tractor's rear axle to the semitrailer's front axle is not more than 37 feet. Source: W.Va. Code 17C-17-4.","handbook":"","hbref":""},{"q":"On West Virginia highways with lanes less than 10 feet wide (such as certain local service routes), what is the maximum legal vehicle width?","options":["7 feet 6 inches","8 feet (96 inches)","8 feet 6 inches","9 feet"],"answer":1,"explanation":"The 102-inch (8'6\") allowance applies only on designated routes or lanes 10 feet or wider; on roads with lanes under 10 feet wide the width reverts to the 96-inch (8-foot) limit. Source: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"What is the maximum overall length of a combination of vehicles on West Virginia highways that are NOT Interstate or otherwise designated routes?","options":["53 feet","55 feet","65 feet","75 feet"],"answer":1,"explanation":"W.Va. Code 17C-17-4 limits a combination of vehicles coupled together, inclusive of front and rear bumpers, to an overall length of 55 feet on non-designated highways. Source: W.Va. Code 17C-17-4.","handbook":"","hbref":""},{"q":"What is the maximum extreme overall length of a single motor vehicle (straight truck) in West Virginia?","options":["35 feet","40 feet","45 feet","48 feet"],"answer":1,"explanation":"W.Va. Code 17C-17-4 limits a single motor vehicle, including its load, to 40 feet extreme overall dimension (45 feet is allowed for certain motor homes and school buses). Source: W.Va. Code 17C-17-4.","handbook":"","hbref":""},{"q":"Under West Virginia's adoption of the federal bridge weight provisions, two consecutive sets of tandem axles may each carry 34,000 pounds provided the distance between the first and last axles of the consecutive tandem sets is at least how many feet?","options":["30 feet","34 feet","36 feet","40 feet"],"answer":2,"explanation":"W.Va. Code 17C-17-9 permits two consecutive sets of tandem axles to carry 34,000 pounds each provided the overall distance between the first and last axles of such consecutive tandem sets is 36 feet or more. Source: W.Va. Code 17C-17-9.","handbook":"","hbref":""},{"q":"A West Virginia overweight (single-trip) permit may generally be issued only when the load meets which condition?","options":["The load is nondivisible","The carrier is based in West Virginia","The vehicle has six or more axles","The trip occurs only on Interstates"],"answer":0,"explanation":"West Virginia issues overweight permits only for nondivisible loads that cannot be reduced to legal limits (seagoing containerized cargo is a noted exception). Source: WV DOT Division of Highways Hauling Permits / Permit Types.","handbook":"","hbref":""},{"q":"How does a motor carrier obtain an oversize/overweight hauling permit for West Virginia state-owned routes?","options":["Only in person at a county courthouse","Through the West Virginia DOT/Division of Highways online hauling permit system","From the West Virginia State Police barracks","Permits are not required in West Virginia"],"answer":1,"explanation":"Oversize/overweight permits for Interstate, Turnpike, U.S., WV, and county routes are obtained through the WV DOT Division of Highways online hauling permit system. Source: WV DOT Hauling Permits; wv.gotpermits.com.","handbook":"","hbref":""},{"q":"On U.S. and WV state routes (non-Interstate), West Virginia applies what weight tolerance to its legal axle and gross weight limits?","options":["No tolerance (zero)","5 percent","10 percent","15 percent"],"answer":2,"explanation":"On U.S. and WV routes and local service routes, West Virginia allows a 10 percent tolerance over the legal weight limits, whereas Interstate highways allow zero tolerance. Source: WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"On West Virginia local service routes (non-designated county roads), what is the maximum legal gross vehicle weight before a permit is required?","options":["60,000 pounds","65,000 pounds","73,280 pounds","80,000 pounds"],"answer":1,"explanation":"While Interstate and U.S./WV routes allow up to 80,000 pounds, West Virginia local service routes carry a lower legal gross weight limit of 65,000 pounds. Source: WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"What maximum permitted gross weight applies to a vehicle operating under a West Virginia overweight-and-oversize ANNUAL blanket permit on routes OTHER than the Interstate?","options":["80,000 pounds","90,000 pounds","110,000 pounds","120,000 pounds"],"answer":1,"explanation":"Under a West Virginia overweight/oversize annual (blanket) permit, the maximum gross weight is 90,000 pounds on non-Interstate routes (110,000 pounds on the Interstate). Source: WV DOT Permit Types (Annual/Blanket Permits).","handbook":"","hbref":""},{"q":"Under a West Virginia overweight annual (blanket) permit, what is the maximum permitted weight on a tandem axle?","options":["34,000 pounds","40,000 pounds","45,000 pounds","50,000 pounds"],"answer":2,"explanation":"West Virginia overweight blanket permits allow up to 28,000 pounds on a single axle, 45,000 pounds on a tandem axle, and 50,000 pounds on a tridem axle. Source: WV DOT Permit Types (Annual/Blanket Permits).","handbook":"","hbref":""},{"q":"On a West Virginia designated 'coal resource transportation road,' a vehicle hauling coal under permit may be operated up to a maximum gross weight of approximately what figure?","options":["80,000 pounds","90,000 pounds","120,000 pounds","150,000 pounds"],"answer":2,"explanation":"Under W.Va. Code Chapter 17C, Article 17A, vehicles hauling coal on designated coal resource transportation roads may operate at a greater gross weight of up to 120,000 pounds (with a 5 percent variance), exceeding the limits in 17C-17-9. Source: W.Va. Code 17C-17A; WV PSC coal resource transportation permitting.","handbook":"","hbref":""},{"q":"What is the maximum permitted weight on a single axle under a West Virginia overweight annual (blanket) permit?","options":["20,000 pounds","24,000 pounds","28,000 pounds","34,000 pounds"],"answer":2,"explanation":"A West Virginia overweight blanket permit allows up to 28,000 pounds on a single axle (versus the 20,000-pound legal limit). Source: WV DOT Permit Types (Annual/Blanket Permits).","handbook":"","hbref":""},{"q":"For a West Virginia oversize single-trip permit, during what hours is the oversize movement generally NOT valid?","options":["Sunset to sunrise (nighttime)","Noon to 2 p.m. on weekdays","Any time on Mondays","Only during morning rush hour"],"answer":0,"explanation":"A West Virginia oversize permit is generally not valid during nighttime hours from sunset to sunrise, and no travel is permitted on holidays. Source: WV DOT Hauling Permits / Permit conditions.","handbook":"","hbref":""},{"q":"A West Virginia single-unit (straight) truck with one steering axle and a tandem axle group is generally limited to what maximum gross vehicle weight before applying the allowed tolerance?","options":["48,000 pounds","54,000 pounds","60,000 pounds","66,000 pounds"],"answer":2,"explanation":"A West Virginia single-unit truck having one steering axle and two axles in tandem is limited to a maximum gross weight of 60,000 pounds (before the 10 percent tolerance on non-Interstate routes). Source: WV DOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"In West Virginia, which CDL class is required to operate a combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the vehicle being towed has a GVWR of more than 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"West Virginia adopts the federal classification: a Class A CDL covers any combination of vehicles with a GCWR of 26,001 lbs or more, provided the towed unit has a GVWR exceeding 10,000 lbs. Source: WV DMV Commercial Driver's License page and WV CDL Manual.","handbook":"","hbref":""},{"q":"Under West Virginia rules, a single vehicle with a GVWR of 26,001 pounds or more (or such a vehicle towing a unit not over 10,000 pounds) requires which CDL class?","options":["Class A","Class B","Class C","Class E"],"answer":1,"explanation":"A Class B CDL in West Virginia authorizes a single vehicle with a GVWR of 26,001 lbs or more, including towing a unit with a GVWR of 10,000 lbs or less. Source: WV DMV CDL page and WV CDL Manual.","handbook":"","hbref":""},{"q":"A West Virginia driver operates a vehicle under 26,001 pounds that is designed to carry 16 or more passengers (including the driver) or that is used to transport placarded hazardous materials. Which CDL class applies?","options":["Class A","Class B","Class C","No CDL required"],"answer":2,"explanation":"A Class C CDL covers vehicles that do not meet Class A or B weight thresholds but are designed to transport 16 or more passengers (including the driver) or carry hazardous materials requiring placards. Source: WV DMV CDL page and WV CDL Manual.","handbook":"","hbref":""},{"q":"Which endorsement code on a West Virginia CDL authorizes the transport of hazardous materials requiring placards?","options":["N","H","T","X"],"answer":1,"explanation":"The 'H' endorsement authorizes transport of placarded hazardous materials. The 'X' code is a combined Tank-plus-HazMat endorsement. Source: WV CDL Manual, Endorsements section.","handbook":"","hbref":""},{"q":"On a West Virginia CDL, which endorsement is required to operate a tank vehicle hauling liquid or gaseous materials in a permanently mounted tank?","options":["T (Doubles/Triples)","N (Tank)","P (Passenger)","H (HazMat)"],"answer":1,"explanation":"The 'N' (Tank) endorsement is required for tank vehicles carrying liquids or gases in bulk. The 'T' endorsement is for double and triple trailers, a separate authorization. Source: WV CDL Manual, Endorsements section.","handbook":"","hbref":""},{"q":"A West Virginia CDL holder wants to pull double or triple trailers. Which endorsement must be added?","options":["N","S","T","P"],"answer":2,"explanation":"The 'T' endorsement authorizes the operation of double and triple trailer combinations and requires passing a knowledge test. Source: WV CDL Manual, Endorsements section.","handbook":"","hbref":""},{"q":"To carry passengers for hire on a bus in West Virginia (for example, a transit or motorcoach), which CDL endorsement is required?","options":["S endorsement","P endorsement","N endorsement","H endorsement"],"answer":1,"explanation":"The 'P' (Passenger) endorsement is required to operate a vehicle designed to carry 16 or more passengers and requires both a knowledge test and a road skills test in a representative vehicle. Source: WV CDL Manual, Endorsements section.","handbook":"","hbref":""},{"q":"Which endorsement does West Virginia require for a driver to operate a school bus, in addition to the Passenger (P) endorsement?","options":["S endorsement","T endorsement","N endorsement","X endorsement"],"answer":0,"explanation":"The 'S' (School Bus) endorsement is required to drive a school bus and is obtained in addition to the 'P' endorsement; it requires a knowledge test and a road skills test in a school bus. Source: WV CDL Manual, Endorsements section.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a West Virginia CDL for INTRASTATE driving (operating only within West Virginia)?","options":["16 years","18 years","21 years","25 years"],"answer":1,"explanation":"An applicant must be at least 18 years old to obtain a CDL valid for intrastate (within West Virginia) commerce. Source: WV CDL Manual / WV DMV CDL requirements.","handbook":"","hbref":""},{"q":"What is the minimum age required to be issued a West Virginia CDL for INTERSTATE driving (across state lines)?","options":["18 years","19 years","21 years","23 years"],"answer":2,"explanation":"Federal rules adopted by West Virginia require a driver to be at least 21 years old to operate a commercial motor vehicle in interstate commerce or to carry hazardous materials. Source: WV CDL Manual / 49 CFR 391.11 as applied by WV DMV.","handbook":"","hbref":""},{"q":"After obtaining a West Virginia Commercial Learner's Permit (CLP), how long must the applicant hold it before being eligible to take the CDL road skills test?","options":["A minimum of 14 days","A minimum of 30 days","A minimum of 7 days","A minimum of 60 days"],"answer":0,"explanation":"Federal law adopted by West Virginia requires the applicant to hold the CLP for at least 14 days before taking the skills (road) test. Source: WV DMV CDL page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Regarding renewal, which statement best describes the West Virginia Commercial Learner's Permit (CLP)?","options":["It is not renewable and its validity may not exceed one year","It may be renewed an unlimited number of times","It is valid for five years like a regular license","It never expires once issued"],"answer":0,"explanation":"The WV DMV CDL page states the Commercial Learner's Permit may not exceed one year in validity and is not renewable. Source: WV DMV Commercial Driver's License page.","handbook":"","hbref":""},{"q":"While driving a commercial motor vehicle on a West Virginia CLP, the permit holder must be accompanied by which of the following?","options":["The holder of a CDL valid for that vehicle type, seated beside the driver","Any licensed driver over 21 in any seat of the vehicle","A DMV examiner only","No one; the CLP allows solo driving"],"answer":0,"explanation":"A CLP holder may operate a CMV only when accompanied by the holder of a valid CDL for that class/type of vehicle who occupies the seat beside the permit holder. Source: WV DMV CDL page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"What is the minimum passing score on the West Virginia CDL knowledge (written) tests?","options":["70%","75%","80%","90%"],"answer":2,"explanation":"West Virginia requires a minimum score of 80% to pass each CDL knowledge test (the HazMat test must be taken in written form). Source: WV DMV CDL testing requirements.","handbook":"","hbref":""},{"q":"Before West Virginia can issue a HazMat (H) endorsement, what federal screening must the applicant pass?","options":["A Transportation Security Administration (TSA) security threat assessment","A credit history review","A state-only criminal records check with no fingerprints","A vision-only medical screening"],"answer":0,"explanation":"Federal law adopted by West Virginia requires applicants for a HazMat endorsement to pass a TSA security threat assessment, which includes fingerprinting and a background check, before the endorsement is issued or renewed. Source: WV CDL Manual; 49 CFR 1572 (TSA).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a HazMat (H) endorsement on a West Virginia CDL?","options":["18 years","21 years","25 years","19 years"],"answer":1,"explanation":"Because hazardous materials transport requires interstate-qualified status under federal rules, an applicant must be at least 21 years old to obtain the HazMat endorsement. Source: WV CDL Manual; TSA/FMCSA HazMat requirements.","handbook":"","hbref":""},{"q":"First-time CDL applicants in West Virginia must complete Entry-Level Driver Training (ELDT) through a provider that is:","options":["Listed on the FMCSA Training Provider Registry (TPR)","Approved only by the West Virginia State Police","Any private driving school of the applicant's choice","Certified by the TSA"],"answer":0,"explanation":"ELDT must be completed with a provider listed on the FMCSA Training Provider Registry (TPR). It applies to those obtaining a Class A or B CDL for the first time, upgrading B to A, or seeking a first-time P, S, or H endorsement (on or after Feb 7, 2022). Source: FMCSA ELDT rule; WV DMV CDL page.","handbook":"","hbref":""},{"q":"Which of the following is one of the four medical self-certification categories a West Virginia CDL applicant must choose from?","options":["Non-Excepted Interstate (NI)","Recreational Interstate (RI)","Commercial Exempt (CE)","Limited Local (LL)"],"answer":0,"explanation":"The four self-certification categories are Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Drivers in non-excepted categories must hold a valid DOT medical examiner's certificate. Source: WV DMV CDL self-certification; FMCSA.","handbook":"","hbref":""},{"q":"A West Virginia CDL driver who certifies as 'Non-Excepted Interstate (NI)' must provide which document?","options":["A valid medical examiner's certificate (DOT medical card)","A motor vehicle insurance binder only","A signed employer exemption letter","Nothing additional beyond the application"],"answer":0,"explanation":"Drivers certifying to a non-excepted category (NI or NA) must obtain and submit a valid medical examiner's certificate from an examiner on the FMCSA National Registry; excepted categories (EI, EA) do not require a DOT medical card. Source: WV DMV CDL self-certification; FMCSA.","handbook":"","hbref":""},{"q":"When applying for a West Virginia CDL or CLP, how many proofs of West Virginia residency does the DMV require?","options":["One proof of residency","Two proofs of residency","Three proofs of residency","No residency proof is required"],"answer":1,"explanation":"West Virginia requires one proof of identity/lawful presence, one proof of Social Security number, and two proofs of West Virginia residency for a CDL/CLP application. Source: WV DMV acceptable documents / driver license requirements.","handbook":"","hbref":""},{"q":"Under West Virginia law, at what blood alcohol concentration (BAC) is a driver considered to be operating a commercial motor vehicle (CMV) with too much alcohol, triggering disqualification?","options":["0.08% or more","0.02% or more","0.10% or more","0.04% or more"],"answer":3,"explanation":"West Virginia sets the CMV alcohol limit at 0.04% (\"four hundredths of one percent or more, by weight\"), half the 0.08% limit for personal vehicles. Source: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)(2).","handbook":"","hbref":""},{"q":"In West Virginia, a CMV driver found to have any detectable amount of alcohol below 0.04% must be:","options":["Immediately disqualified for 1 year","Placed out-of-service for 24 hours","Fined $2,500 with no out-of-service period","Issued a warning only with no penalty"],"answer":1,"explanation":"A CMV driver with any detectable measurable alcohol under 0.04% is placed out-of-service for 24 hours, even though it is below the disqualifying 0.04% threshold. Source: WV CDL Manual Section 1.3 and Implied Consent provisions; WV Code 17E-1-13.","handbook":"","hbref":""},{"q":"What is the disqualification period in West Virginia for a CMV driver's FIRST major offense, such as DUI or a 0.04% BAC, when NOT transporting placarded hazardous materials?","options":["60 days","3 years","1 year","6 months"],"answer":2,"explanation":"A first major offense (DUI, 0.04% BAC, refusal, leaving the scene, using a vehicle in a felony, etc.) results in a 1-year CDL disqualification in West Virginia. Source: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b).","handbook":"","hbref":""},{"q":"If a West Virginia CMV driver commits a first major offense WHILE transporting hazardous materials required to be placarded, the disqualification period is:","options":["3 years","1 year","5 years","180 days"],"answer":0,"explanation":"A first major offense committed while operating a CMV transporting placarded hazardous materials (per 49 CFR Part 172, Subpart F) carries an enhanced disqualification of 3 years instead of 1 year. Source: WV CDL Manual; WV Code 17E-1-13(b)(1)(C).","handbook":"","hbref":""},{"q":"What is the disqualification period in West Virginia for a SECOND major offense (in a separate incident)?","options":["10 years","Life","3 years","5 years"],"answer":1,"explanation":"A second major offense in a separate incident results in a lifetime CDL disqualification in West Virginia. The DMV may allow reinstatement after a minimum period under certain conditions, but it is imposed as a lifetime disqualification. Source: WV CDL Manual; WV Code 17E-1-13(b)(1)(D).","handbook":"","hbref":""},{"q":"In West Virginia, refusing to submit to a designated chemical (secondary) test while operating a CMV results in what disqualification for a first refusal?","options":["60 days","1 year","90 days","30 days"],"answer":1,"explanation":"A test refusal is treated like a major offense: a first refusal disqualifies the driver for 1 year (3 years if transporting placarded hazardous materials), and a second results in a lifetime disqualification. Source: WV CDL Manual; WV Code 17E-1-13(b)(3).","handbook":"","hbref":""},{"q":"Under West Virginia's Implied Consent Law, by accepting the privilege of driving in the state, a driver is deemed to have consented to:","options":["A vehicle search at any traffic stop","A mandatory DUI education course","Random roadside drug-dog inspections","A chemical test to determine the alcohol content in their body"],"answer":3,"explanation":"West Virginia's Implied Consent Law means any person who drives in the state has consented to take the designated chemical test for alcohol content. Refusal suspends driving privileges for at least 1 year, up to life. Source: WV CDL Manual, Implied Consent Law; WV Code 17C-5-4.","handbook":"","hbref":""},{"q":"Under the West Virginia Implied Consent Law, refusing a chemical test suspends a driver's privilege to operate a motor vehicle for what minimum period?","options":["At least 90 days","At least 30 days","At least 1 year","At least 6 months"],"answer":2,"explanation":"Refusing the designated chemical test under West Virginia's Implied Consent Law suspends the privilege to operate a motor vehicle for a period of at least 1 year, and up to life. Source: WV CDL Manual, Implied Consent Law.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period trigger a disqualification of 60 days in West Virginia?","options":["1 (the first violation)","3 (the third within 3 years)","2 (the second within 3 years)","4 (the fourth within 3 years)"],"answer":2,"explanation":"A second serious traffic violation within a 3-year period results in a 60-day disqualification. The first serious violation alone does not disqualify. Source: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c).","handbook":"","hbref":""},{"q":"What is the disqualification period in West Virginia for a THIRD serious traffic violation within a 3-year period?","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"A third or subsequent serious traffic violation within a 3-year period results in a 120-day disqualification. Source: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c).","handbook":"","hbref":""},{"q":"Which of the following is classified as a \"serious traffic violation\" for West Virginia CDL disqualification purposes?","options":["Driving 5 mph over the posted limit","Excessive speeding (15 mph or more over the posted limit)","A parking violation","An expired registration sticker"],"answer":1,"explanation":"Serious traffic violations include excessive speeding (15 mph or more over the posted limit), reckless driving, improper or erratic lane changes, following too closely, and texting while driving. Parking violations are excluded. Source: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c).","handbook":"","hbref":""},{"q":"In West Virginia, what is the disqualification period for a FIRST conviction of violating an out-of-service order while operating a CMV carrying nonhazardous cargo?","options":["90 days","60 days","180 days","1 year"],"answer":2,"explanation":"A first conviction for violating an out-of-service order while operating a CMV results in a 180-day disqualification in West Virginia. Source: WV CDL Manual; WV Code 17E-1-13(e)(1)(A).","handbook":"","hbref":""},{"q":"What is the disqualification period for a SECOND out-of-service order violation within a 10-year period while transporting nonhazardous materials in West Virginia?","options":["180 days","2 years","3 years","1 year"],"answer":1,"explanation":"A second out-of-service order violation in a separate incident within 10 years (nonhazardous) results in a 2-year disqualification. A third or subsequent within 10 years results in 3 years. Source: WV CDL Manual; WV Code 17E-1-13(e)(1)(B).","handbook":"","hbref":""},{"q":"In West Virginia, a SECOND out-of-service order violation within 10 years while transporting placarded hazardous materials OR operating a vehicle designed to carry 16 or more passengers results in what disqualification?","options":["2 years","180 days","1 year","3 years"],"answer":3,"explanation":"A second out-of-service order violation within 10 years while transporting placarded hazmat or carrying 16+ passengers carries an enhanced 3-year disqualification (versus 2 years for nonhazardous). Source: WV CDL Manual; WV Code 17E-1-13(e)(2)(B).","handbook":"","hbref":""},{"q":"What is the disqualification period in West Virginia for a FIRST railroad-highway grade crossing violation while operating a CMV?","options":["30 days","120 days","60 days","180 days"],"answer":2,"explanation":"A first railroad-highway grade crossing violation while operating a CMV results in a 60-day disqualification in West Virginia. Source: WV CDL Manual; WV Code 17E-1-13(d).","handbook":"","hbref":""},{"q":"In West Virginia, the disqualification periods for railroad-highway grade crossing violations escalate from 60 days for a first offense to what for a SECOND and THIRD offense within 3 years?","options":["120 days for the second; 1 year for the third","90 days for the second; 180 days for the third","60 days for the second; 120 days for the third","180 days for the second; 2 years for the third"],"answer":0,"explanation":"Railroad crossing violations disqualify a driver for 60 days (first), 120 days (second within 3 years), and 1 year (third or subsequent within 3 years). Source: WV CDL Manual; WV Code 17E-1-13(d).","handbook":"","hbref":""},{"q":"Under West Virginia and federal rules adopted by the state, a CMV driver's CDL is disqualified after how many convictions for texting while driving a CMV?","options":["1 conviction (the first offense)","4 or more convictions within 3 years","3 or more convictions within 5 years","2 or more convictions within 3 years"],"answer":3,"explanation":"Texting while driving a CMV is a serious violation: the CDL is disqualified for 60 days after a second conviction within 3 years and 120 days for three or more within 3 years. A first conviction does not disqualify but carries a civil penalty. Source: WV CDL Manual Section 2.9.5; WV Code 17E-1-13(c)(9).","handbook":"","hbref":""},{"q":"What is the maximum federal civil penalty (adopted in West Virginia) for a CMV driver who texts or uses a hand-held mobile phone while driving?","options":["Up to $2,750","Up to $500","Up to $11,000","Up to $5,000"],"answer":0,"explanation":"Each texting/hand-held phone violation subjects the CMV driver to a civil penalty of up to $2,750. (Employers who allow or require it may be fined up to $11,000.) Source: WV CDL Manual Sections 2.9.4 and 2.9.5.","handbook":"","hbref":""},{"q":"A West Virginia CDL holder whose personal-vehicle license is suspended for an alcohol, controlled-substance, or felony violation loses CDL privileges for how long on a first violation?","options":["1 year","60 days","90 days","6 months"],"answer":0,"explanation":"If a CDL holder's personal-vehicle privileges are revoked, cancelled, or suspended for alcohol, controlled-substance, or felony violations, the CDL is lost for 1 year; a second such violation (personal vehicle or CMV) results in a lifetime loss. Source: WV CDL Manual Section 1.3; WV Code 17E-1-13(b).","handbook":"","hbref":""},{"q":"Under West Virginia's driver point system, reaching how many points results in suspension of driving privileges?","options":["6 or more points","20 or more points","8 or more points","12 or more points"],"answer":3,"explanation":"The West Virginia DMV point system suspends driving privileges upon reaching 12 or more points. For example, speeding 20 mph or more over the limit is 6 points, and reckless driving is 6 points. Source: WV CDL Manual / WV Driver's Licensing Handbook, Point System.","handbook":"","hbref":""},{"q":"On a NONDIVIDED West Virginia highway, when you cannot safely change lanes away from a stopped emergency or service vehicle showing flashing lights, what is the maximum speed you may pass it at under the state's Move Over law?","options":["15 mph","25 mph","10 mph","20 mph"],"answer":0,"explanation":"West Virginia Code 17C-14-9a (Move Over law) requires a driver who cannot move over to reduce speed to a safe level not to exceed 15 mph on any nondivided highway or street when passing a stationary authorized emergency or service vehicle. Source: WV Code 17C-14-9a.","handbook":"","hbref":""},{"q":"On a DIVIDED West Virginia highway where you cannot safely move to a non-adjacent lane, what is the maximum speed you may pass a stopped emergency vehicle displaying warning lights?","options":["15 mph","35 mph","25 mph","20 mph"],"answer":2,"explanation":"Under WV Code 17C-14-9a, a driver unable to change lanes must reduce speed to a safe level not to exceed 25 mph on any divided highway when passing a stationary emergency or service vehicle. Source: WV Code 17C-14-9a.","handbook":"","hbref":""},{"q":"Under the West Virginia CDL Manual, a placarded HazMat vehicle, a chlorine load, or a cargo tank must stop how far from the nearest rail at a railroad crossing?","options":["Between 10 and 25 feet","Between 15 and 50 feet","Between 5 and 15 feet","Between 25 and 75 feet"],"answer":1,"explanation":"The WV CDL Manual (Section 9.6.12) states a vehicle that is placarded, carries any amount of chlorine, or has cargo tanks used for hazardous materials must stop 15 to 50 feet before the nearest rail. Source: WV CDL Manual, Sec. 9.6.12.","handbook":"","hbref":""},{"q":"A bus driver in West Virginia must stop the bus how far before a railroad crossing?","options":["Between 20 and 40 feet","At least 50 feet","Between 10 and 30 feet","Between 15 and 50 feet"],"answer":3,"explanation":"The WV CDL Manual (Section 4.3.5) directs bus drivers to stop the bus between 15 and 50 feet before railroad crossings, then listen and look in both directions for trains. Source: WV CDL Manual, Sec. 4.3.5.","handbook":"","hbref":""},{"q":"What is the maximum posted speed limit on a West Virginia interstate highway unless otherwise posted?","options":["70 mph","65 mph","75 mph","55 mph"],"answer":0,"explanation":"The WV CDL Manual's designated-speeds table lists interstate highways at 70 mph (unless otherwise posted). Source: WV CDL Manual, designated speeds table; WV Code 17C-6-1.","handbook":"","hbref":""},{"q":"Unless otherwise posted, what is the maximum speed limit in a West Virginia business or residential area?","options":["30 mph","25 mph","20 mph","35 mph"],"answer":1,"explanation":"West Virginia sets a 25 mph maximum in any business or residence district, as shown in the WV CDL Manual designated-speeds table. Source: WV Code 17C-6-1; WV CDL Manual.","handbook":"","hbref":""},{"q":"What is the maximum speed limit in a West Virginia school zone while children are present?","options":["20 mph","25 mph","15 mph","10 mph"],"answer":2,"explanation":"WV Code 17C-6-1 sets 15 mph in a school zone during recess or while children are going to or leaving school; the WV CDL Manual lists the same figure. Source: WV Code 17C-6-1; WV CDL Manual.","handbook":"","hbref":""},{"q":"On an open country highway in West Virginia (not an interstate or controlled-access road), what is the default maximum speed limit unless otherwise posted?","options":["60 mph","65 mph","50 mph","55 mph"],"answer":3,"explanation":"The WV CDL Manual designated-speeds table lists open highways at 55 mph unless otherwise posted, consistent with WV Code 17C-6-1. Source: WV Code 17C-6-1; WV CDL Manual.","handbook":"","hbref":""},{"q":"Under West Virginia Code 17C-12-7, when you meet or overtake a school bus stopped with its warning signal lights flashing to load or unload children, you must:","options":["Stop before reaching the bus and not proceed until the lights stop or the driver signals","Slow to 10 mph and pass with caution","Stop only if you are traveling in the same direction as the bus","Move into the far lane and continue at reduced speed"],"answer":0,"explanation":"WV Code 17C-12-7 requires a driver meeting or overtaking from either direction a school bus with flashing warning lights to stop before reaching the bus and not proceed until the bus moves, the lights stop, or the bus driver signals. Source: WV Code 17C-12-7.","handbook":"","hbref":""},{"q":"Under the West Virginia school-bus law, on which type of roadway does a driver NOT have to stop for a school bus that is on a different roadway where pedestrians are not permitted to cross?","options":["Any four-lane highway","Any road with a center turn lane","A controlled-access highway","A two-lane road with a painted median"],"answer":2,"explanation":"WV Code 17C-12-7 provides that a driver on a controlled-access highway need not stop for a school bus on a different roadway, or adjacent to the highway, where pedestrians are not permitted to cross. A mere painted line or center lane does NOT trigger the exception. Source: WV Code 17C-12-7.","handbook":"","hbref":""},{"q":"After stopping a commercial vehicle on the shoulder of a West Virginia highway, within how many minutes must you place your emergency warning devices?","options":["5 minutes","10 minutes","15 minutes","30 minutes"],"answer":1,"explanation":"The WV CDL Manual states that if you must stop on a road or shoulder you must put out your emergency warning devices within ten minutes. Source: WV CDL Manual, Sec. 2.5.","handbook":"","hbref":""},{"q":"When stopped on a ONE-WAY or DIVIDED West Virginia highway, where should the three reflective triangles be placed?","options":["10 feet, 100 feet, and 100 feet at the front and rear","50 feet, 100 feet, and 500 feet to the rear","10 feet, 50 feet, and 150 feet toward approaching traffic","10 feet, 100 feet, and 200 feet toward the approaching traffic"],"answer":3,"explanation":"The WV CDL Manual directs that on a one-way or divided highway warning devices be placed 10 feet, 100 feet, and 200 feet from the vehicle toward the approaching traffic. Source: WV CDL Manual, Sec. 2.5.","handbook":"","hbref":""},{"q":"If a West Virginia driver does not have reflective triangles, which warning devices does the CDL Manual accept as a substitute for parked-vehicle warning?","options":["At least 6 fusees or 3 liquid-burning flares","At least 2 fusees or 1 liquid-burning flare","A single rotating amber beacon","At least 4 road cones"],"answer":0,"explanation":"The WV CDL Manual lists warning devices for parked vehicles as three reflective triangles or at least 6 fusees or 3 liquid-burning flares. Source: WV CDL Manual, vehicle-inspection/emergency-equipment section.","handbook":"","hbref":""},{"q":"Why does West Virginia prohibit using flares or open-flame warning devices around certain placarded loads?","options":["They are too dim to be seen at night","They are only legal on divided highways","They can ignite flammable cargo such as Class 3 flammable liquids","They drain the vehicle battery"],"answer":2,"explanation":"The WV CDL Manual's 'No Flares!' rule says to use reflective triangles or red electric lights, not burning flares or fuses, around vehicles hauling flammable materials such as Class 3 flammable liquids. Source: WV CDL Manual, Sec. 9.6.4.","handbook":"","hbref":""},{"q":"Under West Virginia's lane-use rule, where must all drivers, including truck traffic, normally travel?","options":["In the center lane to keep the right lane clear for merging","In the far right-hand lane except when passing, turning, or avoiding obstructions","In whichever lane has the least traffic","In the left lane to leave the right lane for slower vehicles"],"answer":1,"explanation":"West Virginia (Chapter 17C, Article 7) requires drivers, including trucks, to default to the far right-hand lane except when overtaking/passing, when the right lane is closed, when traveling below normal traffic speed, or when preparing to turn. Source: WV Code Ch. 17C, Art. 7.","handbook":"","hbref":""},{"q":"On a West Virginia THREE-lane highway, how may a truck use the lanes?","options":["It may use any of the three lanes freely","It must use only the middle lane","It may use the two left lanes and pass in the right lane","It must stay in the right lane but may use the middle lane to pass"],"answer":3,"explanation":"Under West Virginia lane rules, trucks on a three-lane roadway are restricted to the right lane but may move into the middle lane to pass. Source: WV Code Ch. 17C, Art. 7.","handbook":"","hbref":""},{"q":"On a West Virginia FOUR-lane highway, which lanes may a truck tractor pulling a semitrailer use?","options":["The two right-hand lanes","Only the far right lane","Any lane except the far left","The two left-hand lanes"],"answer":0,"explanation":"West Virginia permits truck tractors pulling semitrailers to operate in the two right-hand lanes on a four-lane highway. Source: WV Code Ch. 17C, Art. 7.","handbook":"","hbref":""},{"q":"What is West Virginia's legal maximum vehicle width (without a permit) on Interstate, US, and WV routes with lanes 10 feet or wider?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"answer":2,"explanation":"The WV Division of Highways legal size limits set maximum width at 8 feet 6 inches on Interstate, US, WV, and local routes with lanes 10 feet or greater (8 feet on narrower local routes). Source: WVDOT/Division of Highways Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"What is the legal maximum gross weight (without a permit) for a vehicle on a West Virginia INTERSTATE highway?","options":["65,000 pounds","80,000 pounds","73,280 pounds","90,000 pounds"],"answer":1,"explanation":"West Virginia's legal gross weight limit on interstate highways is 80,000 pounds (zero tolerance); local service routes are limited to 65,000 pounds. Source: WVDOT Legal Size and Weight Limits.","handbook":"","hbref":""},{"q":"Which statement about the West Virginia Turnpike (I-77) is correct for commercial drivers?","options":["Tractor-trailers are banned from the Turnpike entirely","It is a free interstate with no toll plazas","Trucks may use it only between sunrise and sunset","It is a tolled mountain-grade highway where trucks pay tolls at mainline plazas"],"answer":3,"explanation":"The West Virginia Turnpike carries I-77 over steep mountain grades (up to about 5%) and is a toll road with mainline toll plazas (Ghent, Pax, Chelyan) where trucks pay tolls based on size/axles; it also features runaway-truck ramps. Source: WV Parkways Authority / WVDOT Turnpike pages.","handbook":"","hbref":""},{"q":"Which state agency issues Commercial Driver's Licenses (CDLs) in West Virginia?","options":["The West Virginia Division of Motor Vehicles (DMV)","The West Virginia State Police","The West Virginia Public Service Commission","The West Virginia Division of Highways"],"answer":0,"explanation":"In West Virginia, CDLs are issued by the West Virginia Division of Motor Vehicles (DMV), which administers knowledge tests and processes applications. Source: WV DMV Commercial Driver's License page (transportation.wv.gov/DMV/Motor-Carriers/CDL).","handbook":"","hbref":""},{"q":"Before West Virginia issues a full CDL, an applicant must first obtain and hold which credential?","options":["A Commercial Learner's Permit (CLP)","A Class D operator's license endorsement","A federal interstate operating authority","A temporary hardship driving permit"],"answer":0,"explanation":"West Virginia requires applicants to first obtain a Commercial Learner's Permit (CLP) from the DMV, which authorizes supervised practice before the skills test. Source: WV DMV CDL page.","handbook":"","hbref":""},{"q":"In West Virginia, how long must an applicant hold a Commercial Learner's Permit (CLP) before being eligible to take the CDL road skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"West Virginia (following the federal standard) requires the CLP to be held for a minimum of 14 days before the applicant may take the road skills test. Source: WV DMV CDL page; 49 CFR 383.25 as adopted in WV.","handbook":"","hbref":""},{"q":"When self-certifying the type of commercial operation, a West Virginia CDL/CLP applicant must choose from how many categories?","options":["Four categories","Two categories","Three categories","Five categories"],"answer":0,"explanation":"West Virginia requires applicants to self-certify to one of four categories of commercial motor vehicle operation: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Source: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3).","handbook":"","hbref":""},{"q":"Which West Virginia self-certification category requires the driver to maintain a valid DOT Medical Examiner's Certificate on file?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Any driver who only operates in-state is exempt"],"answer":0,"explanation":"Drivers self-certifying to a non-excepted status (NI or NA) must maintain a valid FMCSA Medical Examiner's Certificate; excepted statuses (EI, EA) are exempt from that requirement. Source: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3); FMCSA 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Effective June 23, 2025, how is a West Virginia non-excepted CDL driver's DOT medical information normally provided to the DMV?","options":["The certified medical examiner enters the exam results into a secure electronic database that transmits to the DMV","The driver mails a paper medical card to the DMV after each exam","The driver's employer faxes the medical card to the DMV","The medical card is verified only at the time of license renewal"],"answer":0,"explanation":"As of June 23, 2025, West Virginia no longer accepts paper medical certificates; the certified medical examiner electronically enters exam results into a secure database that is sent to the DMV. Source: WV DMV announcement on improved CDL medical certification process (June 2025).","handbook":"","hbref":""},{"q":"What is the minimum passing score on a West Virginia CDL knowledge (written) test?","options":["80 percent","70 percent","75 percent","90 percent"],"answer":0,"explanation":"West Virginia requires at least 80 percent correct to pass a CDL knowledge test. Source: WV Commercial Driver's License Manual; WV DMV CDL testing rules.","handbook":"","hbref":""},{"q":"The West Virginia CDL skills test is made up of which three parts, in order?","options":["Pre-trip vehicle inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Air brake check, coupling test, and reaction-time test","Backing maneuvers, highway merge, and parallel parking"],"answer":0,"explanation":"The West Virginia CDL skills test consists of three parts: the pre-trip vehicle inspection, the basic vehicle control skills test, and the on-road driving test. Source: WV Commercial Driver's License Manual (Skills Test sections).","handbook":"","hbref":""},{"q":"Who must provide the vehicle used for the West Virginia CDL skills (road) test?","options":["The applicant, who must supply a representative vehicle of the class being tested","The DMV, which provides a standard test truck","The Division of Highways motor pool","Any vehicle is acceptable, including a passenger car"],"answer":0,"explanation":"The applicant must provide the vehicle for the skills test, and it must be representative of the class of CDL for which the applicant is testing. Source: WV Commercial Driver's License Manual; WV DMV CDL page.","handbook":"","hbref":""},{"q":"A first-time West Virginia CDL applicant must complete Entry-Level Driver Training (ELDT) before taking which test?","options":["The CDL skills (road) test","The vision screening","The Class D renewal test","The fingerprint background check"],"answer":0,"explanation":"ELDT (theory and behind-the-wheel) must be completed before the CDL skills test for first-time Class A/B applicants and certain endorsements. Source: WV DMV CDL page; FMCSA ELDT rule (49 CFR Part 380), effective February 7, 2022.","handbook":"","hbref":""},{"q":"Under the federal ELDT rule applied in West Virginia, a driver is treated as a 'first-time' CDL applicant (and must complete ELDT) if they had never held a CDL before which date?","options":["February 7, 2022","January 1, 2020","October 1, 2021","June 23, 2025"],"answer":0,"explanation":"ELDT requirements are not retroactive: a person who had never held a CDL (or the relevant S, P, or H endorsement) before February 7, 2022 is a first-time applicant who must complete ELDT. Source: WV DMV CDL page; FMCSA ELDT final rule.","handbook":"","hbref":""},{"q":"Where must a West Virginia ELDT training provider be listed for the training to count toward CDL eligibility?","options":["On the FMCSA Training Provider Registry (TPR)","On the West Virginia DMV vendor list only","On the state Division of Highways contractor roster","On the National CDL Examiner Directory"],"answer":0,"explanation":"ELDT must be completed through a provider listed on the FMCSA Training Provider Registry (TPR) for it to satisfy the CDL requirement in West Virginia. Source: WV DMV CDL page; FMCSA TPR (tpr.fmcsa.dot.gov).","handbook":"","hbref":""},{"q":"In West Virginia, what is the minimum age to obtain a CDL for intrastate (in-state only) operation?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"An applicant must be at least 18 to obtain a West Virginia CDL for intrastate operation; interstate operation and hazardous materials require age 21. Source: WV DMV CDL page; WV Code Chapter 17E.","handbook":"","hbref":""},{"q":"What is the minimum age to operate a commercial motor vehicle in interstate commerce or to carry hazardous materials under West Virginia CDL rules?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"West Virginia requires a driver to be at least 21 to operate interstate or to transport placarded hazardous materials; 18-20 year-olds are limited to intrastate operation. Source: WV DMV CDL page; FMCSA 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Under West Virginia's standard 'Drive for Five' cycle, a CDL is generally valid for what period?","options":["Five years, expiring on the holder's birthday in a year their age is divisible by five","Four years, on a fixed renewal date","Eight years from the date of issue","Two years, matching the DOT medical card"],"answer":0,"explanation":"West Virginia CDLs are renewed on the standard five-year cycle, expiring on the applicant's birthday in a year in which the applicant's age is evenly divisible by five. Source: WV Code 17E-1-12; WV DMV.","handbook":"","hbref":""},{"q":"A West Virginia CDL issued to a driver who is under 21 expires at what point?","options":["30 days after the applicant's birthday in the year the applicant turns 21","On the driver's 18th birthday","Five years from the issue date regardless of age","Immediately upon turning 21"],"answer":0,"explanation":"A West Virginia CDL issued to a person who has not reached age 21 expires 30 days after the applicant's birthday in the year the applicant attains age 21, since interstate/hazmat eligibility changes at 21. Source: WV Code Chapter 17E; WV DMV.","handbook":"","hbref":""},{"q":"Which document does a West Virginia applicant use to self-certify the type of commercial driving they expect to perform?","options":["The WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3)","The federal Form MCSA-5876 medical certificate","The Class D operator's license application","The IRP apportioned registration form"],"answer":0,"explanation":"Applicants self-certify their operation type on the WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3); Form MCSA-5876 is the separate medical examiner's certificate. Source: WV DMV CDL forms.","handbook":"","hbref":""},{"q":"For how long is a DOT Medical Examiner's Certificate considered current under West Virginia CDL rules?","options":["It is not current if more than two years old (and may be issued for a shorter period)","It is valid for five years","It is valid for one year only","It never expires once on file"],"answer":0,"explanation":"A Medical Examiner's Certificate more than two years old is not current; an examiner may issue it for two years or for a shorter interval depending on the driver's condition. Source: WV DMV CDL page; FMCSA 49 CFR 391.45.","handbook":"","hbref":""},{"q":"What generally happens to a West Virginia driver's CDL privileges if a required Medical Examiner's Certificate is allowed to lapse?","options":["The CDL is downgraded so the person loses commercial driving privileges until a valid certificate is on file","Nothing changes until the next five-year renewal","The driver is automatically reclassified as an excepted driver","The driver receives a one-year automatic extension"],"answer":0,"explanation":"If a non-excepted driver's medical certification lapses, West Virginia downgrades the CDL, removing commercial privileges until a current certificate is provided. Source: WV DMV CDL page; FMCSA 49 CFR 383.73 medical certification provisions.","handbook":"","hbref":""},{"q":"In West Virginia, which set of documents is part of the core requirement to apply for a CDL?","options":["Proof of identity/lawful status, proof of West Virginia residency, Social Security verification, and the completed CDL application","Only a passport and a credit card","A vehicle title and proof of insurance only","An employer letter and a high school diploma"],"answer":0,"explanation":"West Virginia CDL applicants must present proof of identity and U.S. citizenship or lawful permanent residency, proof of West Virginia residency, Social Security number verification, and a completed CDL application (plus medical/self-certification documents). Source: WV DMV CDL page.","handbook":"","hbref":""}],"ru":{"0":{"q":"На автомагистралях Западной Виргинии с минимальной шириной полосы десять футов (включая обозначенные маршруты и маршруты системы Interstate) какова максимально допустимая наружная ширина транспортного средства или его груза?","options":["8 футов (96 inches)","8 футов 6 inches (102 inches)","9 футов (108 inches)","10 футов (120 inches)"],"explanation":"Согласно W.Va. Code 17C-17-2, общая наружная ширина не может превышать 96 inches, за исключением того, что транспортное средство шириной 102 inches (8 футов 6 inches) может эксплуатироваться на автомагистралях, обозначенных U.S. DOT, или на любой автомагистрали с минимальной шириной полосы 10 футов. Источник: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits."},"1":{"q":"Какова максимальная допустимая высота транспортного средства, включая его груз, на автомагистралях Западной Виргинии?","options":["12 футов 6 inches","13 футов","13 футов 6 inches","14 футов"],"explanation":"W.Va. Code 17C-17-4 предусматривает, что транспортное средство, включая любой груз, не может превышать высоту 13 футов 6 inches на любом маршруте Западной Виргинии. Источник: W.Va. Code 17C-17-4; WV DOT Legal Size and Weight Limits."},"2":{"q":"В Западной Виргинии какова максимальная полная масса на одиночную ось?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Западная Виргиния ограничивает нагрузку на одиночную ось до 20,000 pounds, что соответствует федеральному стандарту. Источник: W.Va. Code 17C-17-8 / 17C-17-9; WV DOT Legal Size and Weight Limits."},"3":{"q":"В Западной Виргинии какова максимальная полная масса, разрешённая для группы сдвоенных осей (тандема)?","options":["20,000 pounds","32,000 pounds","34,000 pounds","40,000 pounds"],"explanation":"Западная Виргиния ограничивает нагрузку на сдвоенную ось (тандем) до 34,000 pounds, что соответствует федеральному стандарту нагрузки на ось. Источник: W.Va. Code 17C-17-8a / 17C-17-9; WV DOT Legal Size and Weight Limits."},"4":{"q":"Какова максимальная допустимая полная масса транспортного средства или состава, эксплуатируемого на автомагистрали системы Interstate (национальной системе межштатных и оборонных автомагистралей) в Западной Виргинии, при отсутствии разрешения?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"W.Va. Code 17C-17-9 устанавливает, что максимальная полная масса на национальной системе межштатных и оборонных автомагистралей не должна превышать 80,000 pounds (с учётом мостовой формулы). Источник: W.Va. Code 17C-17-9."},"5":{"q":"В составе «седельный тягач — полуприцеп» в Западной Виргинии какова максимальная длина полуприцепа, разрешённая при выполнении условия о расстоянии от шкворня до задней оси?","options":["45 футов","48 футов","53 футов","57 футов"],"explanation":"W.Va. Code 17C-17-4 ограничивает полуприцеп до 48 футов, но допускает до 53 футов, если расстояние между осями от задней оси седельного тягача до передней оси полуприцепа составляет не более 37 футов. Источник: W.Va. Code 17C-17-4."},"6":{"q":"На автомагистралях Западной Виргинии с шириной полос менее 10 футов (например, на некоторых местных маршрутах) какова максимальная допустимая ширина транспортного средства?","options":["7 футов 6 inches","8 футов (96 inches)","8 футов 6 inches","9 футов"],"explanation":"Допуск в 102 inches (8'6\") применяется только на обозначенных маршрутах или полосах шириной 10 футов и более; на дорогах с полосами шириной менее 10 футов ширина возвращается к пределу в 96 inches (8 футов). Источник: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits."},"7":{"q":"Какова максимальная общая длина состава транспортных средств на автомагистралях Западной Виргинии, которые НЕ являются маршрутами системы Interstate или иными обозначенными маршрутами?","options":["53 футов","55 футов","65 футов","75 футов"],"explanation":"W.Va. Code 17C-17-4 ограничивает состав сцепленных вместе транспортных средств, включая передний и задний бамперы, общей длиной 55 футов на необозначенных автомагистралях. Источник: W.Va. Code 17C-17-4."},"8":{"q":"Какова максимальная предельная общая длина одиночного автотранспортного средства (грузовика с жёсткой рамой) в Западной Виргинии?","options":["35 футов","40 футов","45 футов","48 футов"],"explanation":"W.Va. Code 17C-17-4 ограничивает одиночное автотранспортное средство, включая его груз, до 40 футов предельного общего размера (45 футов допускается для некоторых автодомов и школьных автобусов). Источник: W.Va. Code 17C-17-4."},"9":{"q":"Согласно принятым Западной Виргинией федеральным положениям о мостовой нагрузке, две последовательные группы сдвоенных осей могут нести по 34,000 pounds каждая при условии, что расстояние между первой и последней осями этих последовательных групп тандемов составляет не менее скольких футов?","options":["30 футов","34 футов","36 футов","40 футов"],"explanation":"W.Va. Code 17C-17-9 разрешает двум последовательным группам сдвоенных осей нести по 34,000 pounds каждая при условии, что общее расстояние между первой и последней осями таких последовательных групп тандемов составляет 36 футов или более. Источник: W.Va. Code 17C-17-9."},"10":{"q":"Разрешение на перевес (на одну поездку) в Западной Виргинии, как правило, может быть выдано только при соблюдении грузом какого условия?","options":["Груз неделим","Перевозчик зарегистрирован в Западной Виргинии","Транспортное средство имеет шесть или более осей","Поездка проходит только по автомагистралям Interstate"],"explanation":"Западная Виргиния выдаёт разрешения на перевес только для неделимых грузов, которые невозможно уменьшить до допустимых пределов (морские контейнерные грузы являются отмеченным исключением). Источник: WV DOT Division of Highways Hauling Permits / Permit Types."},"11":{"q":"Как автоперевозчик получает разрешение на перевозку негабаритных/тяжеловесных грузов по маршрутам Западной Виргинии, находящимся в собственности штата?","options":["Только лично в окружном здании суда","Через онлайн-систему разрешений на перевозки WV DOT/Division of Highways","В отделении West Virginia State Police","Разрешения в Западной Виргинии не требуются"],"explanation":"Разрешения на негабаритные/тяжеловесные грузы для маршрутов Interstate, Turnpike, U.S., WV и окружных маршрутов получаются через онлайн-систему разрешений на перевозки WV DOT Division of Highways. Источник: WV DOT Hauling Permits; wv.gotpermits.com."},"12":{"q":"На маршрутах U.S. и WV (не Interstate) Западная Виргиния применяет какой допуск по массе к своим законным пределам нагрузки на ось и полной массы?","options":["Нет допуска (ноль)","5 процентов","10 процентов","15 процентов"],"explanation":"На маршрутах U.S. и WV, а также на местных маршрутах Западная Виргиния допускает 10-процентный допуск сверх законных пределов массы, тогда как на автомагистралях Interstate допуск равен нулю. Источник: WV DOT Legal Size and Weight Limits."},"13":{"q":"На местных маршрутах Западной Виргинии (необозначенных окружных дорогах) какова максимальная допустимая полная масса транспортного средства до того, как потребуется разрешение?","options":["60,000 pounds","65,000 pounds","73,280 pounds","80,000 pounds"],"explanation":"В то время как маршруты Interstate и U.S./WV допускают до 80,000 pounds, местные маршруты Западной Виргинии имеют более низкий законный предел полной массы — 65,000 pounds. Источник: WV DOT Legal Size and Weight Limits."},"14":{"q":"Какая максимальная разрешённая полная масса применяется к транспортному средству, эксплуатируемому по ГОДОВОМУ генеральному разрешению на перевес и негабарит Западной Виргинии на маршрутах, ОТЛИЧНЫХ от Interstate?","options":["80,000 pounds","90,000 pounds","110,000 pounds","120,000 pounds"],"explanation":"По годовому (генеральному) разрешению на перевес/негабарит Западной Виргинии максимальная полная масса составляет 90,000 pounds на маршрутах, не относящихся к Interstate (110,000 pounds на Interstate). Источник: WV DOT Permit Types (Annual/Blanket Permits)."},"15":{"q":"По годовому (генеральному) разрешению на перевес Западной Виргинии какова максимальная разрешённая нагрузка на сдвоенную ось (тандем)?","options":["34,000 pounds","40,000 pounds","45,000 pounds","50,000 pounds"],"explanation":"Генеральные разрешения на перевес Западной Виргинии допускают до 28,000 pounds на одиночную ось, 45,000 pounds на сдвоенную ось (тандем) и 50,000 pounds на тройную ось (тридем). Источник: WV DOT Permit Types (Annual/Blanket Permits)."},"16":{"q":"На обозначенной в Западной Виргинии «дороге для перевозки угольных ресурсов» транспортное средство, перевозящее уголь по разрешению, может эксплуатироваться с максимальной полной массой приблизительно какой величины?","options":["80,000 pounds","90,000 pounds","120,000 pounds","150,000 pounds"],"explanation":"Согласно W.Va. Code Chapter 17C, Article 17A, транспортные средства, перевозящие уголь по обозначенным дорогам для перевозки угольных ресурсов, могут эксплуатироваться с большей полной массой — до 120,000 pounds (с допуском 5 процентов), превышающей пределы, установленные в 17C-17-9. Источник: W.Va. Code 17C-17A; WV PSC coal resource transportation permitting."},"17":{"q":"Какова максимальная разрешённая нагрузка на одиночную ось по годовому (генеральному) разрешению на перевес Западной Виргинии?","options":["20,000 pounds","24,000 pounds","28,000 pounds","34,000 pounds"],"explanation":"Генеральное разрешение на перевес Западной Виргинии допускает до 28,000 pounds на одиночную ось (против законного предела в 20,000 pounds). Источник: WV DOT Permit Types (Annual/Blanket Permits)."},"18":{"q":"Для разрешения Западной Виргинии на негабарит на одну поездку в какие часы движение негабаритного груза, как правило, НЕ действительно?","options":["С заката до восхода (в ночное время)","С полудня до 2 p.m. в будние дни","В любое время по понедельникам","Только в утренний час пик"],"explanation":"Разрешение Западной Виргинии на негабарит, как правило, недействительно в ночные часы с заката до восхода, и движение не допускается в праздничные дни. Источник: WV DOT Hauling Permits / Permit conditions."},"19":{"q":"Одиночный грузовик с жёсткой рамой в Западной Виргинии с одной управляемой осью и группой сдвоенных осей (тандемом), как правило, ограничен какой максимальной полной массой до применения допустимого допуска?","options":["48,000 pounds","54,000 pounds","60,000 pounds","66,000 pounds"],"explanation":"Одиночный грузовик в Западной Виргинии с одной управляемой осью и двумя осями в тандеме ограничен максимальной полной массой 60,000 pounds (до применения 10-процентного допуска на маршрутах, не относящихся к Interstate). Источник: WV DOT Legal Size and Weight Limits."},"20":{"q":"В Западной Виргинии какой класс CDL требуется для управления составом транспортных средств с полной массой состава (GCWR) 26,001 pounds или более, где буксируемое транспортное средство имеет GVWR более 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Западная Виргиния принимает федеральную классификацию: CDL Class A охватывает любой состав транспортных средств с GCWR 26,001 lbs или более при условии, что буксируемая единица имеет GVWR, превышающий 10,000 lbs. Источник: WV DMV Commercial Driver's License page and WV CDL Manual."},"21":{"q":"Согласно правилам Западной Виргинии, одиночное транспортное средство с GVWR 26,001 pounds или более (или такое транспортное средство, буксирующее единицу массой не более 10,000 pounds) требует какого класса CDL?","options":["Class A","Class B","Class C","Class E"],"explanation":"CDL Class B в Западной Виргинии разрешает управление одиночным транспортным средством с GVWR 26,001 lbs или более, включая буксировку единицы с GVWR 10,000 lbs или менее. Источник: WV DMV CDL page and WV CDL Manual."},"22":{"q":"Водитель в Западной Виргинии управляет транспортным средством массой менее 26,001 pounds, которое предназначено для перевозки 16 или более пассажиров (включая водителя) или используется для перевозки опасных грузов, требующих знаков (плакардов). Какой класс CDL применяется?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"CDL Class C охватывает транспортные средства, которые не соответствуют весовым порогам Class A или B, но предназначены для перевозки 16 или более пассажиров (включая водителя) или для перевозки опасных грузов, требующих знаков (плакардов). Источник: WV DMV CDL page and WV CDL Manual."},"23":{"q":"Какой код эндорсмента на CDL Западной Виргинии разрешает перевозку опасных грузов, требующих знаков (плакардов)?","options":["N","H","T","X"],"explanation":"Эндорсмент «H» разрешает перевозку опасных грузов, требующих знаков (плакардов). Код «X» — это объединённый эндорсмент «Цистерна плюс HazMat». Источник: WV CDL Manual, Endorsements section."},"24":{"q":"Какой эндорсмент на CDL Западной Виргинии требуется для управления цистерной, перевозящей жидкие или газообразные вещества в стационарно установленной ёмкости?","options":["T (Сдвоенные/строенные прицепы)","N (Цистерна)","P (Пассажиры)","H (HazMat)"],"explanation":"Эндорсмент «N» (Цистерна) требуется для цистерн, перевозящих жидкости или газы наливом. Эндорсмент «T» предназначен для сдвоенных и строенных прицепов и является отдельным разрешением. Источник: WV CDL Manual, Endorsements section."},"25":{"q":"Держатель CDL Западной Виргинии хочет буксировать сдвоенные или строенные прицепы. Какой эндорсмент необходимо добавить?","options":["N","S","T","P"],"explanation":"Эндорсмент «T» разрешает эксплуатацию составов со сдвоенными и строенными прицепами и требует сдачи теоретического экзамена. Источник: WV CDL Manual, Endorsements section."},"26":{"q":"Чтобы перевозить пассажиров за плату на автобусе в Западной Виргинии (например, на транзитном автобусе или автобусе дальнего следования), какой эндорсмент CDL требуется?","options":["Эндорсмент S","Эндорсмент P","Эндорсмент N","Эндорсмент H"],"explanation":"Эндорсмент «P» (Пассажиры) требуется для управления транспортным средством, предназначенным для перевозки 16 или более пассажиров, и требует как теоретического экзамена, так и дорожного экзамена по навыкам на представительном транспортном средстве. Источник: WV CDL Manual, Endorsements section."},"27":{"q":"Какой эндорсмент требует Западная Виргиния для управления школьным автобусом, в дополнение к пассажирскому эндорсменту (P)?","options":["Эндорсмент S","Эндорсмент T","Эндорсмент N","Эндорсмент X"],"explanation":"Эндорсмент «S» (Школьный автобус) требуется для управления школьным автобусом и получается в дополнение к эндорсменту «P»; он требует теоретического экзамена и дорожного экзамена по навыкам на школьном автобусе. Источник: WV CDL Manual, Endorsements section."},"28":{"q":"Каков минимальный возраст для выдачи CDL Западной Виргинии для ВНУТРИШТАТНОГО вождения (управление только в пределах Западной Виргинии)?","options":["16 лет","18 лет","21 год","25 лет"],"explanation":"Заявитель должен быть не моложе 18 лет, чтобы получить CDL, действительный для внутриштатной (в пределах Западной Виргинии) коммерческой деятельности. Источник: WV CDL Manual / WV DMV CDL requirements."},"29":{"q":"Каков минимальный возраст, необходимый для выдачи CDL Западной Виргинии для МЕЖШТАТНОГО вождения (через границы штатов)?","options":["18 лет","19 лет","21 год","23 года"],"explanation":"Федеральные правила, принятые Западной Виргинией, требуют, чтобы водитель был не моложе 21 года для управления коммерческим автотранспортным средством в межштатной коммерческой деятельности или для перевозки опасных грузов. Источник: WV CDL Manual / 49 CFR 391.11 as applied by WV DMV."},"30":{"q":"После получения коммерческого ученического разрешения (CLP) Западной Виргинии, как долго заявитель должен иметь его, прежде чем получить право сдавать дорожный экзамен CDL по навыкам?","options":["Минимум 14 days","Минимум 30 days","Минимум 7 days","Минимум 60 days"],"explanation":"Федеральный закон, принятый Западной Виргинией, требует, чтобы заявитель имел CLP не менее 14 days, прежде чем сдавать экзамен по навыкам (дорожный). Источник: WV DMV CDL page; 49 CFR 383.25."},"31":{"q":"Что касается продления, какое утверждение наилучшим образом описывает коммерческое ученическое разрешение (CLP) Западной Виргинии?","options":["Оно не подлежит продлению, и срок его действия не может превышать одного года","Оно может продлеваться неограниченное число раз","Оно действительно пять лет, как обычные права","Оно никогда не истекает после выдачи"],"explanation":"Страница CDL WV DMV указывает, что коммерческое ученическое разрешение не может действовать более одного года и не подлежит продлению. Источник: WV DMV Commercial Driver's License page."},"32":{"q":"Управляя коммерческим автотранспортным средством по CLP Западной Виргинии, держатель разрешения должен сопровождаться кем из следующих?","options":["Держателем CDL, действительного для данного типа транспортного средства, сидящим рядом с водителем","Любым лицензированным водителем старше 21 года на любом сиденье транспортного средства","Только экзаменатором DMV","Никем; CLP разрешает самостоятельное вождение"],"explanation":"Держатель CLP может управлять CMV только в сопровождении держателя действительного CDL для данного класса/типа транспортного средства, который занимает сиденье рядом с держателем разрешения. Источник: WV DMV CDL page; 49 CFR 383.25."},"33":{"q":"Каков минимальный проходной балл на теоретических (письменных) экзаменах CDL Западной Виргинии?","options":["70%","75%","80%","90%"],"explanation":"Западная Виргиния требует минимального балла 80% для сдачи каждого теоретического экзамена CDL (экзамен HazMat должен сдаваться в письменной форме). Источник: WV DMV CDL testing requirements."},"34":{"q":"Прежде чем Западная Виргиния сможет выдать эндорсмент HazMat (H), какую федеральную проверку должен пройти заявитель?","options":["Оценку угрозы безопасности от Transportation Security Administration (TSA)","Проверку кредитной истории","Только проверку судимости на уровне штата без снятия отпечатков пальцев","Только медицинскую проверку зрения"],"explanation":"Федеральный закон, принятый Западной Виргинией, требует, чтобы заявители на эндорсмент HazMat прошли оценку угрозы безопасности TSA, которая включает снятие отпечатков пальцев и проверку биографии, прежде чем эндорсмент будет выдан или продлён. Источник: WV CDL Manual; 49 CFR 1572 (TSA)."},"35":{"q":"Каков минимальный возраст для получения эндорсмента HazMat (H) на CDL Западной Виргинии?","options":["18 лет","21 год","25 лет","19 лет"],"explanation":"Поскольку перевозка опасных грузов требует статуса, квалифицированного для межштатной деятельности согласно федеральным правилам, заявитель должен быть не моложе 21 года для получения эндорсмента HazMat. Источник: WV CDL Manual; TSA/FMCSA HazMat requirements."},"36":{"q":"Впервые подающие заявление на CDL в Западной Виргинии должны пройти подготовку водителей начального уровня (ELDT) через поставщика, который:","options":["Включён в реестр поставщиков обучения FMCSA (TPR)","Одобрен только West Virginia State Police","Является любой частной автошколой по выбору заявителя","Сертифицирован TSA"],"explanation":"ELDT должна быть завершена у поставщика, включённого в реестр поставщиков обучения FMCSA (TPR). Это применяется к тем, кто впервые получает CDL Class A или B, повышает категорию с B до A или впервые получает эндорсмент P, S или H (7 февраля 2022 года или позднее). Источник: FMCSA ELDT rule; WV DMV CDL page."},"37":{"q":"Какая из следующих является одной из четырёх категорий медицинской самосертификации, из которых должен выбрать заявитель на CDL Западной Виргинии?","options":["Non-Excepted Interstate (NI)","Recreational Interstate (RI)","Commercial Exempt (CE)","Limited Local (LL)"],"explanation":"Четыре категории самосертификации: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Водители в категориях non-excepted должны иметь действительный сертификат медицинского эксперта DOT. Источник: WV DMV CDL self-certification; FMCSA."},"38":{"q":"Водитель CDL Западной Виргинии, который сертифицируется как «Non-Excepted Interstate (NI)», должен предоставить какой документ?","options":["Действительный сертификат медицинского эксперта (медицинская карта DOT)","Только страховой документ на автотранспортное средство","Подписанное письмо об освобождении от работодателя","Ничего дополнительного, помимо заявления"],"explanation":"Водители, сертифицирующиеся в категорию non-excepted (NI или NA), должны получить и предоставить действительный сертификат медицинского эксперта от эксперта из национального реестра FMCSA; категории excepted (EI, EA) не требуют медицинской карты DOT. Источник: WV DMV CDL self-certification; FMCSA."},"39":{"q":"При подаче заявления на CDL или CLP в Западной Виргинии, сколько доказательств проживания в Западной Виргинии требует DMV?","options":["Одно доказательство проживания","Два доказательства проживания","Три доказательства проживания","Доказательство проживания не требуется"],"explanation":"Западная Виргиния требует одно доказательство личности/законного присутствия, одно доказательство номера Social Security и два доказательства проживания в Западной Виргинии для заявления на CDL/CLP. Источник: WV DMV acceptable documents / driver license requirements."},"40":{"q":"Согласно законодательству Западной Виргинии, при какой концентрации алкоголя в крови (BAC) водитель считается управляющим коммерческим автотранспортным средством (CMV) с превышением допустимого уровня алкоголя, что влечёт дисквалификацию?","options":["0.08% или более","0.02% или более","0.10% или более","0.04% или более"],"explanation":"Западная Виргиния устанавливает предел алкоголя для CMV на уровне 0.04% («четыре сотых одного процента или более, по массе»), что вдвое меньше предела 0.08% для личных транспортных средств. Источник: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)(2)."},"41":{"q":"В Западной Виргинии водитель CMV, у которого обнаружено любое поддающееся обнаружению количество алкоголя ниже 0.04%, должен быть:","options":["Немедленно дисквалифицирован на 1 год","Выведен из эксплуатации (out-of-service) на 24 часа","Оштрафован на $2,500 без вывода из эксплуатации","Только предупреждён без какого-либо наказания"],"explanation":"Водитель CMV с любым поддающимся обнаружению измеримым количеством алкоголя ниже 0.04% выводится из эксплуатации (out-of-service) на 24 часа, даже если это ниже дисквалифицирующего порога 0.04%. Источник: WV CDL Manual Section 1.3 and Implied Consent provisions; WV Code 17E-1-13."},"42":{"q":"Каков срок дисквалификации в Западной Виргинии за ПЕРВОЕ серьёзное (major) правонарушение водителя CMV, такое как DUI или BAC 0.04%, когда НЕ перевозятся опасные грузы со знаками (плакардами)?","options":["60 days","3 года","1 год","6 месяцев"],"explanation":"Первое серьёзное правонарушение (DUI, BAC 0.04%, отказ, оставление места происшествия, использование транспортного средства в совершении тяжкого преступления и т. д.) приводит к дисквалификации CDL на 1 год в Западной Виргинии. Источник: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)."},"43":{"q":"Если водитель CMV в Западной Виргинии совершает первое серьёзное правонарушение ВО ВРЕМЯ перевозки опасных грузов, требующих знаков (плакардов), срок дисквалификации составляет:","options":["3 года","1 год","5 лет","180 days"],"explanation":"Первое серьёзное правонарушение, совершённое при управлении CMV, перевозящим опасные грузы со знаками (плакардами) (согласно 49 CFR Part 172, Subpart F), влечёт усиленную дисквалификацию на 3 года вместо 1 года. Источник: WV CDL Manual; WV Code 17E-1-13(b)(1)(C)."},"44":{"q":"Каков срок дисквалификации в Западной Виргинии за ВТОРОЕ серьёзное правонарушение (в отдельном инциденте)?","options":["10 лет","Пожизненно","3 года","5 лет"],"explanation":"Второе серьёзное правонарушение в отдельном инциденте приводит к пожизненной дисквалификации CDL в Западной Виргинии. DMV может разрешить восстановление по истечении минимального срока при определённых условиях, но дисквалификация налагается как пожизненная. Источник: WV CDL Manual; WV Code 17E-1-13(b)(1)(D)."},"45":{"q":"В Западной Виргинии отказ пройти назначенный химический (вторичный) тест при управлении CMV влечёт какую дисквалификацию за первый отказ?","options":["60 days","1 год","90 days","30 days"],"explanation":"Отказ от теста приравнивается к серьёзному правонарушению: первый отказ дисквалифицирует водителя на 1 год (3 года при перевозке опасных грузов со знаками-плакардами), а второй приводит к пожизненной дисквалификации. Источник: WV CDL Manual; WV Code 17E-1-13(b)(3)."},"46":{"q":"Согласно закону Западной Виргинии о подразумеваемом согласии (Implied Consent Law), приняв привилегию вождения в штате, водитель считается давшим согласие на:","options":["Обыск транспортного средства при любой остановке движения","Обязательный учебный курс по DUI","Случайные придорожные проверки со служебными собаками по поиску наркотиков","Химический тест для определения содержания алкоголя в организме"],"explanation":"Закон Западной Виргинии о подразумеваемом согласии означает, что любое лицо, управляющее транспортным средством в штате, дало согласие на прохождение назначенного химического теста на содержание алкоголя. Отказ приостанавливает право вождения как минимум на 1 год, вплоть до пожизненного. Источник: WV CDL Manual, Implied Consent Law; WV Code 17C-5-4."},"47":{"q":"Согласно закону Западной Виргинии о подразумеваемом согласии (Implied Consent Law), отказ от химического теста приостанавливает право водителя управлять автотранспортным средством на какой минимальный срок?","options":["Как минимум 90 days","Как минимум 30 days","Как минимум 1 год","Как минимум 6 месяцев"],"explanation":"Отказ от назначенного химического теста согласно закону Западной Виргинии о подразумеваемом согласии приостанавливает право управлять автотранспортным средством на срок не менее 1 года, вплоть до пожизненного. Источник: WV CDL Manual, Implied Consent Law."},"48":{"q":"Сколько серьёзных нарушений правил дорожного движения в течение 3-летнего периода влекут дисквалификацию на 60 days в Западной Виргинии?","options":["1 (первое нарушение)","3 (третье в течение 3 лет)","2 (второе в течение 3 лет)","4 (четвёртое в течение 3 лет)"],"explanation":"Второе серьёзное нарушение правил дорожного движения в течение 3-летнего периода приводит к дисквалификации на 60 days. Первое серьёзное нарушение само по себе не влечёт дисквалификации. Источник: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"49":{"q":"Каков срок дисквалификации в Западной Виргинии за ТРЕТЬЕ серьёзное нарушение правил дорожного движения в течение 3-летнего периода?","options":["120 days","60 days","1 год","90 days"],"explanation":"Третье или последующее серьёзное нарушение правил дорожного движения в течение 3-летнего периода приводит к дисквалификации на 120 days. Источник: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"50":{"q":"Какое из следующих классифицируется как «серьёзное нарушение правил дорожного движения» для целей дисквалификации CDL в Западной Виргинии?","options":["Превышение установленного предела на 5 mph","Чрезмерное превышение скорости (на 15 mph или более сверх установленного предела)","Нарушение правил парковки","Просроченная наклейка о регистрации"],"explanation":"Серьёзные нарушения правил дорожного движения включают чрезмерное превышение скорости (на 15 mph или более сверх установленного предела), безрассудное вождение, неправильную или хаотичную смену полос, движение на слишком близком расстоянии и отправку текстовых сообщений за рулём. Нарушения правил парковки исключены. Источник: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"51":{"q":"В Западной Виргинии каков срок дисквалификации за ПЕРВОЕ осуждение за нарушение приказа о выводе из эксплуатации (out-of-service order) при управлении CMV, перевозящим неопасный груз?","options":["90 days","60 days","180 days","1 год"],"explanation":"Первое осуждение за нарушение приказа о выводе из эксплуатации (out-of-service order) при управлении CMV приводит к дисквалификации на 180 days в Западной Виргинии. Источник: WV CDL Manual; WV Code 17E-1-13(e)(1)(A)."},"52":{"q":"Каков срок дисквалификации за ВТОРОЕ нарушение приказа о выводе из эксплуатации (out-of-service order) в течение 10-летнего периода при перевозке неопасных материалов в Западной Виргинии?","options":["180 days","2 года","3 года","1 год"],"explanation":"Второе нарушение приказа о выводе из эксплуатации (out-of-service order) в отдельном инциденте в течение 10 лет (неопасный груз) приводит к дисквалификации на 2 года. Третье или последующее в течение 10 лет приводит к 3 годам. Источник: WV CDL Manual; WV Code 17E-1-13(e)(1)(B)."},"53":{"q":"В Западной Виргинии ВТОРОЕ нарушение приказа о выводе из эксплуатации (out-of-service order) в течение 10 лет при перевозке опасных грузов со знаками (плакардами) ИЛИ управлении транспортным средством, предназначенным для перевозки 16 или более пассажиров, приводит к какой дисквалификации?","options":["2 года","180 days","1 год","3 года"],"explanation":"Второе нарушение приказа о выводе из эксплуатации (out-of-service order) в течение 10 лет при перевозке опасных грузов со знаками (плакардами) или перевозке 16+ пассажиров влечёт усиленную дисквалификацию на 3 года (против 2 лет для неопасного груза). Источник: WV CDL Manual; WV Code 17E-1-13(e)(2)(B)."},"54":{"q":"Каков срок дисквалификации в Западной Виргинии за ПЕРВОЕ нарушение на железнодорожном переезде при управлении CMV?","options":["30 days","120 days","60 days","180 days"],"explanation":"Первое нарушение на железнодорожном переезде при управлении CMV приводит к дисквалификации на 60 days в Западной Виргинии. Источник: WV CDL Manual; WV Code 17E-1-13(d)."},"55":{"q":"В Западной Виргинии сроки дисквалификации за нарушения на железнодорожных переездах возрастают с 60 days за первое нарушение до чего за ВТОРОЕ и ТРЕТЬЕ нарушение в течение 3 лет?","options":["120 days за второе; 1 год за третье","90 days за второе; 180 days за третье","60 days за второе; 120 days за третье","180 days за второе; 2 года за третье"],"explanation":"Нарушения на железнодорожных переездах дисквалифицируют водителя на 60 days (первое), 120 days (второе в течение 3 лет) и 1 год (третье или последующее в течение 3 лет). Источник: WV CDL Manual; WV Code 17E-1-13(d)."},"56":{"q":"Согласно правилам Западной Виргинии и федеральным правилам, принятым штатом, CDL водителя CMV дисквалифицируется после скольких осуждений за отправку текстовых сообщений за рулём CMV?","options":["1 осуждения (первое правонарушение)","4 или более осуждений в течение 3 лет","3 или более осуждений в течение 5 лет","2 или более осуждений в течение 3 лет"],"explanation":"Отправка текстовых сообщений за рулём CMV является серьёзным нарушением: CDL дисквалифицируется на 60 days после второго осуждения в течение 3 лет и на 120 days за три или более в течение 3 лет. Первое осуждение не влечёт дисквалификации, но сопровождается гражданским штрафом. Источник: WV CDL Manual Section 2.9.5; WV Code 17E-1-13(c)(9)."},"57":{"q":"Каков максимальный федеральный гражданский штраф (принятый в Западной Виргинии) для водителя CMV, который отправляет текстовые сообщения или использует портативный мобильный телефон во время вождения?","options":["До $2,750","До $500","До $11,000","До $5,000"],"explanation":"Каждое нарушение, связанное с отправкой текстовых сообщений/использованием портативного телефона, подвергает водителя CMV гражданскому штрафу до $2,750. (Работодатели, которые разрешают или требуют это, могут быть оштрафованы на сумму до $11,000.) Источник: WV CDL Manual Sections 2.9.4 and 2.9.5."},"58":{"q":"Держатель CDL Западной Виргинии, чьи права на личное транспортное средство приостановлены за нарушение, связанное с алкоголем, контролируемыми веществами или тяжким преступлением, теряет привилегии CDL на какой срок при первом нарушении?","options":["1 год","60 days","90 days","6 месяцев"],"explanation":"Если права держателя CDL на личное транспортное средство аннулированы, отменены или приостановлены за нарушения, связанные с алкоголем, контролируемыми веществами или тяжким преступлением, CDL теряется на 1 год; второе такое нарушение (на личном транспортном средстве или CMV) приводит к пожизненной потере. Источник: WV CDL Manual Section 1.3; WV Code 17E-1-13(b)."},"59":{"q":"Согласно балльной системе для водителей Западной Виргинии, достижение какого количества баллов приводит к приостановке права вождения?","options":["6 или более баллов","20 или более баллов","8 или более баллов","12 или более баллов"],"explanation":"Балльная система WV DMV приостанавливает право вождения при достижении 12 или более баллов. Например, превышение скорости на 20 mph или более сверх предела — это 6 баллов, а безрассудное вождение — 6 баллов. Источник: WV CDL Manual / WV Driver's Licensing Handbook, Point System."},"60":{"q":"На НЕРАЗДЕЛЁННОЙ автомагистрали Западной Вирджинии, когда вы не можете безопасно перестроиться в сторону от остановившегося аварийного или служебного автомобиля с включёнными проблесковыми маячками, с какой максимальной скоростью вы можете проехать мимо него согласно закону штата «Move Over»?","options":["15 mph","25 mph","10 mph","20 mph"],"explanation":"Кодекс Западной Вирджинии 17C-14-9a (закон «Move Over») требует, чтобы водитель, который не может перестроиться, снизил скорость до безопасного уровня, не превышающего 15 mph, на любой неразделённой автомагистрали или улице при проезде мимо стоящего уполномоченного аварийного или служебного автомобиля. Источник: WV Code 17C-14-9a."},"61":{"q":"На РАЗДЕЛЁННОЙ автомагистрали Западной Вирджинии, где вы не можете безопасно перестроиться в несмежную полосу, с какой максимальной скоростью вы можете проехать мимо остановившегося аварийного автомобиля с включёнными предупреждающими маячками?","options":["15 mph","35 mph","25 mph","20 mph"],"explanation":"Согласно WV Code 17C-14-9a, водитель, не имеющий возможности сменить полосу, должен снизить скорость до безопасного уровня, не превышающего 25 mph, на любой разделённой автомагистрали при проезде мимо стоящего аварийного или служебного автомобиля. Источник: WV Code 17C-14-9a."},"62":{"q":"Согласно Руководству CDL Западной Вирджинии, на каком расстоянии от ближайшего рельса на железнодорожном переезде должен остановиться автомобиль с табличками HazMat, груз с хлором или цистерна?","options":["Между 10 и 25 feet","Между 15 и 50 feet","Между 5 и 15 feet","Между 25 и 75 feet"],"explanation":"Руководство WV CDL (раздел 9.6.12) гласит, что автомобиль с табличками, перевозящий любое количество хлора или имеющий цистерны для опасных материалов, должен остановиться за 15–50 feet до ближайшего рельса. Источник: WV CDL Manual, Sec. 9.6.12."},"63":{"q":"На каком расстоянии до железнодорожного переезда водитель автобуса в Западной Вирджинии должен остановить автобус?","options":["Между 20 и 40 feet","Не менее 50 feet","Между 10 и 30 feet","Между 15 и 50 feet"],"explanation":"Руководство WV CDL (раздел 4.3.5) предписывает водителям автобусов останавливать автобус за 15–50 feet до железнодорожных переездов, а затем прислушиваться и осматриваться в обоих направлениях на наличие поездов. Источник: WV CDL Manual, Sec. 4.3.5."},"64":{"q":"Каково максимальное установленное ограничение скорости на межштатной автомагистрали Западной Вирджинии, если не указано иное?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"В таблице установленных скоростей Руководства WV CDL для межштатных автомагистралей указано 70 mph (если не установлено иное). Источник: WV CDL Manual, таблица установленных скоростей; WV Code 17C-6-1."},"65":{"q":"Если не указано иное, каково максимальное ограничение скорости в деловом или жилом районе Западной Вирджинии?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"Западная Вирджиния устанавливает максимум 25 mph в любом деловом или жилом районе, как показано в таблице установленных скоростей Руководства WV CDL. Источник: WV Code 17C-6-1; WV CDL Manual."},"66":{"q":"Каково максимальное ограничение скорости в школьной зоне Западной Вирджинии при наличии детей?","options":["20 mph","25 mph","15 mph","10 mph"],"explanation":"WV Code 17C-6-1 устанавливает 15 mph в школьной зоне во время перемены или когда дети идут в школу или из школы; в Руководстве WV CDL указана та же цифра. Источник: WV Code 17C-6-1; WV CDL Manual."},"67":{"q":"На открытой загородной автомагистрали Западной Вирджинии (не межштатной и не дороге с контролируемым доступом) каково максимальное ограничение скорости по умолчанию, если не указано иное?","options":["60 mph","65 mph","50 mph","55 mph"],"explanation":"В таблице установленных скоростей Руководства WV CDL для открытых дорог указано 55 mph, если не установлено иное, что соответствует WV Code 17C-6-1. Источник: WV Code 17C-6-1; WV CDL Manual."},"68":{"q":"Согласно Кодексу Западной Вирджинии 17C-12-7, когда вы встречаете или обгоняете школьный автобус, остановившийся с мигающими предупреждающими сигнальными огнями для посадки или высадки детей, вы должны:","options":["Остановиться, не доезжая до автобуса, и не продолжать движение, пока огни не погаснут или водитель не подаст сигнал","Снизить скорость до 10 mph и проехать с осторожностью","Остановиться только если вы едете в том же направлении, что и автобус","Перестроиться в дальнюю полосу и продолжить движение со сниженной скоростью"],"explanation":"WV Code 17C-12-7 требует, чтобы водитель, встречающий или обгоняющий с любого направления школьный автобус с мигающими предупреждающими огнями, остановился, не доезжая до автобуса, и не продолжал движение, пока автобус не тронется, огни не погаснут или водитель автобуса не подаст сигнал. Источник: WV Code 17C-12-7."},"69":{"q":"Согласно закону Западной Вирджинии о школьных автобусах, на каком типе проезжей части водитель НЕ обязан останавливаться перед школьным автобусом, который находится на другой проезжей части, где пешеходам не разрешено переходить?","options":["На любой четырёхполосной автомагистрали","На любой дороге с центральной полосой для поворота","На автомагистрали с контролируемым доступом","На двухполосной дороге с размеченной разделительной полосой"],"explanation":"WV Code 17C-12-7 предусматривает, что водитель на автомагистрали с контролируемым доступом не обязан останавливаться перед школьным автобусом, находящимся на другой проезжей части или рядом с автомагистралью, где пешеходам не разрешено переходить. Простая разметка или центральная полоса НЕ дают основания для этого исключения. Источник: WV Code 17C-12-7."},"70":{"q":"После остановки коммерческого автомобиля на обочине автомагистрали Западной Вирджинии, в течение скольких минут вы должны выставить аварийные предупреждающие устройства?","options":["5 minutes","10 minutes","15 minutes","30 minutes"],"explanation":"Руководство WV CDL гласит, что если вы вынуждены остановиться на дороге или обочине, вы должны выставить аварийные предупреждающие устройства в течение десяти минут. Источник: WV CDL Manual, Sec. 2.5."},"71":{"q":"При остановке на ОДНОСТОРОННЕЙ или РАЗДЕЛЁННОЙ автомагистрали Западной Вирджинии, где следует разместить три светоотражающих треугольника?","options":["На 10 feet, 100 feet и 100 feet спереди и сзади","На 50 feet, 100 feet и 500 feet позади","На 10 feet, 50 feet и 150 feet в сторону приближающегося транспорта","На 10 feet, 100 feet и 200 feet в сторону приближающегося транспорта"],"explanation":"Руководство WV CDL предписывает, чтобы на односторонней или разделённой автомагистрали предупреждающие устройства размещались на 10 feet, 100 feet и 200 feet от автомобиля в сторону приближающегося транспорта. Источник: WV CDL Manual, Sec. 2.5."},"72":{"q":"Если у водителя в Западной Вирджинии нет светоотражающих треугольников, какие предупреждающие устройства Руководство CDL допускает в качестве замены для предупреждения о припаркованном автомобиле?","options":["Не менее 6 факелов (fusees) или 3 жидкотопливных сигнальных огней (flares)","Не менее 2 факелов (fusees) или 1 жидкотопливного сигнального огня (flare)","Один вращающийся жёлтый проблесковый маяк","Не менее 4 дорожных конусов"],"explanation":"Руководство WV CDL перечисляет предупреждающие устройства для припаркованных автомобилей как три светоотражающих треугольника либо не менее 6 факелов (fusees) или 3 жидкотопливных сигнальных огней (flares). Источник: WV CDL Manual, раздел об осмотре автомобиля/аварийном оборудовании."},"73":{"q":"Почему Западная Вирджиния запрещает использование сигнальных огней или устройств с открытым пламенем рядом с определёнными грузами с табличками?","options":["Они слишком тусклые, чтобы их было видно ночью","Они разрешены только на разделённых автомагистралях","Они могут воспламенить легковоспламеняющийся груз, например, легковоспламеняющиеся жидкости класса 3 (Class 3)","Они разряжают аккумулятор автомобиля"],"explanation":"Правило «No Flares!» Руководства WV CDL гласит, что рядом с автомобилями, перевозящими легковоспламеняющиеся материалы, такие как легковоспламеняющиеся жидкости класса 3 (Class 3), следует использовать светоотражающие треугольники или красные электрические фонари, а не горящие сигнальные огни или факелы. Источник: WV CDL Manual, Sec. 9.6.4."},"74":{"q":"Согласно правилу использования полос в Западной Вирджинии, где обычно должны двигаться все водители, включая грузовой транспорт?","options":["По центральной полосе, чтобы оставить правую полосу свободной для въезжающего транспорта","По крайней правой полосе, за исключением обгона, поворота или объезда препятствий","По той полосе, где меньше всего транспорта","По левой полосе, чтобы оставить правую полосу для более медленного транспорта"],"explanation":"Западная Вирджиния (Глава 17C, Статья 7) требует, чтобы водители, включая грузовики, по умолчанию двигались по крайней правой полосе, за исключением обгона/опережения, когда правая полоса закрыта, при движении ниже обычной скорости потока или при подготовке к повороту. Источник: WV Code Ch. 17C, Art. 7."},"75":{"q":"На ТРЁХполосной автомагистрали Западной Вирджинии как грузовик может использовать полосы?","options":["Он может свободно использовать любую из трёх полос","Он должен использовать только среднюю полосу","Он может использовать две левые полосы и обгонять по правой полосе","Он должен оставаться в правой полосе, но может использовать среднюю полосу для обгона"],"explanation":"Согласно правилам использования полос в Западной Вирджинии, грузовики на трёхполосной проезжей части ограничены правой полосой, но могут перестраиваться в среднюю полосу для обгона. Источник: WV Code Ch. 17C, Art. 7."},"76":{"q":"На ЧЕТЫРЁХполосной автомагистрали Западной Вирджинии какие полосы может использовать седельный тягач с полуприцепом?","options":["Две правые полосы","Только крайнюю правую полосу","Любую полосу, кроме крайней левой","Две левые полосы"],"explanation":"Западная Вирджиния разрешает седельным тягачам с полуприцепами двигаться по двум правым полосам на четырёхполосной автомагистрали. Источник: WV Code Ch. 17C, Art. 7."},"77":{"q":"Какова законная максимальная ширина транспортного средства (без разрешения) в Западной Вирджинии на маршрутах Interstate, US и WV с полосами шириной 10 feet или больше?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"explanation":"Законные ограничения по габаритам Управления автомобильных дорог Западной Вирджинии устанавливают максимальную ширину 8 feet 6 inches на маршрутах Interstate, US, WV и местных маршрутах с полосами шириной 10 feet или больше (8 feet на более узких местных маршрутах). Источник: WVDOT/Division of Highways Legal Size and Weight Limits."},"78":{"q":"Каков законный максимальный полный вес (без разрешения) для транспортного средства на МЕЖШТАТНОЙ автомагистрали Западной Вирджинии?","options":["65,000 pounds","80,000 pounds","73,280 pounds","90,000 pounds"],"explanation":"Законное ограничение полного веса в Западной Вирджинии на межштатных автомагистралях составляет 80,000 pounds (нулевой допуск); местные служебные маршруты ограничены 65,000 pounds. Источник: WVDOT Legal Size and Weight Limits."},"79":{"q":"Какое утверждение о магистрали West Virginia Turnpike (I-77) верно для коммерческих водителей?","options":["Седельным тягачам с прицепами полностью запрещено движение по Turnpike","Это бесплатная межштатная автомагистраль без пунктов взимания платы","Грузовики могут использовать её только от восхода до заката","Это платная горная автомагистраль, где грузовики платят за проезд на основных пунктах взимания платы"],"explanation":"Магистраль West Virginia Turnpike проводит I-77 через крутые горные подъёмы (до примерно 5%) и является платной дорогой с основными пунктами взимания платы (Ghent, Pax, Chelyan), где грузовики платят за проезд в зависимости от размера/осей; на ней также есть аварийные съезды для грузовиков. Источник: WV Parkways Authority / WVDOT Turnpike pages."},"80":{"q":"Какое государственное ведомство выдаёт коммерческие водительские удостоверения (CDL) в Западной Вирджинии?","options":["West Virginia Division of Motor Vehicles (DMV)","Полиция штата Западная Вирджиния","Комиссия по коммунальным услугам Западной Вирджинии","Управление автомобильных дорог Западной Вирджинии"],"explanation":"В Западной Вирджинии CDL выдаются West Virginia Division of Motor Vehicles (DMV), которое проводит тесты на знания и обрабатывает заявления. Источник: WV DMV Commercial Driver's License page (transportation.wv.gov/DMV/Motor-Carriers/CDL)."},"81":{"q":"Прежде чем Западная Вирджиния выдаст полноценное CDL, заявитель должен сначала получить и иметь какой документ?","options":["Commercial Learner's Permit (CLP)","Эндорсмент к водительскому удостоверению класса D","Федеральное разрешение на межштатную перевозку","Временное разрешение на вождение по необходимости"],"explanation":"Западная Вирджиния требует, чтобы заявители сначала получили Commercial Learner's Permit (CLP) от DMV, который разрешает практику под наблюдением перед тестом навыков. Источник: WV DMV CDL page."},"82":{"q":"В Западной Вирджинии как долго заявитель должен иметь Commercial Learner's Permit (CLP), прежде чем получит право сдавать дорожный тест навыков CDL?","options":["Не менее 14 days","Не менее 30 days","Не менее 7 days","Не менее 60 days"],"explanation":"Западная Вирджиния (следуя федеральному стандарту) требует, чтобы CLP имелся минимум 14 days, прежде чем заявитель сможет сдавать дорожный тест навыков. Источник: WV DMV CDL page; 49 CFR 383.25 в редакции, принятой в WV."},"83":{"q":"При самостоятельной сертификации типа коммерческой деятельности заявитель на CDL/CLP в Западной Вирджинии должен выбрать из скольких категорий?","options":["Из четырёх категорий","Из двух категорий","Из трёх категорий","Из пяти категорий"],"explanation":"Западная Вирджиния требует, чтобы заявители самостоятельно сертифицировались по одной из четырёх категорий эксплуатации коммерческого автотранспорта: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Источник: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3)."},"84":{"q":"Какая категория самостоятельной сертификации в Западной Вирджинии требует, чтобы водитель имел в наличии действующий DOT Medical Examiner's Certificate?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Любой водитель, работающий только внутри штата, освобождён"],"explanation":"Водители, самостоятельно сертифицирующиеся как non-excepted (NI или NA), должны иметь действующий FMCSA Medical Examiner's Certificate; статусы excepted (EI, EA) освобождены от этого требования. Источник: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3); FMCSA 49 CFR 383.71."},"85":{"q":"С 23 июня 2025 года как обычно предоставляется в DMV медицинская информация DOT водителя CDL категории non-excepted в Западной Вирджинии?","options":["Сертифицированный медицинский эксперт вносит результаты осмотра в защищённую электронную базу данных, которая передаётся в DMV","Водитель отправляет бумажную медицинскую карту в DMV по почте после каждого осмотра","Работодатель водителя отправляет медицинскую карту в DMV по факсу","Медицинская карта проверяется только во время продления удостоверения"],"explanation":"С 23 июня 2025 года Западная Вирджиния больше не принимает бумажные медицинские сертификаты; сертифицированный медицинский эксперт в электронном виде вносит результаты осмотра в защищённую базу данных, которая отправляется в DMV. Источник: WV DMV announcement on improved CDL medical certification process (June 2025)."},"86":{"q":"Каков минимальный проходной балл на тесте на знания (письменном) CDL в Западной Вирджинии?","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"Западная Вирджиния требует не менее 80 percent правильных ответов для сдачи теста на знания CDL. Источник: WV Commercial Driver's License Manual; WV DMV CDL testing rules."},"87":{"q":"Из каких трёх частей состоит тест навыков CDL в Западной Вирджинии, в порядке прохождения?","options":["Предрейсовый осмотр автомобиля, базовое управление автомобилем и вождение по дороге","Письменный тест на знания, проверка зрения и вождение по дороге","Проверка пневматических тормозов, тест на сцепку и тест на время реакции","Манёвры задним ходом, въезд на автомагистраль и параллельная парковка"],"explanation":"Тест навыков CDL в Западной Вирджинии состоит из трёх частей: предрейсового осмотра автомобиля, теста на базовое управление автомобилем и теста на вождение по дороге. Источник: WV Commercial Driver's License Manual (разделы о тесте навыков)."},"88":{"q":"Кто должен предоставить автомобиль, используемый для дорожного теста навыков CDL в Западной Вирджинии?","options":["Заявитель, который должен предоставить репрезентативный автомобиль того класса, по которому проводится тестирование","DMV, которое предоставляет стандартный тестовый грузовик","Автопарк Управления автомобильных дорог","Подойдёт любой автомобиль, включая легковую машину"],"explanation":"Заявитель должен предоставить автомобиль для теста навыков, и он должен быть репрезентативным для класса CDL, по которому заявитель проходит тестирование. Источник: WV Commercial Driver's License Manual; WV DMV CDL page."},"89":{"q":"Заявитель на CDL в Западной Вирджинии, подающий впервые, должен пройти Entry-Level Driver Training (ELDT) перед каким тестом?","options":["Перед дорожным тестом навыков CDL","Перед проверкой зрения","Перед тестом на продление удостоверения класса D","Перед проверкой биографии по отпечаткам пальцев"],"explanation":"ELDT (теория и практика вождения) должен быть пройден перед тестом навыков CDL для впервые подающих заявителей на класс A/B и определённые эндорсменты. Источник: WV DMV CDL page; FMCSA ELDT rule (49 CFR Part 380), действует с 7 февраля 2022 года."},"90":{"q":"Согласно федеральному правилу ELDT, применяемому в Западной Вирджинии, водитель считается заявителем на CDL «впервые» (и должен пройти ELDT), если он никогда не имел CDL до какой даты?","options":["7 февраля 2022 года","1 января 2020 года","1 октября 2021 года","23 июня 2025 года"],"explanation":"Требования ELDT не имеют обратной силы: лицо, которое никогда не имело CDL (или соответствующего эндорсмента S, P или H) до 7 февраля 2022 года, является заявителем, подающим впервые, который должен пройти ELDT. Источник: WV DMV CDL page; FMCSA ELDT final rule."},"91":{"q":"Где должен быть зарегистрирован поставщик обучения ELDT в Западной Вирджинии, чтобы обучение засчитывалось для получения права на CDL?","options":["В FMCSA Training Provider Registry (TPR)","Только в списке поставщиков West Virginia DMV","В реестре подрядчиков Управления автомобильных дорог штата","В National CDL Examiner Directory"],"explanation":"ELDT должен быть пройден через поставщика, зарегистрированного в FMCSA Training Provider Registry (TPR), чтобы он удовлетворял требованию CDL в Западной Вирджинии. Источник: WV DMV CDL page; FMCSA TPR (tpr.fmcsa.dot.gov)."},"92":{"q":"Каков в Западной Вирджинии минимальный возраст для получения CDL для эксплуатации внутри штата (только в пределах штата)?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Заявителю должно быть не менее 18 лет, чтобы получить CDL Западной Вирджинии для эксплуатации внутри штата; межштатная эксплуатация и опасные материалы требуют возраста 21 год. Источник: WV DMV CDL page; WV Code Chapter 17E."},"93":{"q":"Каков минимальный возраст для эксплуатации коммерческого автотранспорта в межштатных перевозках или для перевозки опасных материалов согласно правилам CDL Западной Вирджинии?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Западная Вирджиния требует, чтобы водителю было не менее 21 года для межштатной эксплуатации или для перевозки опасных материалов с табличками; лица 18–20 лет ограничены эксплуатацией внутри штата. Источник: WV DMV CDL page; FMCSA 49 CFR 391.11."},"94":{"q":"Согласно стандартному циклу «Drive for Five» в Западной Вирджинии, в течение какого срока CDL обычно действительно?","options":["Пять лет, истекая в день рождения владельца в год, когда его возраст делится на пять","Четыре года, на фиксированную дату продления","Восемь лет с даты выдачи","Два года, совпадая с медицинской картой DOT"],"explanation":"CDL Западной Вирджинии продлеваются по стандартному пятилетнему циклу, истекая в день рождения заявителя в год, в котором возраст заявителя нацело делится на пять. Источник: WV Code 17E-1-12; WV DMV."},"95":{"q":"Когда истекает срок действия CDL Западной Вирджинии, выданного водителю младше 21 года?","options":["Через 30 days после дня рождения заявителя в году, когда заявителю исполняется 21 год","В 18-й день рождения водителя","Через пять лет с даты выдачи независимо от возраста","Немедленно по достижении 21 года"],"explanation":"CDL Западной Вирджинии, выданное лицу, не достигшему возраста 21 года, истекает через 30 days после дня рождения заявителя в году, когда заявителю исполняется 21 год, поскольку право на межштатную эксплуатацию/перевозку опасных грузов меняется в 21 год. Источник: WV Code Chapter 17E; WV DMV."},"96":{"q":"Какой документ использует заявитель в Западной Вирджинии для самостоятельной сертификации типа коммерческого вождения, которое он планирует выполнять?","options":["WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3)","Федеральный Form MCSA-5876 medical certificate","Заявление на водительское удостоверение класса D","Форма пропорциональной регистрации IRP"],"explanation":"Заявители самостоятельно сертифицируют тип своей деятельности в WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3); Form MCSA-5876 — это отдельный сертификат медицинского эксперта. Источник: WV DMV CDL forms."},"97":{"q":"Как долго DOT Medical Examiner's Certificate считается действующим согласно правилам CDL Западной Вирджинии?","options":["Он не действует, если ему более двух лет (и может быть выдан на более короткий срок)","Он действителен пять лет","Он действителен только один год","Он никогда не истекает, как только находится в деле"],"explanation":"Medical Examiner's Certificate, которому более двух лет, не действует; эксперт может выдать его на два года или на более короткий интервал в зависимости от состояния водителя. Источник: WV DMV CDL page; FMCSA 49 CFR 391.45."},"98":{"q":"Что обычно происходит с правами CDL водителя в Западной Вирджинии, если требуемый Medical Examiner's Certificate просрочен?","options":["CDL понижается в классе, так что лицо теряет права на коммерческое вождение до тех пор, пока действующий сертификат не будет в деле","Ничего не меняется до следующего пятилетнего продления","Водитель автоматически переклассифицируется как excepted-водитель","Водитель получает автоматическое продление на один год"],"explanation":"Если медицинская сертификация водителя non-excepted просрочена, Западная Вирджиния понижает CDL в классе, лишая коммерческих прав до тех пор, пока не будет предоставлен действующий сертификат. Источник: WV DMV CDL page; FMCSA 49 CFR 383.73, положения о медицинской сертификации."},"99":{"q":"В Западной Вирджинии какой набор документов является частью основного требования для подачи заявления на CDL?","options":["Подтверждение личности/законного статуса, подтверждение проживания в Западной Вирджинии, проверка Social Security и заполненное заявление на CDL","Только паспорт и кредитная карта","Только свидетельство о праве собственности на автомобиль и подтверждение страховки","Письмо от работодателя и аттестат о среднем образовании"],"explanation":"Заявители на CDL в Западной Вирджинии должны предъявить подтверждение личности и гражданства США или законного постоянного проживания, подтверждение проживания в Западной Вирджинии, проверку номера Social Security и заполненное заявление на CDL (плюс медицинские документы/документы о самостоятельной сертификации). Источник: WV DMV CDL page."}},"tr":{"0":{"q":"Minimum şerit genişliği on fit (belirlenmiş ve Interstate güzergahları dahil) olan Batı Virginia karayollarında, bir aracın veya yükünün izin verilen maksimum dış genişliği nedir?","options":["8 fit (96 inç)","8 fit 6 inç (102 inç)","9 fit (108 inç)","10 fit (120 inç)"],"explanation":"W.Va. Code 17C-17-2 uyarınca, toplam dış genişlik 96 inçi aşamaz; ancak 102 inçlik (8 fit 6 inç) bir araç, U.S. DOT tarafından belirlenmiş karayollarında veya minimum şerit genişliği 10 fit olan herhangi bir karayolunda kullanılabilir. Kaynak: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits."},"1":{"q":"Batı Virginia karayollarında, yükü dahil bir aracın yasal maksimum yüksekliği nedir?","options":["12 fit 6 inç","13 fit","13 fit 6 inç","14 fit"],"explanation":"W.Va. Code 17C-17-4, bir aracın, herhangi bir yük dahil, Batı Virginia'daki hiçbir güzergahta 13 fit 6 inç yüksekliği aşamayacağını öngörür. Kaynak: W.Va. Code 17C-17-4; WV DOT Legal Size and Weight Limits."},"2":{"q":"Batı Virginia'da, tek bir aks üzerindeki maksimum brüt ağırlık nedir?","options":["18,000 pound","20,000 pound","22,400 pound","34,000 pound"],"explanation":"Batı Virginia, federal standartla uyumlu olarak tek aksı 20,000 pound ile sınırlar. Kaynak: W.Va. Code 17C-17-8 / 17C-17-9; WV DOT Legal Size and Weight Limits."},"3":{"q":"Batı Virginia'da, tandem aks grubuna izin verilen maksimum brüt ağırlık nedir?","options":["20,000 pound","32,000 pound","34,000 pound","40,000 pound"],"explanation":"Batı Virginia, federal aks ağırlığı standardıyla uyumlu olarak tandem aksı 34,000 pound ile sınırlar. Kaynak: W.Va. Code 17C-17-8a / 17C-17-9; WV DOT Legal Size and Weight Limits."},"4":{"q":"İzin olmaksızın Batı Virginia'da Interstate üzerinde (ulusal eyaletler arası ve savunma karayolları sistemi) çalışan bir araç veya araç kombinasyonu için yasal maksimum brüt araç ağırlığı nedir?","options":["73,280 pound","80,000 pound","88,000 pound","90,000 pound"],"explanation":"W.Va. Code 17C-17-9, ulusal eyaletler arası ve savunma karayolları sistemindeki maksimum brüt ağırlığın 80,000 pound'u (köprü formülüne tabi olarak) aşamayacağını belirtir. Kaynak: W.Va. Code 17C-17-9."},"5":{"q":"Batı Virginia'da bir çekici-yarı römork kombinasyonunda, kingpin'den arka aksa mesafe koşulu karşılandığında izin verilen maksimum yarı römork uzunluğu nedir?","options":["45 fit","48 fit","53 fit","57 fit"],"explanation":"W.Va. Code 17C-17-4 bir yarı römorku 48 fit ile sınırlar, ancak çekicinin arka aksından yarı römorkun ön aksına olan aks mesafesi 37 fitten fazla olmadığında 53 fite kadar izin verir. Kaynak: W.Va. Code 17C-17-4."},"6":{"q":"Şeritleri 10 fitten dar olan Batı Virginia karayollarında (bazı yerel hizmet güzergahları gibi), yasal maksimum araç genişliği nedir?","options":["7 fit 6 inç","8 fit (96 inç)","8 fit 6 inç","9 fit"],"explanation":"102 inçlik (8'6\") izin yalnızca belirlenmiş güzergahlarda veya 10 fit ya da daha geniş şeritlerde geçerlidir; şeritleri 10 fitten dar olan yollarda genişlik 96 inçlik (8 fit) sınıra döner. Kaynak: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits."},"7":{"q":"Interstate veya başka bir şekilde belirlenmiş güzergah OLMAYAN Batı Virginia karayollarında bir araç kombinasyonunun maksimum toplam uzunluğu nedir?","options":["53 fit","55 fit","65 fit","75 fit"],"explanation":"W.Va. Code 17C-17-4, birbirine bağlı bir araç kombinasyonunu, ön ve arka tamponlar dahil, belirlenmemiş karayollarında 55 fit toplam uzunlukla sınırlar. Kaynak: W.Va. Code 17C-17-4."},"8":{"q":"Batı Virginia'da tek bir motorlu aracın (düz kamyon) maksimum aşırı toplam uzunluğu nedir?","options":["35 fit","40 fit","45 fit","48 fit"],"explanation":"W.Va. Code 17C-17-4, tek bir motorlu aracı, yükü dahil, 40 fit aşırı toplam boyutla sınırlar (belirli karavanlar ve okul otobüsleri için 45 fite izin verilir). Kaynak: W.Va. Code 17C-17-4."},"9":{"q":"Batı Virginia'nın federal köprü ağırlığı hükümlerini benimsemesi kapsamında, ardışık iki tandem aks seti, ardışık tandem setlerinin ilk ve son aksları arasındaki mesafenin en az kaç fit olması koşuluyla her biri 34,000 pound taşıyabilir?","options":["30 fit","34 fit","36 fit","40 fit"],"explanation":"W.Va. Code 17C-17-9, ardışık iki tandem aks setinin, bu ardışık tandem setlerinin ilk ve son aksları arasındaki toplam mesafenin 36 fit veya daha fazla olması koşuluyla her birinin 34,000 pound taşımasına izin verir. Kaynak: W.Va. Code 17C-17-9."},"10":{"q":"Bir Batı Virginia aşırı yük (tek seferlik) izni genellikle yalnızca yük hangi koşulu karşıladığında verilebilir?","options":["Yük bölünemez niteliktedir","Taşıyıcı Batı Virginia merkezlidir","Aracın altı veya daha fazla aksı vardır","Seyahat yalnızca Interstate'lerde gerçekleşir"],"explanation":"Batı Virginia aşırı yük izinlerini yalnızca yasal sınırlara indirilemeyen bölünemez yükler için verir (deniz aşırı konteynerli kargo bilinen bir istisnadır). Kaynak: WV DOT Division of Highways Hauling Permits / Permit Types."},"11":{"q":"Bir motorlu taşıyıcı, Batı Virginia eyalet mülkiyetindeki güzergahlar için aşırı boyut/aşırı yük taşıma iznini nasıl alır?","options":["Yalnızca bir ilçe adliyesinde şahsen","Batı Virginia DOT/Division of Highways çevrimiçi taşıma izni sistemi aracılığıyla","Batı Virginia Eyalet Polisi karakolundan","Batı Virginia'da izin gerekmez"],"explanation":"Interstate, Turnpike, U.S., WV ve ilçe güzergahları için aşırı boyut/aşırı yük izinleri, WV DOT Division of Highways çevrimiçi taşıma izni sistemi aracılığıyla alınır. Kaynak: WV DOT Hauling Permits; wv.gotpermits.com."},"12":{"q":"U.S. ve WV eyalet güzergahlarında (Interstate dışı), Batı Virginia yasal aks ve brüt ağırlık sınırlarına hangi ağırlık toleransını uygular?","options":["Tolerans yok (sıfır)","Yüzde 5","Yüzde 10","Yüzde 15"],"explanation":"U.S. ve WV güzergahları ile yerel hizmet güzergahlarında Batı Virginia yasal ağırlık sınırlarının üzerinde yüzde 10 tolerans tanırken, Interstate karayolları sıfır tolerans tanır. Kaynak: WV DOT Legal Size and Weight Limits."},"13":{"q":"Batı Virginia yerel hizmet güzergahlarında (belirlenmemiş ilçe yolları), izin gerekmeden önce yasal maksimum brüt araç ağırlığı nedir?","options":["60,000 pound","65,000 pound","73,280 pound","80,000 pound"],"explanation":"Interstate ve U.S./WV güzergahları 80,000 pound'a kadar izin verirken, Batı Virginia yerel hizmet güzergahları 65,000 pound'luk daha düşük bir yasal brüt ağırlık sınırına sahiptir. Kaynak: WV DOT Legal Size and Weight Limits."},"14":{"q":"Interstate DIŞINDAKİ güzergahlarda bir Batı Virginia aşırı yük ve aşırı boyut YILLIK genel izniyle çalışan bir araca hangi maksimum izinli brüt ağırlık uygulanır?","options":["80,000 pound","90,000 pound","110,000 pound","120,000 pound"],"explanation":"Bir Batı Virginia aşırı yük/aşırı boyut yıllık (genel) izni kapsamında, Interstate dışı güzergahlarda maksimum brüt ağırlık 90,000 pound'dur (Interstate'te 110,000 pound). Kaynak: WV DOT Permit Types (Annual/Blanket Permits)."},"15":{"q":"Bir Batı Virginia aşırı yük yıllık (genel) izni kapsamında, bir tandem aks üzerindeki maksimum izinli ağırlık nedir?","options":["34,000 pound","40,000 pound","45,000 pound","50,000 pound"],"explanation":"Batı Virginia aşırı yük genel izinleri, tek aks üzerinde 28,000 pound'a, tandem aks üzerinde 45,000 pound'a ve üçlü aks üzerinde 50,000 pound'a kadar izin verir. Kaynak: WV DOT Permit Types (Annual/Blanket Permits)."},"16":{"q":"Belirlenmiş bir Batı Virginia 'kömür kaynağı taşıma yolunda', izinle kömür taşıyan bir araç yaklaşık hangi maksimum brüt ağırlığa kadar çalıştırılabilir?","options":["80,000 pound","90,000 pound","120,000 pound","150,000 pound"],"explanation":"W.Va. Code Chapter 17C, Article 17A uyarınca, belirlenmiş kömür kaynağı taşıma yollarında kömür taşıyan araçlar, 17C-17-9'daki sınırları aşarak 120,000 pound'a kadar (yüzde 5 sapma ile) daha yüksek bir brüt ağırlıkta çalışabilir. Kaynak: W.Va. Code 17C-17A; WV PSC kömür kaynağı taşıma izinlendirmesi."},"17":{"q":"Bir Batı Virginia aşırı yük yıllık (genel) izni kapsamında tek aks üzerindeki maksimum izinli ağırlık nedir?","options":["20,000 pound","24,000 pound","28,000 pound","34,000 pound"],"explanation":"Bir Batı Virginia aşırı yük genel izni, tek aks üzerinde 28,000 pound'a kadar izin verir (20,000 pound'luk yasal sınıra kıyasla). Kaynak: WV DOT Permit Types (Annual/Blanket Permits)."},"18":{"q":"Bir Batı Virginia aşırı boyut tek seferlik izni için, aşırı boyut hareketi genellikle hangi saatlerde geçerli DEĞİLDİR?","options":["Gün batımından gün doğumuna (gece)","Hafta içi öğlenden 14:00'e kadar","Pazartesi günleri herhangi bir saatte","Yalnızca sabah yoğun saatlerinde"],"explanation":"Bir Batı Virginia aşırı boyut izni genellikle gün batımından gün doğumuna kadarki gece saatlerinde geçerli değildir ve tatil günlerinde seyahate izin verilmez. Kaynak: WV DOT Hauling Permits / izin koşulları."},"19":{"q":"Bir direksiyon aksı ve bir tandem aks grubu olan bir Batı Virginia tek üniteli (düz) kamyon, izin verilen tolerans uygulanmadan önce genellikle hangi maksimum brüt araç ağırlığıyla sınırlıdır?","options":["48,000 pound","54,000 pound","60,000 pound","66,000 pound"],"explanation":"Bir direksiyon aksı ve tandemde iki aksı olan bir Batı Virginia tek üniteli kamyonu, maksimum 60,000 pound brüt ağırlıkla sınırlıdır (Interstate dışı güzergahlardaki yüzde 10 tolerans uygulanmadan önce). Kaynak: WV DOT Legal Size and Weight Limits."},"20":{"q":"Batı Virginia'da, brüt kombinasyon ağırlık derecesi (GCWR) 26,001 pound veya daha fazla olan ve çekilen aracın GVWR'si 10,000 pound'dan fazla olan bir araç kombinasyonunu kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Batı Virginia federal sınıflandırmayı benimser: bir Class A CDL, çekilen ünitenin GVWR'si 10,000 lbs'yi aşması koşuluyla, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonunu kapsar. Kaynak: WV DMV Commercial Driver's License sayfası ve WV CDL Manual."},"21":{"q":"Batı Virginia kurallarına göre, GVWR'si 26,001 pound veya daha fazla olan tek bir araç (veya 10,000 pound'u geçmeyen bir üniteyi çeken böyle bir araç) hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class E"],"explanation":"Batı Virginia'da bir Class B CDL, GVWR'si 10,000 lbs veya daha az olan bir üniteyi çekmek dahil, GVWR'si 26,001 lbs veya daha fazla olan tek bir araca yetki verir. Kaynak: WV DMV CDL sayfası ve WV CDL Manual."},"22":{"q":"Bir Batı Virginia sürücüsü, 26,001 pound'un altında, 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakart gerektiren tehlikeli madde taşımak için kullanılan bir aracı kullanıyor. Hangi CDL sınıfı uygulanır?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"Bir Class C CDL, Class A veya B ağırlık eşiklerini karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakart gerektiren tehlikeli madde taşıyan araçları kapsar. Kaynak: WV DMV CDL sayfası ve WV CDL Manual."},"23":{"q":"Bir Batı Virginia CDL'sinde hangi onay kodu, plakart gerektiren tehlikeli maddelerin taşınmasına yetki verir?","options":["N","H","T","X"],"explanation":"'H' onayı, plakartlı tehlikeli maddelerin taşınmasına yetki verir. 'X' kodu, birleşik bir Tank artı HazMat onayıdır. Kaynak: WV CDL Manual, Endorsements bölümü."},"24":{"q":"Bir Batı Virginia CDL'sinde, kalıcı olarak monte edilmiş bir tankta sıvı veya gaz halinde madde taşıyan bir tank aracını kullanmak için hangi onay gereklidir?","options":["T (İkili/Üçlü)","N (Tank)","P (Yolcu)","H (HazMat)"],"explanation":"Sıvı veya gazları dökme halinde taşıyan tank araçları için 'N' (Tank) onayı gereklidir. 'T' onayı, ayrı bir yetkilendirme olan ikili ve üçlü römorklar içindir. Kaynak: WV CDL Manual, Endorsements bölümü."},"25":{"q":"Bir Batı Virginia CDL sahibi ikili veya üçlü römork çekmek istiyor. Hangi onay eklenmelidir?","options":["N","S","T","P"],"explanation":"'T' onayı, ikili ve üçlü römork kombinasyonlarının kullanımına yetki verir ve bir bilgi testini geçmeyi gerektirir. Kaynak: WV CDL Manual, Endorsements bölümü."},"26":{"q":"Batı Virginia'da bir otobüste (örneğin bir toplu taşıma aracı veya otokar) ücret karşılığı yolcu taşımak için hangi CDL onayı gereklidir?","options":["S onayı","P onayı","N onayı","H onayı"],"explanation":"16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı kullanmak için 'P' (Yolcu) onayı gereklidir ve hem bir bilgi testi hem de temsili bir araçta yol becerileri testini gerektirir. Kaynak: WV CDL Manual, Endorsements bölümü."},"27":{"q":"Batı Virginia, bir sürücünün okul otobüsü kullanması için Yolcu (P) onayına ek olarak hangi onayı gerektirir?","options":["S onayı","T onayı","N onayı","X onayı"],"explanation":"Bir okul otobüsü kullanmak için 'S' (Okul Otobüsü) onayı gereklidir ve 'P' onayına ek olarak alınır; bir bilgi testi ve okul otobüsünde bir yol becerileri testi gerektirir. Kaynak: WV CDL Manual, Endorsements bölümü."},"28":{"q":"EYALET İÇİ sürüş (yalnızca Batı Virginia içinde çalışma) için bir Batı Virginia CDL'sinin verilebilmesi için minimum yaş nedir?","options":["16 yaş","18 yaş","21 yaş","25 yaş"],"explanation":"Bir başvuru sahibi, eyalet içi (Batı Virginia içinde) ticaret için geçerli bir CDL almak için en az 18 yaşında olmalıdır. Kaynak: WV CDL Manual / WV DMV CDL gereklilikleri."},"29":{"q":"EYALETLER ARASI sürüş (eyalet sınırları arasında) için bir Batı Virginia CDL'sinin verilebilmesi için gereken minimum yaş nedir?","options":["18 yaş","19 yaş","21 yaş","23 yaş"],"explanation":"Batı Virginia tarafından benimsenen federal kurallar, bir sürücünün eyaletler arası ticarette ticari motorlu araç kullanması veya tehlikeli madde taşıması için en az 21 yaşında olmasını gerektirir. Kaynak: WV CDL Manual / WV DMV tarafından uygulanan 49 CFR 391.11."},"30":{"q":"Bir Batı Virginia Commercial Learner's Permit (CLP) aldıktan sonra, başvuru sahibi CDL yol becerileri testine girmeye hak kazanmadan önce bunu ne kadar süre elinde bulundurmalıdır?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Batı Virginia tarafından benimsenen federal yasa, başvuru sahibinin becerileri (yol) testine girmeden önce CLP'yi en az 14 gün elinde bulundurmasını gerektirir. Kaynak: WV DMV CDL sayfası; 49 CFR 383.25."},"31":{"q":"Yenileme açısından, Batı Virginia Commercial Learner's Permit (CLP) hangi ifade en iyi şekilde tanımlar?","options":["Yenilenemez ve geçerliliği bir yılı aşamaz","Sınırsız sayıda yenilenebilir","Normal bir ehliyet gibi beş yıl geçerlidir","Bir kez verildiğinde asla süresi dolmaz"],"explanation":"WV DMV CDL sayfası, Commercial Learner's Permit'in geçerliliğinin bir yılı aşamayacağını ve yenilenemeyeceğini belirtir. Kaynak: WV DMV Commercial Driver's License sayfası."},"32":{"q":"Bir Batı Virginia CLP'si ile ticari motorlu araç kullanırken, izin sahibine aşağıdakilerden hangisi eşlik etmelidir?","options":["O araç tipi için geçerli bir CDL sahibi, sürücünün yanında oturarak","Aracın herhangi bir koltuğunda 21 yaşından büyük herhangi bir ehliyetli sürücü","Yalnızca bir DMV sınav görevlisi","Hiç kimse; CLP tek başına sürüşe izin verir"],"explanation":"Bir CLP sahibi, yalnızca o araç sınıfı/tipi için geçerli bir CDL sahibinin izin sahibinin yanındaki koltukta bulunması durumunda bir CMV kullanabilir. Kaynak: WV DMV CDL sayfası; 49 CFR 383.25."},"33":{"q":"Batı Virginia CDL bilgi (yazılı) testlerinde minimum geçme puanı nedir?","options":["%70","%75","%80","%90"],"explanation":"Batı Virginia, her CDL bilgi testini geçmek için minimum %80 puan gerektirir (HazMat testi yazılı formda alınmalıdır). Kaynak: WV DMV CDL test gereklilikleri."},"34":{"q":"Batı Virginia bir HazMat (H) onayı verebilmeden önce, başvuru sahibinin hangi federal taramayı geçmesi gerekir?","options":["Bir Transportation Security Administration (TSA) güvenlik tehdidi değerlendirmesi","Bir kredi geçmişi incelemesi","Parmak izi olmadan yalnızca eyalet düzeyinde sabıka kaydı kontrolü","Yalnızca görme odaklı bir tıbbi tarama"],"explanation":"Batı Virginia tarafından benimsenen federal yasa, HazMat onayı başvuru sahiplerinin onay verilmeden veya yenilenmeden önce parmak izi alımı ve geçmiş kontrolünü içeren bir TSA güvenlik tehdidi değerlendirmesini geçmesini gerektirir. Kaynak: WV CDL Manual; 49 CFR 1572 (TSA)."},"35":{"q":"Bir Batı Virginia CDL'sinde HazMat (H) onayı almak için minimum yaş nedir?","options":["18 yaş","21 yaş","25 yaş","19 yaş"],"explanation":"Tehlikeli madde taşıma, federal kurallar uyarınca eyaletler arası nitelikli statü gerektirdiğinden, bir başvuru sahibinin HazMat onayını almak için en az 21 yaşında olması gerekir. Kaynak: WV CDL Manual; TSA/FMCSA HazMat gereklilikleri."},"36":{"q":"Batı Virginia'da ilk kez CDL başvurusu yapanlar, Entry-Level Driver Training'i (ELDT) şu nitelikte bir sağlayıcı aracılığıyla tamamlamalıdır:","options":["FMCSA Training Provider Registry'de (TPR) listelenmiş","Yalnızca Batı Virginia Eyalet Polisi tarafından onaylanmış","Başvuru sahibinin seçtiği herhangi bir özel sürücü kursu","TSA tarafından sertifikalandırılmış"],"explanation":"ELDT, FMCSA Training Provider Registry'de (TPR) listelenmiş bir sağlayıcı ile tamamlanmalıdır. İlk kez Class A veya B CDL alanlar, B'den A'ya yükseltenler veya ilk kez P, S ya da H onayı arayanlar için geçerlidir (7 Şubat 2022 ve sonrasında). Kaynak: FMCSA ELDT kuralı; WV DMV CDL sayfası."},"37":{"q":"Bir Batı Virginia CDL başvuru sahibinin seçmesi gereken dört tıbbi öz-beyan kategorisinden biri aşağıdakilerden hangisidir?","options":["Non-Excepted Interstate (NI)","Recreational Interstate (RI)","Commercial Exempt (CE)","Limited Local (LL)"],"explanation":"Dört öz-beyan kategorisi şunlardır: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Non-excepted kategorilerindeki sürücüler geçerli bir DOT tıbbi sınav görevlisi sertifikasına sahip olmalıdır. Kaynak: WV DMV CDL öz-beyan; FMCSA."},"38":{"q":"'Non-Excepted Interstate (NI)' olarak beyan veren bir Batı Virginia CDL sürücüsü hangi belgeyi sunmalıdır?","options":["Geçerli bir tıbbi sınav görevlisi sertifikası (DOT tıbbi kartı)","Yalnızca bir motorlu araç sigortası belgesi","İmzalı bir işveren muafiyet mektubu","Başvurunun ötesinde ek hiçbir şey"],"explanation":"Non-excepted bir kategoriye (NI veya NA) beyan veren sürücüler, FMCSA National Registry'deki bir sınav görevlisinden geçerli bir tıbbi sınav görevlisi sertifikası almalı ve sunmalıdır; excepted kategoriler (EI, EA) DOT tıbbi kartı gerektirmez. Kaynak: WV DMV CDL öz-beyan; FMCSA."},"39":{"q":"Bir Batı Virginia CDL veya CLP başvurusu yaparken, DMV kaç adet Batı Virginia ikamet kanıtı ister?","options":["Bir ikamet kanıtı","İki ikamet kanıtı","Üç ikamet kanıtı","İkamet kanıtı gerekmez"],"explanation":"Batı Virginia, bir CDL/CLP başvurusu için bir kimlik/yasal mevcudiyet kanıtı, bir Social Security numarası kanıtı ve iki Batı Virginia ikamet kanıtı ister. Kaynak: WV DMV kabul edilen belgeler / sürücü ehliyeti gereklilikleri."},"40":{"q":"Batı Virginia yasasına göre, bir sürücünün ticari motorlu araç (CMV) kullanırken aşırı alkollü kabul edilip diskalifiyeyi tetiklediği kan alkol konsantrasyonu (BAC) nedir?","options":["%0.08 veya daha fazla","%0.02 veya daha fazla","%0.10 veya daha fazla","%0.04 veya daha fazla"],"explanation":"Batı Virginia, CMV alkol sınırını kişisel araçlar için %0.08 sınırının yarısı olan %0.04 (\"ağırlıkça yüzde birin dört yüzde biri veya daha fazlası\") olarak belirler. Kaynak: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)(2)."},"41":{"q":"Batı Virginia'da, %0.04'ün altında herhangi bir tespit edilebilir alkol miktarına sahip olduğu bulunan bir CMV sürücüsüne ne yapılmalıdır?","options":["1 yıl boyunca derhal diskalifiye edilir","24 saat hizmet dışı bırakılır","Hizmet dışı süresi olmadan $2,500 para cezası verilir","Yalnızca uyarı verilir, ceza yoktur"],"explanation":"%0.04'ün altında herhangi bir tespit edilebilir ölçülebilir alkole sahip bir CMV sürücüsü, diskalifiye edici %0.04 eşiğinin altında olsa bile 24 saat hizmet dışı bırakılır. Kaynak: WV CDL Manual Section 1.3 ve Implied Consent hükümleri; WV Code 17E-1-13."},"42":{"q":"Plakartlı tehlikeli madde taşımıyorken, bir CMV sürücüsünün DUI veya %0.04 BAC gibi İLK büyük suçu için Batı Virginia'daki diskalifiye süresi nedir?","options":["60 gün","3 yıl","1 yıl","6 ay"],"explanation":"İlk büyük suç (DUI, %0.04 BAC, ret, olay yerini terk etme, bir aracı bir suçta kullanma vb.) Batı Virginia'da 1 yıllık CDL diskalifiyesiyle sonuçlanır. Kaynak: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)."},"43":{"q":"Bir Batı Virginia CMV sürücüsü, plakart gerektiren tehlikeli madde taşırken ilk büyük suçu işlerse, diskalifiye süresi nedir?","options":["3 yıl","1 yıl","5 yıl","180 gün"],"explanation":"Plakartlı tehlikeli madde taşıyan bir CMV kullanılırken işlenen ilk büyük suç (49 CFR Part 172, Subpart F uyarınca), 1 yıl yerine 3 yıllık artırılmış bir diskalifiye taşır. Kaynak: WV CDL Manual; WV Code 17E-1-13(b)(1)(C)."},"44":{"q":"Batı Virginia'da İKİNCİ bir büyük suç (ayrı bir olayda) için diskalifiye süresi nedir?","options":["10 yıl","Ömür boyu","3 yıl","5 yıl"],"explanation":"Ayrı bir olaydaki ikinci bir büyük suç, Batı Virginia'da ömür boyu CDL diskalifiyesiyle sonuçlanır. DMV, belirli koşullar altında asgari bir süreden sonra yeniden yetkilendirmeye izin verebilir, ancak bu ömür boyu diskalifiye olarak uygulanır. Kaynak: WV CDL Manual; WV Code 17E-1-13(b)(1)(D)."},"45":{"q":"Batı Virginia'da, bir CMV kullanırken belirlenmiş kimyasal (ikincil) testi yaptırmayı reddetmek, ilk ret için hangi diskalifiyeyle sonuçlanır?","options":["60 gün","1 yıl","90 gün","30 gün"],"explanation":"Test reddi bir büyük suç gibi işlem görür: ilk ret sürücüyü 1 yıl (plakartlı tehlikeli madde taşıyorsa 3 yıl) diskalifiye eder ve ikincisi ömür boyu diskalifiyeyle sonuçlanır. Kaynak: WV CDL Manual; WV Code 17E-1-13(b)(3)."},"46":{"q":"Batı Virginia'nın Implied Consent Law'u uyarınca, eyalette araç kullanma ayrıcalığını kabul ederek, bir sürücü aşağıdakilerden hangisine onay vermiş sayılır?","options":["Herhangi bir trafik durdurmasında araç aramasına","Zorunlu bir DUI eğitim kursuna","Rastgele yol kenarı uyuşturucu köpeği denetimlerine","Vücudundaki alkol içeriğini belirlemek için bir kimyasal teste"],"explanation":"Batı Virginia'nın Implied Consent Law'u, eyalette araç kullanan herhangi bir kişinin alkol içeriği için belirlenmiş kimyasal testi yaptırmaya onay verdiği anlamına gelir. Ret, sürüş ayrıcalıklarını en az 1 yıl, ömür boyuna kadar askıya alır. Kaynak: WV CDL Manual, Implied Consent Law; WV Code 17C-5-4."},"47":{"q":"Batı Virginia Implied Consent Law uyarınca, bir kimyasal testi reddetmek, bir sürücünün motorlu araç kullanma ayrıcalığını hangi minimum süre boyunca askıya alır?","options":["En az 90 gün","En az 30 gün","En az 1 yıl","En az 6 ay"],"explanation":"Batı Virginia'nın Implied Consent Law'u uyarınca belirlenmiş kimyasal testi reddetmek, motorlu araç kullanma ayrıcalığını en az 1 yıl ve ömür boyuna kadar bir süre askıya alır. Kaynak: WV CDL Manual, Implied Consent Law."},"48":{"q":"Batı Virginia'da 3 yıllık bir süre içinde kaç ciddi trafik ihlali 60 günlük bir diskalifiyeyi tetikler?","options":["1 (ilk ihlal)","3 (3 yıl içinde üçüncü)","2 (3 yıl içinde ikinci)","4 (3 yıl içinde dördüncü)"],"explanation":"3 yıllık bir süre içinde ikinci bir ciddi trafik ihlali 60 günlük bir diskalifiyeyle sonuçlanır. İlk ciddi ihlal tek başına diskalifiye etmez. Kaynak: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"49":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir ciddi trafik ihlali için Batı Virginia'daki diskalifiye süresi nedir?","options":["120 gün","60 gün","1 yıl","90 gün"],"explanation":"3 yıllık bir süre içinde üçüncü veya sonraki bir ciddi trafik ihlali 120 günlük bir diskalifiyeyle sonuçlanır. Kaynak: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"50":{"q":"Batı Virginia CDL diskalifiye amaçları açısından aşağıdakilerden hangisi \"ciddi trafik ihlali\" olarak sınıflandırılır?","options":["Belirlenen limitin 5 mph üzerinde araç kullanma","Aşırı hız (belirlenen limitin 15 mph veya daha fazla üzerinde)","Bir park ihlali","Süresi dolmuş bir tescil etiketi"],"explanation":"Ciddi trafik ihlalleri arasında aşırı hız (belirlenen limitin 15 mph veya daha fazla üzerinde), dikkatsiz sürüş, uygunsuz veya düzensiz şerit değiştirme, çok yakın takip etme ve araç kullanırken mesajlaşma yer alır. Park ihlalleri hariçtir. Kaynak: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"51":{"q":"Batı Virginia'da, tehlikesiz kargo taşıyan bir CMV kullanırken bir hizmet dışı (out-of-service) emrini ihlal etmeden İLK mahkumiyet için diskalifiye süresi nedir?","options":["90 gün","60 gün","180 gün","1 yıl"],"explanation":"Bir CMV kullanırken bir hizmet dışı emrini ihlal etmek için ilk mahkumiyet, Batı Virginia'da 180 günlük bir diskalifiyeyle sonuçlanır. Kaynak: WV CDL Manual; WV Code 17E-1-13(e)(1)(A)."},"52":{"q":"Batı Virginia'da tehlikesiz madde taşırken 10 yıllık bir süre içinde İKİNCİ bir hizmet dışı emir ihlali için diskalifiye süresi nedir?","options":["180 gün","2 yıl","3 yıl","1 yıl"],"explanation":"10 yıl içinde ayrı bir olayda ikinci bir hizmet dışı emir ihlali (tehlikesiz), 2 yıllık bir diskalifiyeyle sonuçlanır. 10 yıl içinde üçüncü veya sonraki ise 3 yılla sonuçlanır. Kaynak: WV CDL Manual; WV Code 17E-1-13(e)(1)(B)."},"53":{"q":"Batı Virginia'da, plakartlı tehlikeli madde taşırken VEYA 16 ya da daha fazla yolcu taşımak için tasarlanmış bir araç kullanırken 10 yıl içinde İKİNCİ bir hizmet dışı emir ihlali hangi diskalifiyeyle sonuçlanır?","options":["2 yıl","180 gün","1 yıl","3 yıl"],"explanation":"Plakartlı tehlikeli madde taşırken veya 16+ yolcu taşırken 10 yıl içinde ikinci bir hizmet dışı emir ihlali, artırılmış 3 yıllık bir diskalifiye taşır (tehlikesiz için 2 yıla kıyasla). Kaynak: WV CDL Manual; WV Code 17E-1-13(e)(2)(B)."},"54":{"q":"Bir CMV kullanırken İLK demiryolu-karayolu hemzemin geçit ihlali için Batı Virginia'daki diskalifiye süresi nedir?","options":["30 gün","120 gün","60 gün","180 gün"],"explanation":"Bir CMV kullanırken ilk demiryolu-karayolu hemzemin geçit ihlali, Batı Virginia'da 60 günlük bir diskalifiyeyle sonuçlanır. Kaynak: WV CDL Manual; WV Code 17E-1-13(d)."},"55":{"q":"Batı Virginia'da, demiryolu-karayolu hemzemin geçit ihlalleri için diskalifiye süreleri, ilk suç için 60 günden, 3 yıl içinde İKİNCİ ve ÜÇÜNCÜ suç için neye yükselir?","options":["İkinci için 120 gün; üçüncü için 1 yıl","İkinci için 90 gün; üçüncü için 180 gün","İkinci için 60 gün; üçüncü için 120 gün","İkinci için 180 gün; üçüncü için 2 yıl"],"explanation":"Demiryolu geçit ihlalleri bir sürücüyü 60 gün (ilk), 120 gün (3 yıl içinde ikinci) ve 1 yıl (3 yıl içinde üçüncü veya sonraki) diskalifiye eder. Kaynak: WV CDL Manual; WV Code 17E-1-13(d)."},"56":{"q":"Eyalet tarafından benimsenen Batı Virginia ve federal kurallar uyarınca, bir CMV sürücüsünün CDL'si, bir CMV kullanırken mesajlaşma için kaç mahkumiyetten sonra diskalifiye edilir?","options":["1 mahkumiyet (ilk suç)","3 yıl içinde 4 veya daha fazla mahkumiyet","5 yıl içinde 3 veya daha fazla mahkumiyet","3 yıl içinde 2 veya daha fazla mahkumiyet"],"explanation":"Bir CMV kullanırken mesajlaşma ciddi bir ihlaldir: CDL, 3 yıl içinde ikinci mahkumiyetten sonra 60 gün ve 3 yıl içinde üç veya daha fazla mahkumiyet için 120 gün diskalifiye edilir. İlk mahkumiyet diskalifiye etmez ancak bir hukuki para cezası taşır. Kaynak: WV CDL Manual Section 2.9.5; WV Code 17E-1-13(c)(9)."},"57":{"q":"Araç kullanırken mesajlaşan veya elde tutulan bir cep telefonu kullanan bir CMV sürücüsü için maksimum federal hukuki para cezası (Batı Virginia'da benimsenmiş) nedir?","options":["$2,750'ye kadar","$500'e kadar","$11,000'e kadar","$5,000'e kadar"],"explanation":"Her mesajlaşma/elde tutulan telefon ihlali, CMV sürücüsünü $2,750'ye kadar bir hukuki para cezasına tabi tutar. (Buna izin veren veya bunu gerektiren işverenlere $11,000'e kadar para cezası verilebilir.) Kaynak: WV CDL Manual Sections 2.9.4 ve 2.9.5."},"58":{"q":"Kişisel araç ehliyeti bir alkol, kontrollü madde veya suç ihlali nedeniyle askıya alınan bir Batı Virginia CDL sahibi, ilk ihlalde CDL ayrıcalıklarını ne kadar süreyle kaybeder?","options":["1 yıl","60 gün","90 gün","6 ay"],"explanation":"Bir CDL sahibinin kişisel araç ayrıcalıkları alkol, kontrollü madde veya suç ihlalleri nedeniyle iptal, fesih veya askıya alınırsa, CDL 1 yıl kaybedilir; ikinci böyle bir ihlal (kişisel araç veya CMV) ömür boyu kayıpla sonuçlanır. Kaynak: WV CDL Manual Section 1.3; WV Code 17E-1-13(b)."},"59":{"q":"Batı Virginia sürücü puan sistemi kapsamında, kaç puana ulaşmak sürüş ayrıcalıklarının askıya alınmasıyla sonuçlanır?","options":["6 veya daha fazla puan","20 veya daha fazla puan","8 veya daha fazla puan","12 veya daha fazla puan"],"explanation":"Batı Virginia DMV puan sistemi, 12 veya daha fazla puana ulaşıldığında sürüş ayrıcalıklarını askıya alır. Örneğin, limitin 20 mph veya daha fazla üzerinde hız 6 puan ve dikkatsiz sürüş 6 puandır. Kaynak: WV CDL Manual / WV Driver's Licensing Handbook, Point System."},"60":{"q":"BÖLÜNMEMİŞ bir Batı Virginia karayolunda, yanıp sönen ışıklar gösteren, durmuş bir acil durum veya hizmet aracından güvenli bir şekilde uzaklaşacak şekilde şerit değiştiremiyorsanız, eyaletin Move Over yasası uyarınca aracı geçerken çıkabileceğiniz azami hız nedir?","options":["15 mph","25 mph","10 mph","20 mph"],"explanation":"West Virginia Code 17C-14-9a (Move Over yasası), şerit değiştiremeyen bir sürücünün, durmuş yetkili bir acil durum veya hizmet aracını geçerken herhangi bir bölünmemiş karayolu veya caddede hızını güvenli bir seviyeye ve 15 mph'yi aşmayacak şekilde düşürmesini gerektirir. Kaynak: WV Code 17C-14-9a."},"61":{"q":"BÖLÜNMÜŞ bir Batı Virginia karayolunda, bitişik olmayan bir şeride güvenli bir şekilde geçemediğiniz durumda, uyarı ışıkları gösteren durmuş bir acil durum aracını geçerken çıkabileceğiniz azami hız nedir?","options":["15 mph","35 mph","25 mph","20 mph"],"explanation":"WV Code 17C-14-9a uyarınca, şerit değiştiremeyen bir sürücü, durmuş bir acil durum veya hizmet aracını geçerken herhangi bir bölünmüş karayolunda hızını güvenli bir seviyeye ve 25 mph'yi aşmayacak şekilde düşürmelidir. Kaynak: WV Code 17C-14-9a."},"62":{"q":"Batı Virginia CDL Kılavuzu'na göre, plakart taşıyan bir HazMat aracı, klor yükü veya kargo tankı, bir demiryolu geçidinde en yakın raydan ne kadar uzakta durmalıdır?","options":["10 ile 25 fit arası","15 ile 50 fit arası","5 ile 15 fit arası","25 ile 75 fit arası"],"explanation":"WV CDL Kılavuzu (Bölüm 9.6.12), plakart taşıyan, herhangi bir miktarda klor taşıyan veya tehlikeli maddeler için kullanılan kargo tankları olan bir aracın en yakın raydan 15 ile 50 fit önce durması gerektiğini belirtir. Kaynak: WV CDL Manual, Sec. 9.6.12."},"63":{"q":"Batı Virginia'da bir otobüs sürücüsü, otobüsü bir demiryolu geçidinden ne kadar önce durdurmalıdır?","options":["20 ile 40 fit arası","En az 50 fit","10 ile 30 fit arası","15 ile 50 fit arası"],"explanation":"WV CDL Kılavuzu (Bölüm 4.3.5), otobüs sürücülerine, otobüsü demiryolu geçitlerinden 15 ile 50 fit önce durdurmalarını, ardından trenler için her iki yönü dinlemelerini ve bakmalarını söyler. Kaynak: WV CDL Manual, Sec. 4.3.5."},"64":{"q":"Aksi belirtilmedikçe, bir Batı Virginia eyaletler arası karayolundaki azami belirlenmiş hız sınırı nedir?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"WV CDL Kılavuzu'nun belirlenmiş hızlar tablosu, eyaletler arası karayollarını 70 mph olarak listeler (aksi belirtilmedikçe). Kaynak: WV CDL Manual, belirlenmiş hızlar tablosu; WV Code 17C-6-1."},"65":{"q":"Aksi belirtilmedikçe, bir Batı Virginia ticari veya yerleşim bölgesindeki azami hız sınırı nedir?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"Batı Virginia, WV CDL Kılavuzu belirlenmiş hızlar tablosunda gösterildiği gibi, herhangi bir ticari veya yerleşim bölgesinde azami 25 mph belirler. Kaynak: WV Code 17C-6-1; WV CDL Manual."},"66":{"q":"Çocuklar mevcutken bir Batı Virginia okul bölgesindeki azami hız sınırı nedir?","options":["20 mph","25 mph","15 mph","10 mph"],"explanation":"WV Code 17C-6-1, teneffüs sırasında veya çocuklar okula gidip gelirken bir okul bölgesinde 15 mph belirler; WV CDL Kılavuzu aynı rakamı listeler. Kaynak: WV Code 17C-6-1; WV CDL Manual."},"67":{"q":"Batı Virginia'da açık bir kırsal karayolunda (eyaletler arası veya kontrollü erişimli bir yol değil), aksi belirtilmedikçe varsayılan azami hız sınırı nedir?","options":["60 mph","65 mph","50 mph","55 mph"],"explanation":"WV CDL Kılavuzu belirlenmiş hızlar tablosu, WV Code 17C-6-1 ile tutarlı olarak, açık karayollarını aksi belirtilmedikçe 55 mph olarak listeler. Kaynak: WV Code 17C-6-1; WV CDL Manual."},"68":{"q":"West Virginia Code 17C-12-7 uyarınca, çocukları bindirmek veya indirmek için uyarı sinyal ışıkları yanıp sönerek durmuş bir okul otobüsüyle karşılaştığınızda veya onu geçtiğinizde şunları yapmalısınız:","options":["Otobüse ulaşmadan önce durun ve ışıklar sönene veya sürücü işaret edene kadar devam etmeyin","10 mph'ye yavaşlayın ve dikkatle geçin","Yalnızca otobüsle aynı yönde gidiyorsanız durun","En uzak şeride geçin ve azaltılmış hızda devam edin"],"explanation":"WV Code 17C-12-7, her iki yönden de yanıp sönen uyarı ışıkları olan bir okul otobüsüyle karşılaşan veya onu geçen bir sürücünün, otobüse ulaşmadan önce durmasını ve otobüs hareket edene, ışıklar sönene veya otobüs sürücüsü işaret edene kadar devam etmemesini gerektirir. Kaynak: WV Code 17C-12-7."},"69":{"q":"Batı Virginia okul otobüsü yasası uyarınca, yayaların geçmesine izin verilmeyen farklı bir yolda bulunan bir okul otobüsü için bir sürücünün durmak zorunda OLMADIĞI yol türü hangisidir?","options":["Herhangi bir dört şeritli karayolu","Ortada dönüş şeridi olan herhangi bir yol","Kontrollü erişimli bir karayolu","Boyalı refüjlü iki şeritli bir yol"],"explanation":"WV Code 17C-12-7, kontrollü erişimli bir karayolundaki bir sürücünün, yayaların geçmesine izin verilmeyen farklı bir yoldaki veya karayoluna bitişik bir okul otobüsü için durmak zorunda olmadığını öngörür. Yalnızca boyalı bir çizgi veya ortadaki bir şerit bu istisnayı TETİKLEMEZ. Kaynak: WV Code 17C-12-7."},"70":{"q":"Bir Batı Virginia karayolunun banketinde bir ticari aracı durdurduktan sonra, acil durum uyarı cihazlarınızı kaç dakika içinde yerleştirmelisiniz?","options":["5 dakika","10 dakika","15 dakika","30 dakika"],"explanation":"WV CDL Kılavuzu, bir yolda veya bankette durmanız gerekiyorsa acil durum uyarı cihazlarınızı on dakika içinde yerleştirmeniz gerektiğini belirtir. Kaynak: WV CDL Manual, Sec. 2.5."},"71":{"q":"TEK YÖNLÜ veya BÖLÜNMÜŞ bir Batı Virginia karayolunda durduğunuzda, üç reflektörlü üçgen nereye yerleştirilmelidir?","options":["Önde ve arkada 10 fit, 100 fit ve 100 fit","Arkaya doğru 50 fit, 100 fit ve 500 fit","Yaklaşan trafiğe doğru 10 fit, 50 fit ve 150 fit","Yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit"],"explanation":"WV CDL Kılavuzu, tek yönlü veya bölünmüş bir karayolunda uyarı cihazlarının araçtan yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit yerleştirilmesini söyler. Kaynak: WV CDL Manual, Sec. 2.5."},"72":{"q":"Bir Batı Virginia sürücüsünün reflektörlü üçgenleri yoksa, CDL Kılavuzu park edilmiş araç uyarısı için hangi uyarı cihazlarını ikame olarak kabul eder?","options":["En az 6 fişek (fusee) veya 3 sıvı yanan işaret fişeği (flare)","En az 2 fişek (fusee) veya 1 sıvı yanan işaret fişeği (flare)","Tek bir dönen sarı işaret lambası","En az 4 yol konisi"],"explanation":"WV CDL Kılavuzu, park edilmiş araçlar için uyarı cihazlarını üç reflektörlü üçgen veya en az 6 fişek (fusee) ya da 3 sıvı yanan işaret fişeği (flare) olarak listeler. Kaynak: WV CDL Manual, araç muayenesi/acil durum ekipmanı bölümü."},"73":{"q":"Batı Virginia neden belirli plakart taşıyan yüklerin çevresinde işaret fişeği (flare) veya açık alevli uyarı cihazlarının kullanımını yasaklar?","options":["Geceleri görülemeyecek kadar sönüktürler","Yalnızca bölünmüş karayollarında yasaldırlar","Sınıf 3 yanıcı sıvılar gibi yanıcı kargoları tutuşturabilirler","Aracın aküsünü tüketirler"],"explanation":"WV CDL Kılavuzu'nun 'No Flares!' (İşaret Fişeği Yok!) kuralı, Sınıf 3 yanıcı sıvılar gibi yanıcı maddeler taşıyan araçların çevresinde yanan işaret fişekleri veya fişekler yerine reflektörlü üçgenler veya kırmızı elektrikli ışıklar kullanılmasını söyler. Kaynak: WV CDL Manual, Sec. 9.6.4."},"74":{"q":"Batı Virginia'nın şerit kullanım kuralı uyarınca, kamyon trafiği dahil tüm sürücüler normalde nerede seyretmelidir?","options":["Birleşme için sağ şeridi açık tutmak amacıyla orta şeritte","Geçiş, dönüş veya engellerden kaçınma durumları dışında en sağdaki şeritte","Trafiğin en az olduğu şeritte","Sağ şeridi daha yavaş araçlara bırakmak için sol şeritte"],"explanation":"Batı Virginia (Bölüm 17C, Madde 7), kamyonlar dahil sürücülerin; geçiş yaparken/sollarken, sağ şerit kapalıyken, normal trafik hızının altında seyrederken veya dönüşe hazırlanırken hariç olmak üzere, varsayılan olarak en sağdaki şeritte seyretmesini gerektirir. Kaynak: WV Code Ch. 17C, Art. 7."},"75":{"q":"ÜÇ şeritli bir Batı Virginia karayolunda, bir kamyon şeritleri nasıl kullanabilir?","options":["Üç şeridin herhangi birini serbestçe kullanabilir","Yalnızca orta şeridi kullanmalıdır","İki sol şeridi kullanabilir ve sağ şeritte geçiş yapabilir","Sağ şeritte kalmalı, ancak geçiş yapmak için orta şeridi kullanabilir"],"explanation":"Batı Virginia şerit kurallarına göre, üç şeritli bir yoldaki kamyonlar sağ şeritle sınırlıdır ancak geçiş yapmak için orta şeride geçebilirler. Kaynak: WV Code Ch. 17C, Art. 7."},"76":{"q":"DÖRT şeritli bir Batı Virginia karayolunda, yarı römork çeken bir çekici hangi şeritleri kullanabilir?","options":["En sağdaki iki şeridi","Yalnızca en sağ şeridi","En sol hariç herhangi bir şeridi","En soldaki iki şeridi"],"explanation":"Batı Virginia, dört şeritli bir karayolunda yarı römork çeken çekicilerin en sağdaki iki şeritte seyretmesine izin verir. Kaynak: WV Code Ch. 17C, Art. 7."},"77":{"q":"10 fit veya daha geniş şeritleri olan Eyaletler arası, ABD ve WV güzergahlarında, Batı Virginia'nın (izin olmadan) yasal azami araç genişliği nedir?","options":["8 fit 0 inç","9 fit 0 inç","8 fit 6 inç","10 fit 0 inç"],"explanation":"WV Karayolları Bölümü'nün yasal boyut sınırları, azami genişliği şeritleri 10 fit veya daha büyük olan Eyaletler arası, ABD, WV ve yerel güzergahlarda 8 fit 6 inç olarak belirler (daha dar yerel güzergahlarda 8 fit). Kaynak: WVDOT/Division of Highways Legal Size and Weight Limits."},"78":{"q":"Bir Batı Virginia EYALETLER ARASI karayolundaki bir araç için yasal azami brüt ağırlık (izin olmadan) nedir?","options":["65,000 pound","80,000 pound","73,280 pound","90,000 pound"],"explanation":"Batı Virginia'nın eyaletler arası karayollarındaki yasal brüt ağırlık sınırı 80,000 pounddur (sıfır tolerans); yerel hizmet güzergahları 65,000 pound ile sınırlıdır. Kaynak: WVDOT Legal Size and Weight Limits."},"79":{"q":"West Virginia Turnpike (I-77) hakkında ticari sürücüler için hangi ifade doğrudur?","options":["Çekici-römorkların Turnpike'a girmesi tamamen yasaktır","Gişe alanı olmayan ücretsiz bir eyaletler arası karayoludur","Kamyonlar onu yalnızca gün doğumu ile gün batımı arasında kullanabilir","Kamyonların ana hat gişelerinde ücret ödediği, ücretli bir dağ eğimli karayoludur"],"explanation":"West Virginia Turnpike, I-77'yi dik dağ eğimlerinden (yaklaşık %5'e kadar) geçirir ve kamyonların boyut/aks sayısına göre ücret ödediği ana hat gişeleri (Ghent, Pax, Chelyan) olan ücretli bir yoldur; ayrıca kaçak kamyon rampaları da bulunur. Kaynak: WV Parkways Authority / WVDOT Turnpike sayfaları."},"80":{"q":"Batı Virginia'da Ticari Sürücü Belgelerini (CDL) hangi eyalet kurumu verir?","options":["West Virginia Division of Motor Vehicles (DMV)","West Virginia Eyalet Polisi","West Virginia Public Service Commission","West Virginia Division of Highways"],"explanation":"Batı Virginia'da CDL'ler, bilgi testlerini yöneten ve başvuruları işleyen West Virginia Division of Motor Vehicles (DMV) tarafından verilir. Kaynak: WV DMV Commercial Driver's License sayfası (transportation.wv.gov/DMV/Motor-Carriers/CDL)."},"81":{"q":"Batı Virginia tam bir CDL vermeden önce, bir başvuru sahibinin önce hangi belgeyi alması ve elinde bulundurması gerekir?","options":["Commercial Learner's Permit (CLP)","Class D operatör ehliyeti onayı","Federal eyaletler arası işletme yetkisi","Geçici zorluk sürüş izni"],"explanation":"Batı Virginia, başvuru sahiplerinin önce DMV'den, beceri testinden önce gözetim altında pratik yapmaya yetki veren bir Commercial Learner's Permit (CLP) almasını gerektirir. Kaynak: WV DMV CDL sayfası."},"82":{"q":"Batı Virginia'da, bir başvuru sahibi CDL yol beceri testine girmeye hak kazanmadan önce bir Commercial Learner's Permit (CLP) ne kadar süre elinde bulundurmalıdır?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Batı Virginia (federal standardı takip ederek), başvuru sahibinin yol beceri testine girebilmesi için CLP'nin en az 14 gün elde tutulmasını gerektirir. Kaynak: WV DMV CDL sayfası; WV'de uygulandığı şekliyle 49 CFR 383.25."},"83":{"q":"Ticari operasyon türünü öz-belgelendirirken, bir Batı Virginia CDL/CLP başvuru sahibi kaç kategori arasından seçim yapmalıdır?","options":["Dört kategori","İki kategori","Üç kategori","Beş kategori"],"explanation":"Batı Virginia, başvuru sahiplerinin dört ticari motorlu araç operasyon kategorisinden birini öz-belgelendirmesini gerektirir: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Kaynak: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3)."},"84":{"q":"Hangi Batı Virginia öz-belgelendirme kategorisi, sürücünün dosyada geçerli bir DOT Medical Examiner's Certificate bulundurmasını gerektirir?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Yalnızca eyalet içinde çalışan herhangi bir sürücü muaftır"],"explanation":"Excepted olmayan bir statüye (NI veya NA) öz-belgelendiren sürücüler, geçerli bir FMCSA Medical Examiner's Certificate bulundurmalıdır; excepted statüler (EI, EA) bu gereklilikten muaftır. Kaynak: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3); FMCSA 49 CFR 383.71."},"85":{"q":"23 Haziran 2025 itibarıyla geçerli olmak üzere, excepted olmayan bir Batı Virginia CDL sürücüsünün DOT tıbbi bilgileri normalde DMV'ye nasıl sağlanır?","options":["Sertifikalı tıbbi muayene uzmanı, muayene sonuçlarını DMV'ye ileten güvenli bir elektronik veritabanına girer","Sürücü her muayeneden sonra DMV'ye kağıt bir tıbbi kart postalar","Sürücünün işvereni tıbbi kartı DMV'ye faksla gönderir","Tıbbi kart yalnızca ehliyet yenileme sırasında doğrulanır"],"explanation":"23 Haziran 2025 itibarıyla, Batı Virginia artık kağıt tıbbi sertifikaları kabul etmiyor; sertifikalı tıbbi muayene uzmanı muayene sonuçlarını DMV'ye gönderilen güvenli bir veritabanına elektronik olarak girer. Kaynak: WV DMV'nin geliştirilmiş CDL tıbbi belgelendirme süreciyle ilgili duyurusu (Haziran 2025)."},"86":{"q":"Bir Batı Virginia CDL bilgi (yazılı) testinde geçer asgari puan nedir?","options":["Yüzde 80","Yüzde 70","Yüzde 75","Yüzde 90"],"explanation":"Batı Virginia, bir CDL bilgi testini geçmek için en az yüzde 80 doğru cevap gerektirir. Kaynak: WV Commercial Driver's License Manual; WV DMV CDL test kuralları."},"87":{"q":"Batı Virginia CDL beceri testi, sırasıyla hangi üç bölümden oluşur?","options":["Sefer öncesi araç muayenesi, temel araç kontrolü ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Hava freni kontrolü, bağlantı testi ve tepki süresi testi","Geri manevralar, otoyola katılım ve paralel park"],"explanation":"Batı Virginia CDL beceri testi üç bölümden oluşur: sefer öncesi araç muayenesi, temel araç kontrol beceri testi ve yolda sürüş testi. Kaynak: WV Commercial Driver's License Manual (Beceri Testi bölümleri)."},"88":{"q":"Batı Virginia CDL beceri (yol) testinde kullanılan aracı kim sağlamalıdır?","options":["Test edilen sınıfı temsil eden bir araç sağlaması gereken başvuru sahibi","Standart bir test kamyonu sağlayan DMV","Division of Highways araç havuzu","Binek otomobil dahil herhangi bir araç kabul edilebilir"],"explanation":"Başvuru sahibi beceri testi için aracı sağlamalıdır ve araç, başvuru sahibinin test olduğu CDL sınıfını temsil etmelidir. Kaynak: WV Commercial Driver's License Manual; WV DMV CDL sayfası."},"89":{"q":"İlk kez başvuran bir Batı Virginia CDL başvuru sahibi, hangi teste girmeden önce Entry-Level Driver Training (ELDT) tamamlamalıdır?","options":["CDL beceri (yol) testi","Görme taraması","Class D yenileme testi","Parmak izi geçmiş kontrolü"],"explanation":"ELDT (teori ve direksiyon başında), ilk kez başvuran Class A/B başvuru sahipleri ve belirli onaylar için CDL beceri testinden önce tamamlanmalıdır. Kaynak: WV DMV CDL sayfası; FMCSA ELDT kuralı (49 CFR Part 380), 7 Şubat 2022'de yürürlüğe girdi."},"90":{"q":"Batı Virginia'da uygulanan federal ELDT kuralı uyarınca, bir sürücü hangi tarihten önce hiç CDL'ye sahip olmadıysa 'ilk kez başvuran' bir CDL başvuru sahibi olarak kabul edilir (ve ELDT tamamlamalıdır)?","options":["7 Şubat 2022","1 Ocak 2020","1 Ekim 2021","23 Haziran 2025"],"explanation":"ELDT gereklilikleri geriye dönük değildir: 7 Şubat 2022'den önce hiç CDL'ye (veya ilgili S, P ya da H onayına) sahip olmamış bir kişi, ELDT tamamlaması gereken ilk kez başvuran bir kişidir. Kaynak: WV DMV CDL sayfası; FMCSA ELDT nihai kuralı."},"91":{"q":"Bir Batı Virginia ELDT eğitim sağlayıcısının, eğitimin CDL uygunluğuna sayılması için nerede listelenmesi gerekir?","options":["FMCSA Training Provider Registry (TPR) üzerinde","Yalnızca West Virginia DMV tedarikçi listesinde","Eyalet Division of Highways yüklenici listesinde","National CDL Examiner Directory üzerinde"],"explanation":"ELDT'nin, Batı Virginia'daki CDL gerekliliğini karşılaması için FMCSA Training Provider Registry (TPR) üzerinde listelenen bir sağlayıcı aracılığıyla tamamlanması gerekir. Kaynak: WV DMV CDL sayfası; FMCSA TPR (tpr.fmcsa.dot.gov)."},"92":{"q":"Batı Virginia'da, eyalet içi (yalnızca eyalet içinde) operasyon için bir CDL almanın asgari yaşı nedir?","options":["18 yaş","21 yaş","19 yaş","16 yaş"],"explanation":"Bir başvuru sahibinin eyalet içi operasyon için bir Batı Virginia CDL alması için en az 18 yaşında olması gerekir; eyaletler arası operasyon ve tehlikeli maddeler 21 yaşını gerektirir. Kaynak: WV DMV CDL sayfası; WV Code Chapter 17E."},"93":{"q":"Batı Virginia CDL kuralları uyarınca, eyaletler arası ticarette bir ticari motorlu aracı kullanmanın veya tehlikeli madde taşımanın asgari yaşı nedir?","options":["21 yaş","18 yaş","19 yaş","25 yaş"],"explanation":"Batı Virginia, bir sürücünün eyaletler arası çalışması veya plakart taşıyan tehlikeli maddeleri taşıması için en az 21 yaşında olmasını gerektirir; 18-20 yaş arasındakiler eyalet içi operasyonla sınırlıdır. Kaynak: WV DMV CDL sayfası; FMCSA 49 CFR 391.11."},"94":{"q":"Batı Virginia'nın standart 'Drive for Five' döngüsü uyarınca, bir CDL genellikle hangi süre için geçerlidir?","options":["Beş yıl, sahibinin yaşının beşe bölünebildiği bir yılda doğum gününde sona erer","Dört yıl, sabit bir yenileme tarihinde","Veriliş tarihinden itibaren sekiz yıl","İki yıl, DOT tıbbi kartıyla eşleşerek"],"explanation":"Batı Virginia CDL'leri, başvuru sahibinin yaşının tam olarak beşe bölünebildiği bir yılda doğum gününde sona ermek üzere standart beş yıllık döngüde yenilenir. Kaynak: WV Code 17E-1-12; WV DMV."},"95":{"q":"21 yaşından küçük bir sürücüye verilen bir Batı Virginia CDL hangi noktada sona erer?","options":["Başvuru sahibinin 21 yaşına girdiği yılda doğum gününden 30 gün sonra","Sürücünün 18. doğum gününde","Yaştan bağımsız olarak veriliş tarihinden beş yıl sonra","21 yaşına girer girmez derhal"],"explanation":"21 yaşına ulaşmamış bir kişiye verilen bir Batı Virginia CDL, eyaletler arası/hazmat uygunluğu 21 yaşında değiştiği için, başvuru sahibinin 21 yaşına ulaştığı yılda doğum gününden 30 gün sonra sona erer. Kaynak: WV Code Chapter 17E; WV DMV."},"96":{"q":"Bir Batı Virginia başvuru sahibi, yapmayı beklediği ticari sürüş türünü öz-belgelendirmek için hangi belgeyi kullanır?","options":["WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3)","Federal Form MCSA-5876 tıbbi sertifika","Class D operatör ehliyeti başvurusu","IRP oranlı kayıt formu"],"explanation":"Başvuru sahipleri, operasyon türlerini WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3) üzerinde öz-belgelendirir; Form MCSA-5876 ise ayrı bir tıbbi muayene uzmanı sertifikasıdır. Kaynak: WV DMV CDL formları."},"97":{"q":"Batı Virginia CDL kuralları uyarınca, bir DOT Medical Examiner's Certificate ne kadar süreyle güncel kabul edilir?","options":["İki yıldan eski ise güncel değildir (ve daha kısa bir süre için verilebilir)","Beş yıl geçerlidir","Yalnızca bir yıl geçerlidir","Dosyaya girdikten sonra asla sona ermez"],"explanation":"İki yıldan eski bir Medical Examiner's Certificate güncel değildir; bir muayene uzmanı, sürücünün durumuna bağlı olarak bunu iki yıl için veya daha kısa bir aralık için verebilir. Kaynak: WV DMV CDL sayfası; FMCSA 49 CFR 391.45."},"98":{"q":"Gerekli bir Medical Examiner's Certificate'in süresinin geçmesine izin verilirse, bir Batı Virginia sürücüsünün CDL ayrıcalıklarına genellikle ne olur?","options":["CDL düşürülür, böylece kişi geçerli bir sertifika dosyaya girene kadar ticari sürüş ayrıcalıklarını kaybeder","Bir sonraki beş yıllık yenilemeye kadar hiçbir şey değişmez","Sürücü otomatik olarak excepted bir sürücü olarak yeniden sınıflandırılır","Sürücü bir yıllık otomatik uzatma alır"],"explanation":"Excepted olmayan bir sürücünün tıbbi belgelendirmesinin süresi dolarsa, Batı Virginia CDL'yi düşürerek, güncel bir sertifika sağlanana kadar ticari ayrıcalıkları kaldırır. Kaynak: WV DMV CDL sayfası; FMCSA 49 CFR 383.73 tıbbi belgelendirme hükümleri."},"99":{"q":"Batı Virginia'da, bir CDL'ye başvurmak için temel gerekliliğin parçası olan belge seti hangisidir?","options":["Kimlik/yasal statü kanıtı, West Virginia ikamet kanıtı, Social Security doğrulaması ve tamamlanmış CDL başvurusu","Yalnızca bir pasaport ve bir kredi kartı","Yalnızca bir araç tapusu ve sigorta kanıtı","Bir işveren mektubu ve bir lise diploması"],"explanation":"Batı Virginia CDL başvuru sahipleri, kimlik ve ABD vatandaşlığı veya yasal daimi ikamet kanıtı, West Virginia ikamet kanıtı, Social Security numarası doğrulaması ve tamamlanmış bir CDL başvurusu (ayrıca tıbbi/öz-belgelendirme belgeleri) sunmalıdır. Kaynak: WV DMV CDL sayfası."}},"es":{"0":{"q":"En las carreteras de Virginia Occidental que tienen un ancho mínimo de carril de diez pies (incluidas las rutas designadas e Interestatales), ¿cuál es el ancho exterior máximo permitido de un vehículo o su carga?","options":["8 pies (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies (108 pulgadas)","10 pies (120 pulgadas)"],"explanation":"Según el W.Va. Code 17C-17-2, el ancho exterior total no puede exceder las 96 pulgadas, excepto que un vehículo de 102 pulgadas (8 pies 6 pulgadas) puede circular por carreteras designadas por el U.S. DOT o por cualquier carretera con un ancho mínimo de carril de 10 pies. Fuente: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits."},"1":{"q":"En Virginia Occidental, ¿cuál es la altura legal máxima de un vehículo, incluida su carga, en las carreteras?","options":["12 pies 6 pulgadas","13 pies","13 pies 6 pulgadas","14 pies"],"explanation":"El W.Va. Code 17C-17-4 establece que un vehículo, incluida cualquier carga, no puede exceder una altura de 13 pies 6 pulgadas en ninguna ruta de Virginia Occidental. Fuente: W.Va. Code 17C-17-4; WV DOT Legal Size and Weight Limits."},"2":{"q":"En Virginia Occidental, ¿cuál es el peso bruto máximo sobre un solo eje?","options":["18,000 libras","20,000 libras","22,400 libras","34,000 libras"],"explanation":"Virginia Occidental limita un solo eje a 20,000 libras, en concordancia con el estándar federal. Fuente: W.Va. Code 17C-17-8 / 17C-17-9; WV DOT Legal Size and Weight Limits."},"3":{"q":"En Virginia Occidental, ¿cuál es el peso bruto máximo permitido sobre un grupo de ejes en tándem?","options":["20,000 libras","32,000 libras","34,000 libras","40,000 libras"],"explanation":"Virginia Occidental limita un eje en tándem a 34,000 libras, lo que coincide con el estándar federal de peso por eje. Fuente: W.Va. Code 17C-17-8a / 17C-17-9; WV DOT Legal Size and Weight Limits."},"4":{"q":"¿Cuál es el peso bruto vehicular legal máximo para un vehículo o combinación que circula por la Interestatal (sistema nacional de carreteras interestatales y de defensa) en Virginia Occidental, sin un permiso?","options":["73,280 libras","80,000 libras","88,000 libras","90,000 libras"],"explanation":"El W.Va. Code 17C-17-9 establece que el peso bruto máximo en el sistema nacional de carreteras interestatales y de defensa no debe exceder las 80,000 libras (sujeto a la fórmula del puente). Fuente: W.Va. Code 17C-17-9."},"5":{"q":"En una combinación de tractocamión y semirremolque en Virginia Occidental, ¿cuál es la longitud máxima del semirremolque permitida cuando se cumple la condición de separación entre el pivote de enganche (kingpin) y el eje trasero?","options":["45 pies","48 pies","53 pies","57 pies"],"explanation":"El W.Va. Code 17C-17-4 limita un semirremolque a 48 pies, pero permite hasta 53 pies cuando la separación entre el eje trasero del tractocamión y el eje delantero del semirremolque no es mayor de 37 pies. Fuente: W.Va. Code 17C-17-4."},"6":{"q":"En las carreteras de Virginia Occidental con carriles de menos de 10 pies de ancho (como ciertas rutas de servicio local), ¿cuál es el ancho legal máximo del vehículo?","options":["7 pies 6 pulgadas","8 pies (96 pulgadas)","8 pies 6 pulgadas","9 pies"],"explanation":"La tolerancia de 102 pulgadas (8'6\") solo aplica en rutas designadas o carriles de 10 pies o más de ancho; en caminos con carriles de menos de 10 pies de ancho, el ancho vuelve al límite de 96 pulgadas (8 pies). Fuente: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits."},"7":{"q":"¿Cuál es la longitud total máxima de una combinación de vehículos en las carreteras de Virginia Occidental que NO son Interestatales ni otras rutas designadas?","options":["53 pies","55 pies","65 pies","75 pies"],"explanation":"El W.Va. Code 17C-17-4 limita una combinación de vehículos acoplados entre sí, incluidos los parachoques delantero y trasero, a una longitud total de 55 pies en carreteras no designadas. Fuente: W.Va. Code 17C-17-4."},"8":{"q":"¿Cuál es la longitud total máxima extrema de un solo vehículo automotor (camión rígido) en Virginia Occidental?","options":["35 pies","40 pies","45 pies","48 pies"],"explanation":"El W.Va. Code 17C-17-4 limita un solo vehículo automotor, incluida su carga, a 40 pies de dimensión total extrema (se permiten 45 pies para ciertas casas rodantes y autobuses escolares). Fuente: W.Va. Code 17C-17-4."},"9":{"q":"Conforme a la adopción por parte de Virginia Occidental de las disposiciones federales de peso de puente, dos conjuntos consecutivos de ejes en tándem pueden cargar cada uno 34,000 libras, siempre que la distancia entre el primer y el último eje de los conjuntos consecutivos en tándem sea de al menos cuántos pies?","options":["30 pies","34 pies","36 pies","40 pies"],"explanation":"El W.Va. Code 17C-17-9 permite que dos conjuntos consecutivos de ejes en tándem carguen 34,000 libras cada uno, siempre que la distancia total entre el primer y el último eje de dichos conjuntos consecutivos en tándem sea de 36 pies o más. Fuente: W.Va. Code 17C-17-9."},"10":{"q":"Un permiso de sobrepeso (de un solo viaje) de Virginia Occidental generalmente solo puede emitirse cuando la carga cumple con cuál condición?","options":["La carga es indivisible","El transportista tiene su base en Virginia Occidental","El vehículo tiene seis o más ejes","El viaje ocurre únicamente en Interestatales"],"explanation":"Virginia Occidental emite permisos de sobrepeso solo para cargas indivisibles que no pueden reducirse a los límites legales (la carga marítima en contenedores es una excepción notable). Fuente: WV DOT Division of Highways Hauling Permits / Permit Types."},"11":{"q":"¿Cómo obtiene un transportista un permiso de transporte para cargas sobredimensionadas o con sobrepeso para las rutas estatales de Virginia Occidental?","options":["Solo en persona en un juzgado del condado","A través del sistema en línea de permisos de transporte del WV DOT/Division of Highways","En el cuartel de la Policía Estatal de Virginia Occidental","No se requieren permisos en Virginia Occidental"],"explanation":"Los permisos para cargas sobredimensionadas o con sobrepeso para rutas Interestatales, Turnpike, de EE. UU., de WV y de condado se obtienen a través del sistema en línea de permisos de transporte del WV DOT Division of Highways. Fuente: WV DOT Hauling Permits; wv.gotpermits.com."},"12":{"q":"En las rutas de EE. UU. y estatales de WV (no Interestatales), ¿qué tolerancia de peso aplica Virginia Occidental a sus límites legales de peso por eje y peso bruto?","options":["Sin tolerancia (cero)","5 por ciento","10 por ciento","15 por ciento"],"explanation":"En las rutas de EE. UU. y de WV y en las rutas de servicio local, Virginia Occidental permite una tolerancia del 10 por ciento sobre los límites legales de peso, mientras que las carreteras Interestatales permiten cero tolerancia. Fuente: WV DOT Legal Size and Weight Limits."},"13":{"q":"En las rutas de servicio local de Virginia Occidental (caminos de condado no designados), ¿cuál es el peso bruto vehicular legal máximo antes de que se requiera un permiso?","options":["60,000 libras","65,000 libras","73,280 libras","80,000 libras"],"explanation":"Mientras que las rutas Interestatales y de EE. UU./WV permiten hasta 80,000 libras, las rutas de servicio local de Virginia Occidental tienen un límite legal de peso bruto menor, de 65,000 libras. Fuente: WV DOT Legal Size and Weight Limits."},"14":{"q":"¿Qué peso bruto máximo permitido aplica a un vehículo que circula bajo un permiso ANUAL general de sobrepeso y sobredimensión de Virginia Occidental en rutas DISTINTAS a la Interestatal?","options":["80,000 libras","90,000 libras","110,000 libras","120,000 libras"],"explanation":"Bajo un permiso anual (general) de sobrepeso/sobredimensión de Virginia Occidental, el peso bruto máximo es de 90,000 libras en rutas no Interestatales (110,000 libras en la Interestatal). Fuente: WV DOT Permit Types (Annual/Blanket Permits)."},"15":{"q":"Bajo un permiso anual (general) de sobrepeso de Virginia Occidental, ¿cuál es el peso máximo permitido sobre un eje en tándem?","options":["34,000 libras","40,000 libras","45,000 libras","50,000 libras"],"explanation":"Los permisos generales de sobrepeso de Virginia Occidental permiten hasta 28,000 libras sobre un solo eje, 45,000 libras sobre un eje en tándem y 50,000 libras sobre un eje en trídem. Fuente: WV DOT Permit Types (Annual/Blanket Permits)."},"16":{"q":"En un \"camino de transporte de recursos de carbón\" designado de Virginia Occidental, un vehículo que transporta carbón con permiso puede operar hasta un peso bruto máximo de aproximadamente qué cifra?","options":["80,000 libras","90,000 libras","120,000 libras","150,000 libras"],"explanation":"Conforme al W.Va. Code Chapter 17C, Article 17A, los vehículos que transportan carbón en caminos designados de transporte de recursos de carbón pueden operar con un peso bruto mayor de hasta 120,000 libras (con una variación del 5 por ciento), excediendo los límites del 17C-17-9. Fuente: W.Va. Code 17C-17A; WV PSC coal resource transportation permitting."},"17":{"q":"¿Cuál es el peso máximo permitido sobre un solo eje bajo un permiso anual (general) de sobrepeso de Virginia Occidental?","options":["20,000 libras","24,000 libras","28,000 libras","34,000 libras"],"explanation":"Un permiso general de sobrepeso de Virginia Occidental permite hasta 28,000 libras sobre un solo eje (frente al límite legal de 20,000 libras). Fuente: WV DOT Permit Types (Annual/Blanket Permits)."},"18":{"q":"Para un permiso de un solo viaje por sobredimensión de Virginia Occidental, ¿durante qué horas generalmente NO es válido el movimiento de carga sobredimensionada?","options":["De la puesta a la salida del sol (horario nocturno)","Del mediodía a las 2 p.m. en días laborables","En cualquier momento los lunes","Solo durante la hora pico de la mañana"],"explanation":"Un permiso de sobredimensión de Virginia Occidental generalmente no es válido durante el horario nocturno, desde la puesta hasta la salida del sol, y no se permite circular en días festivos. Fuente: WV DOT Hauling Permits / Permit conditions."},"19":{"q":"Un camión rígido de una sola unidad de Virginia Occidental con un eje de dirección y un grupo de ejes en tándem generalmente está limitado a qué peso bruto vehicular máximo antes de aplicar la tolerancia permitida?","options":["48,000 libras","54,000 libras","60,000 libras","66,000 libras"],"explanation":"Un camión de una sola unidad de Virginia Occidental que tiene un eje de dirección y dos ejes en tándem está limitado a un peso bruto máximo de 60,000 libras (antes de la tolerancia del 10 por ciento en rutas no Interestatales). Fuente: WV DOT Legal Size and Weight Limits."},"20":{"q":"En Virginia Occidental, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, donde el vehículo remolcado tiene un GVWR de más de 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Virginia Occidental adopta la clasificación federal: una CDL Clase A cubre cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que la unidad remolcada tenga un GVWR que exceda las 10,000 lbs. Fuente: WV DMV Commercial Driver's License page y WV CDL Manual."},"21":{"q":"Según las normas de Virginia Occidental, un solo vehículo con un GVWR de 26,001 libras o más (o tal vehículo remolcando una unidad de no más de 10,000 libras) requiere qué clase de CDL?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"Una CDL Clase B en Virginia Occidental autoriza un solo vehículo con un GVWR de 26,001 lbs o más, incluyendo el remolque de una unidad con un GVWR de 10,000 lbs o menos. Fuente: WV DMV CDL page y WV CDL Manual."},"22":{"q":"Un conductor de Virginia Occidental opera un vehículo de menos de 26,001 libras que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que se usa para transportar materiales peligrosos con rótulos (placardados). ¿Qué clase de CDL aplica?","options":["Clase A","Clase B","Clase C","No se requiere CDL"],"explanation":"Una CDL Clase C cubre vehículos que no cumplen con los umbrales de peso de la Clase A o B pero que están diseñados para transportar 16 o más pasajeros (incluido el conductor) o transportar materiales peligrosos que requieren rótulos (placards). Fuente: WV DMV CDL page y WV CDL Manual."},"23":{"q":"¿Qué código de aval en una CDL de Virginia Occidental autoriza el transporte de materiales peligrosos que requieren rótulos (placards)?","options":["N","H","T","X"],"explanation":"El aval 'H' autoriza el transporte de materiales peligrosos placardados. El código 'X' es un aval combinado de Tanque más HazMat. Fuente: WV CDL Manual, Endorsements section."},"24":{"q":"En una CDL de Virginia Occidental, ¿qué aval se requiere para operar un vehículo cisterna que transporta materiales líquidos o gaseosos en un tanque montado permanentemente?","options":["T (Dobles/Triples)","N (Tanque)","P (Pasajeros)","H (HazMat)"],"explanation":"El aval 'N' (Tanque) se requiere para vehículos cisterna que transportan líquidos o gases a granel. El aval 'T' es para remolques dobles y triples, una autorización aparte. Fuente: WV CDL Manual, Endorsements section."},"25":{"q":"Un titular de una CDL de Virginia Occidental desea jalar remolques dobles o triples. ¿Qué aval debe agregarse?","options":["N","S","T","P"],"explanation":"El aval 'T' autoriza la operación de combinaciones de remolques dobles y triples y requiere aprobar un examen de conocimientos. Fuente: WV CDL Manual, Endorsements section."},"26":{"q":"Para transportar pasajeros con fines comerciales en un autobús en Virginia Occidental (por ejemplo, un autobús de tránsito o un autocar), ¿qué aval de CDL se requiere?","options":["Aval S","Aval P","Aval N","Aval H"],"explanation":"El aval 'P' (Pasajeros) se requiere para operar un vehículo diseñado para transportar 16 o más pasajeros y exige tanto un examen de conocimientos como un examen práctico de manejo en un vehículo representativo. Fuente: WV CDL Manual, Endorsements section."},"27":{"q":"¿Qué aval requiere Virginia Occidental para que un conductor opere un autobús escolar, además del aval de Pasajeros (P)?","options":["Aval S","Aval T","Aval N","Aval X"],"explanation":"El aval 'S' (Autobús Escolar) se requiere para conducir un autobús escolar y se obtiene además del aval 'P'; exige un examen de conocimientos y un examen práctico de manejo en un autobús escolar. Fuente: WV CDL Manual, Endorsements section."},"28":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Virginia Occidental para conducir DENTRO DEL ESTADO (operar únicamente dentro de Virginia Occidental)?","options":["16 años","18 años","21 años","25 años"],"explanation":"Un solicitante debe tener al menos 18 años para obtener una CDL válida para el comercio intraestatal (dentro de Virginia Occidental). Fuente: WV CDL Manual / WV DMV CDL requirements."},"29":{"q":"¿Cuál es la edad mínima requerida para que se emita una CDL de Virginia Occidental para conducir ENTRE ESTADOS (a través de las líneas estatales)?","options":["18 años","19 años","21 años","23 años"],"explanation":"Las normas federales adoptadas por Virginia Occidental exigen que un conductor tenga al menos 21 años para operar un vehículo automotor comercial en el comercio interestatal o para transportar materiales peligrosos. Fuente: WV CDL Manual / 49 CFR 391.11 según lo aplica el WV DMV."},"30":{"q":"Después de obtener un Permiso de Aprendiz Comercial (CLP) de Virginia Occidental, ¿cuánto tiempo debe conservarlo el solicitante antes de ser elegible para presentar el examen práctico de manejo de la CDL?","options":["Un mínimo de 14 días","Un mínimo de 30 días","Un mínimo de 7 días","Un mínimo de 60 días"],"explanation":"La ley federal adoptada por Virginia Occidental exige que el solicitante conserve el CLP durante al menos 14 días antes de presentar el examen práctico (de manejo). Fuente: WV DMV CDL page; 49 CFR 383.25."},"31":{"q":"En cuanto a la renovación, ¿qué afirmación describe mejor el Permiso de Aprendiz Comercial (CLP) de Virginia Occidental?","options":["No es renovable y su validez no puede exceder un año","Puede renovarse un número ilimitado de veces","Es válido por cinco años, como una licencia regular","Nunca vence una vez emitido"],"explanation":"La página de CDL del WV DMV establece que el Permiso de Aprendiz Comercial no puede exceder un año de validez y no es renovable. Fuente: WV DMV Commercial Driver's License page."},"32":{"q":"Al conducir un vehículo automotor comercial con un CLP de Virginia Occidental, el titular del permiso debe estar acompañado por cuál de los siguientes?","options":["El titular de una CDL válida para ese tipo de vehículo, sentado al lado del conductor","Cualquier conductor con licencia mayor de 21 años en cualquier asiento del vehículo","Únicamente un examinador del DMV","Nadie; el CLP permite conducir en solitario"],"explanation":"Un titular de un CLP puede operar un CMV solo cuando está acompañado por el titular de una CDL válida para esa clase/tipo de vehículo, quien ocupa el asiento junto al titular del permiso. Fuente: WV DMV CDL page; 49 CFR 383.25."},"33":{"q":"¿Cuál es la calificación mínima aprobatoria en los exámenes de conocimientos (escritos) de la CDL de Virginia Occidental?","options":["70%","75%","80%","90%"],"explanation":"Virginia Occidental exige una calificación mínima del 80% para aprobar cada examen de conocimientos de la CDL (el examen de HazMat debe presentarse en forma escrita). Fuente: WV DMV CDL testing requirements."},"34":{"q":"Antes de que Virginia Occidental pueda emitir un aval de HazMat (H), ¿qué evaluación federal debe aprobar el solicitante?","options":["Una evaluación de amenaza a la seguridad de la Transportation Security Administration (TSA)","Una revisión del historial crediticio","Una verificación de antecedentes penales solo estatal sin huellas digitales","Una evaluación médica únicamente de la vista"],"explanation":"La ley federal adoptada por Virginia Occidental exige que los solicitantes de un aval de HazMat aprueben una evaluación de amenaza a la seguridad de la TSA, que incluye la toma de huellas digitales y una verificación de antecedentes, antes de que se emita o renueve el aval. Fuente: WV CDL Manual; 49 CFR 1572 (TSA)."},"35":{"q":"¿Cuál es la edad mínima para obtener un aval de HazMat (H) en una CDL de Virginia Occidental?","options":["18 años","21 años","25 años","19 años"],"explanation":"Debido a que el transporte de materiales peligrosos requiere el estatus de calificación interestatal según las normas federales, un solicitante debe tener al menos 21 años para obtener el aval de HazMat. Fuente: WV CDL Manual; TSA/FMCSA HazMat requirements."},"36":{"q":"Los solicitantes de CDL por primera vez en Virginia Occidental deben completar la Capacitación para Conductores de Nivel Inicial (ELDT) a través de un proveedor que esté:","options":["Inscrito en el FMCSA Training Provider Registry (TPR)","Aprobado únicamente por la Policía Estatal de Virginia Occidental","Cualquier escuela de manejo privada que elija el solicitante","Certificado por la TSA"],"explanation":"La ELDT debe completarse con un proveedor inscrito en el FMCSA Training Provider Registry (TPR). Aplica a quienes obtienen una CDL Clase A o B por primera vez, ascienden de B a A, o buscan por primera vez un aval P, S o H (en o después del 7 de febrero de 2022). Fuente: FMCSA ELDT rule; WV DMV CDL page."},"37":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación médica entre las que debe elegir un solicitante de CDL de Virginia Occidental?","options":["No Exento Interestatal (NI)","Recreativo Interestatal (RI)","Comercial Exento (CE)","Local Limitado (LL)"],"explanation":"Las cuatro categorías de autocertificación son No Exento Interestatal (NI), Exento Interestatal (EI), No Exento Intraestatal (NA) y Exento Intraestatal (EA). Los conductores en categorías no exentas deben tener un certificado válido de examinador médico del DOT. Fuente: WV DMV CDL self-certification; FMCSA."},"38":{"q":"Un conductor de CDL de Virginia Occidental que se certifica como 'No Exento Interestatal (NI)' debe presentar cuál documento?","options":["Un certificado válido de examinador médico (tarjeta médica del DOT)","Únicamente un comprobante de seguro de vehículo automotor","Una carta de exención del empleador firmada","Nada adicional más allá de la solicitud"],"explanation":"Los conductores que se certifican en una categoría no exenta (NI o NA) deben obtener y presentar un certificado válido de examinador médico de un examinador inscrito en el FMCSA National Registry; las categorías exentas (EI, EA) no requieren una tarjeta médica del DOT. Fuente: WV DMV CDL self-certification; FMCSA."},"39":{"q":"Al solicitar una CDL o un CLP de Virginia Occidental, ¿cuántos comprobantes de residencia en Virginia Occidental exige el DMV?","options":["Un comprobante de residencia","Dos comprobantes de residencia","Tres comprobantes de residencia","No se requiere comprobante de residencia"],"explanation":"Virginia Occidental requiere un comprobante de identidad/presencia legal, un comprobante del número de Seguro Social y dos comprobantes de residencia en Virginia Occidental para una solicitud de CDL/CLP. Fuente: WV DMV acceptable documents / driver license requirements."},"40":{"q":"Según la ley de Virginia Occidental, ¿con qué concentración de alcohol en sangre (BAC) se considera que un conductor está operando un vehículo automotor comercial (CMV) con demasiado alcohol, lo que activa la descalificación?","options":["0.08% o más","0.02% o más","0.10% o más","0.04% o más"],"explanation":"Virginia Occidental establece el límite de alcohol para CMV en 0.04% (\"cuatro centésimas de uno por ciento o más, en peso\"), la mitad del límite de 0.08% para vehículos personales. Fuente: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)(2)."},"41":{"q":"En Virginia Occidental, un conductor de CMV en quien se detecte cualquier cantidad de alcohol por debajo de 0.04% debe ser:","options":["Descalificado de inmediato por 1 año","Puesto fuera de servicio durante 24 horas","Multado con $2,500 sin período fuera de servicio","Amonestado únicamente, sin sanción"],"explanation":"Un conductor de CMV con cualquier cantidad detectable y medible de alcohol por debajo de 0.04% es puesto fuera de servicio durante 24 horas, aunque esté por debajo del umbral descalificante de 0.04%. Fuente: WV CDL Manual Section 1.3 e Implied Consent provisions; WV Code 17E-1-13."},"42":{"q":"¿Cuál es el período de descalificación en Virginia Occidental para la PRIMERA infracción grave de un conductor de CMV, como conducir bajo los efectos (DUI) o un BAC de 0.04%, cuando NO se transportan materiales peligrosos placardados?","options":["60 días","3 años","1 año","6 meses"],"explanation":"Una primera infracción grave (DUI, BAC de 0.04%, negativa a la prueba, abandono del lugar del accidente, uso de un vehículo en un delito grave, etc.) resulta en una descalificación de la CDL de 1 año en Virginia Occidental. Fuente: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)."},"43":{"q":"Si un conductor de CMV de Virginia Occidental comete una primera infracción grave MIENTRAS transporta materiales peligrosos que requieren rótulos (placards), el período de descalificación es:","options":["3 años","1 año","5 años","180 días"],"explanation":"Una primera infracción grave cometida mientras se opera un CMV que transporta materiales peligrosos placardados (según 49 CFR Part 172, Subpart F) conlleva una descalificación agravada de 3 años en lugar de 1 año. Fuente: WV CDL Manual; WV Code 17E-1-13(b)(1)(C)."},"44":{"q":"¿Cuál es el período de descalificación en Virginia Occidental para una SEGUNDA infracción grave (en un incidente separado)?","options":["10 años","De por vida","3 años","5 años"],"explanation":"Una segunda infracción grave en un incidente separado resulta en una descalificación de la CDL de por vida en Virginia Occidental. El DMV puede permitir la reinstalación después de un período mínimo bajo ciertas condiciones, pero se impone como una descalificación de por vida. Fuente: WV CDL Manual; WV Code 17E-1-13(b)(1)(D)."},"45":{"q":"En Virginia Occidental, negarse a someterse a una prueba química (secundaria) designada mientras se opera un CMV resulta en qué descalificación por una primera negativa?","options":["60 días","1 año","90 días","30 días"],"explanation":"Una negativa a la prueba se trata como una infracción grave: una primera negativa descalifica al conductor por 1 año (3 años si transporta materiales peligrosos placardados), y una segunda resulta en una descalificación de por vida. Fuente: WV CDL Manual; WV Code 17E-1-13(b)(3)."},"46":{"q":"Según la Ley de Consentimiento Implícito de Virginia Occidental, al aceptar el privilegio de conducir en el estado, se considera que un conductor ha consentido a:","options":["Un registro del vehículo en cualquier parada de tráfico","Un curso obligatorio de educación sobre el DUI","Inspecciones aleatorias con perros antidrogas al borde de la carretera","Una prueba química para determinar el contenido de alcohol en su cuerpo"],"explanation":"La Ley de Consentimiento Implícito de Virginia Occidental significa que toda persona que conduce en el estado ha consentido a tomar la prueba química designada para detectar el contenido de alcohol. La negativa suspende los privilegios de conducir por al menos 1 año, hasta de por vida. Fuente: WV CDL Manual, Implied Consent Law; WV Code 17C-5-4."},"47":{"q":"Según la Ley de Consentimiento Implícito de Virginia Occidental, negarse a una prueba química suspende el privilegio de un conductor para operar un vehículo automotor por qué período mínimo?","options":["Al menos 90 días","Al menos 30 días","Al menos 1 año","Al menos 6 meses"],"explanation":"Negarse a la prueba química designada bajo la Ley de Consentimiento Implícito de Virginia Occidental suspende el privilegio de operar un vehículo automotor por un período de al menos 1 año, y hasta de por vida. Fuente: WV CDL Manual, Implied Consent Law."},"48":{"q":"¿Cuántas infracciones de tráfico graves dentro de un período de 3 años activan una descalificación de 60 días en Virginia Occidental?","options":["1 (la primera infracción)","3 (la tercera dentro de 3 años)","2 (la segunda dentro de 3 años)","4 (la cuarta dentro de 3 años)"],"explanation":"Una segunda infracción de tráfico grave dentro de un período de 3 años resulta en una descalificación de 60 días. La primera infracción grave por sí sola no descalifica. Fuente: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"49":{"q":"¿Cuál es el período de descalificación en Virginia Occidental para una TERCERA infracción de tráfico grave dentro de un período de 3 años?","options":["120 días","60 días","1 año","90 días"],"explanation":"Una tercera o posterior infracción de tráfico grave dentro de un período de 3 años resulta en una descalificación de 120 días. Fuente: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"50":{"q":"¿Cuál de las siguientes se clasifica como una \"infracción de tráfico grave\" para efectos de descalificación de la CDL de Virginia Occidental?","options":["Conducir 5 mph por encima del límite señalizado","Exceso de velocidad (15 mph o más por encima del límite señalizado)","Una infracción de estacionamiento","Una calcomanía de registro vencida"],"explanation":"Las infracciones de tráfico graves incluyen el exceso de velocidad (15 mph o más por encima del límite señalizado), conducción imprudente, cambios de carril indebidos o erráticos, seguir demasiado de cerca y enviar mensajes de texto mientras se conduce. Las infracciones de estacionamiento están excluidas. Fuente: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)."},"51":{"q":"En Virginia Occidental, ¿cuál es el período de descalificación para una PRIMERA condena por violar una orden de fuera de servicio mientras se opera un CMV que transporta carga no peligrosa?","options":["90 días","60 días","180 días","1 año"],"explanation":"Una primera condena por violar una orden de fuera de servicio mientras se opera un CMV resulta en una descalificación de 180 días en Virginia Occidental. Fuente: WV CDL Manual; WV Code 17E-1-13(e)(1)(A)."},"52":{"q":"¿Cuál es el período de descalificación para una SEGUNDA violación de una orden de fuera de servicio dentro de un período de 10 años mientras se transportan materiales no peligrosos en Virginia Occidental?","options":["180 días","2 años","3 años","1 año"],"explanation":"Una segunda violación de una orden de fuera de servicio en un incidente separado dentro de 10 años (no peligroso) resulta en una descalificación de 2 años. Una tercera o posterior dentro de 10 años resulta en 3 años. Fuente: WV CDL Manual; WV Code 17E-1-13(e)(1)(B)."},"53":{"q":"En Virginia Occidental, una SEGUNDA violación de una orden de fuera de servicio dentro de 10 años mientras se transportan materiales peligrosos placardados O se opera un vehículo diseñado para transportar 16 o más pasajeros resulta en qué descalificación?","options":["2 años","180 días","1 año","3 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años mientras se transportan materiales peligrosos placardados o se transportan 16+ pasajeros conlleva una descalificación agravada de 3 años (frente a 2 años para carga no peligrosa). Fuente: WV CDL Manual; WV Code 17E-1-13(e)(2)(B)."},"54":{"q":"¿Cuál es el período de descalificación en Virginia Occidental para una PRIMERA infracción en un cruce a nivel de ferrocarril y carretera mientras se opera un CMV?","options":["30 días","120 días","60 días","180 días"],"explanation":"Una primera infracción en un cruce a nivel de ferrocarril y carretera mientras se opera un CMV resulta en una descalificación de 60 días en Virginia Occidental. Fuente: WV CDL Manual; WV Code 17E-1-13(d)."},"55":{"q":"En Virginia Occidental, los períodos de descalificación por infracciones en cruces a nivel de ferrocarril y carretera aumentan de 60 días por una primera infracción a qué para una SEGUNDA y TERCERA infracción dentro de 3 años?","options":["120 días para la segunda; 1 año para la tercera","90 días para la segunda; 180 días para la tercera","60 días para la segunda; 120 días para la tercera","180 días para la segunda; 2 años para la tercera"],"explanation":"Las infracciones en cruces de ferrocarril descalifican a un conductor por 60 días (primera), 120 días (segunda dentro de 3 años) y 1 año (tercera o posterior dentro de 3 años). Fuente: WV CDL Manual; WV Code 17E-1-13(d)."},"56":{"q":"Según las normas de Virginia Occidental y federales adoptadas por el estado, la CDL de un conductor de CMV se descalifica después de cuántas condenas por enviar mensajes de texto mientras conduce un CMV?","options":["1 condena (la primera infracción)","4 o más condenas dentro de 3 años","3 o más condenas dentro de 5 años","2 o más condenas dentro de 3 años"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV es una infracción grave: la CDL se descalifica por 60 días después de una segunda condena dentro de 3 años y 120 días por tres o más dentro de 3 años. Una primera condena no descalifica pero conlleva una sanción civil. Fuente: WV CDL Manual Section 2.9.5; WV Code 17E-1-13(c)(9)."},"57":{"q":"¿Cuál es la sanción civil federal máxima (adoptada en Virginia Occidental) para un conductor de CMV que envía mensajes de texto o usa un teléfono móvil de mano mientras conduce?","options":["Hasta $2,750","Hasta $500","Hasta $11,000","Hasta $5,000"],"explanation":"Cada infracción por mensajes de texto/teléfono de mano somete al conductor de CMV a una sanción civil de hasta $2,750. (Los empleadores que lo permitan o exijan pueden ser multados con hasta $11,000). Fuente: WV CDL Manual Sections 2.9.4 y 2.9.5."},"58":{"q":"Un titular de una CDL de Virginia Occidental cuya licencia de vehículo personal está suspendida por una infracción relacionada con alcohol, sustancias controladas o un delito grave pierde los privilegios de la CDL por cuánto tiempo en una primera infracción?","options":["1 año","60 días","90 días","6 meses"],"explanation":"Si los privilegios de vehículo personal de un titular de CDL son revocados, cancelados o suspendidos por infracciones relacionadas con alcohol, sustancias controladas o delitos graves, la CDL se pierde por 1 año; una segunda infracción de este tipo (vehículo personal o CMV) resulta en una pérdida de por vida. Fuente: WV CDL Manual Section 1.3; WV Code 17E-1-13(b)."},"59":{"q":"Bajo el sistema de puntos para conductores de Virginia Occidental, alcanzar cuántos puntos resulta en la suspensión de los privilegios de conducir?","options":["6 o más puntos","20 o más puntos","8 o más puntos","12 o más puntos"],"explanation":"El sistema de puntos del WV DMV suspende los privilegios de conducir al alcanzar 12 o más puntos. Por ejemplo, conducir a 20 mph o más por encima del límite son 6 puntos, y la conducción imprudente son 6 puntos. Fuente: WV CDL Manual / WV Driver's Licensing Handbook, Point System."},"60":{"q":"En una carretera NO DIVIDIDA de Virginia Occidental, cuando no puede cambiar de carril de forma segura para alejarse de un vehículo de emergencia o de servicio detenido que muestra luces intermitentes, ¿cuál es la velocidad máxima a la que puede pasarlo según la ley estatal Move Over (cambio de carril)?","options":["15 mph","25 mph","10 mph","20 mph"],"explanation":"El Código de Virginia Occidental 17C-14-9a (ley Move Over) exige que el conductor que no pueda cambiar de carril reduzca la velocidad a un nivel seguro que no exceda las 15 mph en cualquier carretera o calle no dividida al pasar junto a un vehículo autorizado de emergencia o de servicio que esté detenido. Fuente: WV Code 17C-14-9a."},"61":{"q":"En una carretera DIVIDIDA de Virginia Occidental donde no puede pasarse de forma segura a un carril no adyacente, ¿cuál es la velocidad máxima a la que puede pasar junto a un vehículo de emergencia detenido que muestra luces de advertencia?","options":["15 mph","35 mph","25 mph","20 mph"],"explanation":"Según el WV Code 17C-14-9a, el conductor que no pueda cambiar de carril debe reducir la velocidad a un nivel seguro que no exceda las 25 mph en cualquier carretera dividida al pasar junto a un vehículo de emergencia o de servicio que esté detenido. Fuente: WV Code 17C-14-9a."},"62":{"q":"Según el Manual CDL de Virginia Occidental, un vehículo con carteles (placards) de HazMat, una carga de cloro o un tanque de carga deben detenerse a qué distancia del riel más cercano en un cruce ferroviario?","options":["Entre 10 y 25 pies","Entre 15 y 50 pies","Entre 5 y 15 pies","Entre 25 y 75 pies"],"explanation":"El Manual CDL de WV (Sección 9.6.12) establece que un vehículo que lleva carteles (placards), que transporta cualquier cantidad de cloro o que tiene tanques de carga usados para materiales peligrosos debe detenerse entre 15 y 50 pies antes del riel más cercano. Fuente: WV CDL Manual, Sec. 9.6.12."},"63":{"q":"Un conductor de autobús en Virginia Occidental debe detener el autobús a qué distancia antes de un cruce ferroviario?","options":["Entre 20 y 40 pies","Al menos 50 pies","Entre 10 y 30 pies","Entre 15 y 50 pies"],"explanation":"El Manual CDL de WV (Sección 4.3.5) indica a los conductores de autobús que detengan el autobús entre 15 y 50 pies antes de los cruces ferroviarios, y que luego escuchen y miren en ambas direcciones por si vienen trenes. Fuente: WV CDL Manual, Sec. 4.3.5."},"64":{"q":"¿Cuál es el límite máximo de velocidad señalizado en una autopista interestatal de Virginia Occidental, a menos que se indique lo contrario?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"La tabla de velocidades designadas del Manual CDL de WV indica que las autopistas interestatales tienen 70 mph (a menos que se señalice lo contrario). Fuente: WV CDL Manual, tabla de velocidades designadas; WV Code 17C-6-1."},"65":{"q":"A menos que se indique lo contrario, ¿cuál es el límite máximo de velocidad en una zona comercial o residencial de Virginia Occidental?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"Virginia Occidental establece un máximo de 25 mph en cualquier distrito comercial o residencial, como se muestra en la tabla de velocidades designadas del Manual CDL de WV. Fuente: WV Code 17C-6-1; WV CDL Manual."},"66":{"q":"¿Cuál es el límite máximo de velocidad en una zona escolar de Virginia Occidental cuando hay niños presentes?","options":["20 mph","25 mph","15 mph","10 mph"],"explanation":"El WV Code 17C-6-1 establece 15 mph en una zona escolar durante el recreo o mientras los niños van a la escuela o salen de ella; el Manual CDL de WV indica la misma cifra. Fuente: WV Code 17C-6-1; WV CDL Manual."},"67":{"q":"En una carretera rural abierta de Virginia Occidental (que no sea una interestatal ni una vía de acceso controlado), ¿cuál es el límite máximo de velocidad predeterminado, a menos que se indique lo contrario?","options":["60 mph","65 mph","50 mph","55 mph"],"explanation":"La tabla de velocidades designadas del Manual CDL de WV indica que las carreteras abiertas tienen 55 mph a menos que se señalice lo contrario, en concordancia con el WV Code 17C-6-1. Fuente: WV Code 17C-6-1; WV CDL Manual."},"68":{"q":"Según el Código de Virginia Occidental 17C-12-7, cuando se cruza o adelanta a un autobús escolar detenido con sus luces de señal de advertencia intermitentes para subir o bajar niños, usted debe:","options":["Detenerse antes de llegar al autobús y no continuar hasta que las luces se apaguen o el conductor le indique","Reducir la velocidad a 10 mph y pasar con precaución","Detenerse solo si viaja en la misma dirección que el autobús","Pasarse al carril más alejado y continuar a velocidad reducida"],"explanation":"El WV Code 17C-12-7 exige que el conductor que se cruce o adelante desde cualquier dirección a un autobús escolar con luces de advertencia intermitentes se detenga antes de llegar al autobús y no continúe hasta que el autobús avance, las luces se apaguen o el conductor del autobús le indique. Fuente: WV Code 17C-12-7."},"69":{"q":"Según la ley de autobuses escolares de Virginia Occidental, ¿en qué tipo de vía un conductor NO tiene que detenerse por un autobús escolar que se encuentra en una calzada distinta donde no se permite cruzar a los peatones?","options":["Cualquier carretera de cuatro carriles","Cualquier carretera con un carril central de giro","Una autopista de acceso controlado","Una carretera de dos carriles con una mediana pintada"],"explanation":"El WV Code 17C-12-7 dispone que un conductor en una autopista de acceso controlado no necesita detenerse por un autobús escolar que esté en una calzada distinta, o adyacente a la autopista, donde no se permite cruzar a los peatones. Una simple línea pintada o un carril central NO activa la excepción. Fuente: WV Code 17C-12-7."},"70":{"q":"Después de detener un vehículo comercial en el arcén de una carretera de Virginia Occidental, ¿dentro de cuántos minutos debe colocar sus dispositivos de advertencia de emergencia?","options":["5 minutos","10 minutos","15 minutos","30 minutos"],"explanation":"El Manual CDL de WV establece que si debe detenerse en una carretera o en el arcén, debe colocar sus dispositivos de advertencia de emergencia dentro de los diez minutos. Fuente: WV CDL Manual, Sec. 2.5."},"71":{"q":"Cuando se detiene en una carretera de UN SOLO SENTIDO o DIVIDIDA de Virginia Occidental, ¿dónde deben colocarse los tres triángulos reflectantes?","options":["A 10 pies, 100 pies y 100 pies por delante y por detrás","A 50 pies, 100 pies y 500 pies por detrás","A 10 pies, 50 pies y 150 pies hacia el tráfico que se aproxima","A 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima"],"explanation":"El Manual CDL de WV indica que en una carretera de un solo sentido o dividida los dispositivos de advertencia se coloquen a 10 pies, 100 pies y 200 pies del vehículo hacia el tráfico que se aproxima. Fuente: WV CDL Manual, Sec. 2.5."},"72":{"q":"Si un conductor de Virginia Occidental no tiene triángulos reflectantes, ¿qué dispositivos de advertencia acepta el Manual CDL como sustituto para advertir de un vehículo estacionado?","options":["Al menos 6 bengalas (fusees) o 3 antorchas de combustible líquido","Al menos 2 bengalas (fusees) o 1 antorcha de combustible líquido","Una sola baliza giratoria ámbar","Al menos 4 conos viales"],"explanation":"El Manual CDL de WV indica como dispositivos de advertencia para vehículos estacionados tres triángulos reflectantes o al menos 6 bengalas (fusees) o 3 antorchas de combustible líquido. Fuente: WV CDL Manual, sección de inspección del vehículo/equipo de emergencia."},"73":{"q":"¿Por qué Virginia Occidental prohíbe el uso de antorchas o dispositivos de advertencia con llama abierta cerca de ciertas cargas con carteles (placards)?","options":["Son demasiado tenues para verse de noche","Solo son legales en carreteras divididas","Pueden encender carga inflamable como líquidos inflamables de Clase 3","Descargan la batería del vehículo"],"explanation":"La regla 'No Flares!' (¡Sin antorchas!) del Manual CDL de WV indica usar triángulos reflectantes o luces eléctricas rojas, no antorchas ni fusibles ardiendo, alrededor de vehículos que transportan materiales inflamables como líquidos inflamables de Clase 3. Fuente: WV CDL Manual, Sec. 9.6.4."},"74":{"q":"Según la regla de uso de carriles de Virginia Occidental, ¿por dónde deben circular normalmente todos los conductores, incluido el tráfico de camiones?","options":["Por el carril central para mantener libre el carril derecho para incorporaciones","Por el carril del extremo derecho, excepto al adelantar, girar o evitar obstrucciones","Por el carril que tenga menos tráfico","Por el carril izquierdo para dejar el carril derecho a los vehículos más lentos"],"explanation":"Virginia Occidental (Capítulo 17C, Artículo 7) exige que los conductores, incluidos los camiones, circulen por defecto por el carril del extremo derecho, excepto al rebasar/adelantar, cuando el carril derecho esté cerrado, cuando se circule por debajo de la velocidad normal del tráfico o cuando se prepare un giro. Fuente: WV Code Ch. 17C, Art. 7."},"75":{"q":"En una carretera de TRES carriles de Virginia Occidental, ¿cómo puede un camión usar los carriles?","options":["Puede usar libremente cualquiera de los tres carriles","Debe usar solo el carril del medio","Puede usar los dos carriles de la izquierda y adelantar por el carril derecho","Debe permanecer en el carril derecho, pero puede usar el carril del medio para adelantar"],"explanation":"Según las reglas de carriles de Virginia Occidental, los camiones en una calzada de tres carriles están restringidos al carril derecho, pero pueden pasar al carril del medio para adelantar. Fuente: WV Code Ch. 17C, Art. 7."},"76":{"q":"En una carretera de CUATRO carriles de Virginia Occidental, ¿qué carriles puede usar un tractocamión que arrastra un semirremolque?","options":["Los dos carriles de la derecha","Solo el carril del extremo derecho","Cualquier carril excepto el del extremo izquierdo","Los dos carriles de la izquierda"],"explanation":"Virginia Occidental permite que los tractocamiones que arrastran semirremolques circulen por los dos carriles de la derecha en una carretera de cuatro carriles. Fuente: WV Code Ch. 17C, Art. 7."},"77":{"q":"¿Cuál es el ancho máximo legal del vehículo en Virginia Occidental (sin permiso) en rutas Interstate, US y WV con carriles de 10 pies o más de ancho?","options":["8 pies 0 pulgadas","9 pies 0 pulgadas","8 pies 6 pulgadas","10 pies 0 pulgadas"],"explanation":"Los límites legales de tamaño de la WV Division of Highways fijan el ancho máximo en 8 pies 6 pulgadas en rutas Interstate, US, WV y locales con carriles de 10 pies o más (8 pies en rutas locales más estrechas). Fuente: WVDOT/Division of Highways Legal Size and Weight Limits."},"78":{"q":"¿Cuál es el peso bruto máximo legal (sin permiso) para un vehículo en una autopista INTERESTATAL de Virginia Occidental?","options":["65,000 libras","80,000 libras","73,280 libras","90,000 libras"],"explanation":"El límite legal de peso bruto de Virginia Occidental en las autopistas interestatales es de 80,000 libras (tolerancia cero); las rutas de servicio local están limitadas a 65,000 libras. Fuente: WVDOT Legal Size and Weight Limits."},"79":{"q":"¿Qué afirmación sobre la West Virginia Turnpike (I-77) es correcta para los conductores comerciales?","options":["Los tractocamiones están totalmente prohibidos en la Turnpike","Es una interestatal gratuita sin plazas de peaje","Los camiones solo pueden usarla entre el amanecer y el atardecer","Es una carretera de montaña con peaje donde los camiones pagan peajes en las plazas de la vía principal"],"explanation":"La West Virginia Turnpike lleva la I-77 sobre pendientes montañosas pronunciadas (de hasta aproximadamente 5%) y es una carretera de peaje con plazas de peaje en la vía principal (Ghent, Pax, Chelyan) donde los camiones pagan peajes según su tamaño/ejes; también cuenta con rampas de escape para camiones. Fuente: páginas de la WV Parkways Authority / WVDOT Turnpike."},"80":{"q":"¿Qué agencia estatal emite las Licencias de Conducir Comerciales (CDL) en Virginia Occidental?","options":["La West Virginia Division of Motor Vehicles (DMV)","La Policía Estatal de Virginia Occidental","La West Virginia Public Service Commission","La West Virginia Division of Highways"],"explanation":"En Virginia Occidental, las CDL son emitidas por la West Virginia Division of Motor Vehicles (DMV), que administra los exámenes de conocimientos y procesa las solicitudes. Fuente: página de Commercial Driver's License de WV DMV (transportation.wv.gov/DMV/Motor-Carriers/CDL)."},"81":{"q":"Antes de que Virginia Occidental emita una CDL completa, el solicitante primero debe obtener y poseer qué credencial?","options":["Un Commercial Learner's Permit (CLP)","Un endoso de licencia de operador Clase D","Una autoridad federal de operación interestatal","Un permiso de conducir temporal por dificultad económica"],"explanation":"Virginia Occidental exige que los solicitantes obtengan primero un Commercial Learner's Permit (CLP) de la DMV, que autoriza la práctica supervisada antes del examen de habilidades. Fuente: página CDL de WV DMV."},"82":{"q":"En Virginia Occidental, ¿durante cuánto tiempo debe un solicitante poseer un Commercial Learner's Permit (CLP) antes de ser elegible para tomar el examen de habilidades de manejo de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Virginia Occidental (siguiendo el estándar federal) exige que el CLP se posea durante un mínimo de 14 días antes de que el solicitante pueda tomar el examen de habilidades de manejo. Fuente: página CDL de WV DMV; 49 CFR 383.25 según se adopta en WV."},"83":{"q":"Al autocertificar el tipo de operación comercial, un solicitante de CDL/CLP de Virginia Occidental debe elegir entre cuántas categorías?","options":["Cuatro categorías","Dos categorías","Tres categorías","Cinco categorías"],"explanation":"Virginia Occidental exige que los solicitantes se autocertifiquen en una de cuatro categorías de operación de vehículos motorizados comerciales: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) y Excepted Intrastate (EA). Fuente: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3)."},"84":{"q":"¿Qué categoría de autocertificación de Virginia Occidental exige que el conductor mantenga en archivo un DOT Medical Examiner's Certificate válido?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","Cualquier conductor que solo opere dentro del estado está exento"],"explanation":"Los conductores que se autocertifican en un estatus non-excepted (NI o NA) deben mantener un FMCSA Medical Examiner's Certificate válido; los estatus excepted (EI, EA) están exentos de ese requisito. Fuente: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3); FMCSA 49 CFR 383.71."},"85":{"q":"A partir del 23 de junio de 2025, ¿cómo se proporciona normalmente a la DMV la información médica del DOT de un conductor de CDL non-excepted de Virginia Occidental?","options":["El examinador médico certificado ingresa los resultados del examen en una base de datos electrónica segura que los transmite a la DMV","El conductor envía por correo una tarjeta médica en papel a la DMV después de cada examen","El empleador del conductor envía por fax la tarjeta médica a la DMV","La tarjeta médica se verifica solo en el momento de la renovación de la licencia"],"explanation":"A partir del 23 de junio de 2025, Virginia Occidental ya no acepta certificados médicos en papel; el examinador médico certificado ingresa electrónicamente los resultados del examen en una base de datos segura que se envía a la DMV. Fuente: anuncio de WV DMV sobre el proceso mejorado de certificación médica de la CDL (junio de 2025)."},"86":{"q":"¿Cuál es la puntuación mínima para aprobar un examen de conocimientos (escrito) de la CDL de Virginia Occidental?","options":["80 por ciento","70 por ciento","75 por ciento","90 por ciento"],"explanation":"Virginia Occidental exige al menos 80 por ciento de respuestas correctas para aprobar un examen de conocimientos de la CDL. Fuente: WV Commercial Driver's License Manual; reglas de exámenes de la CDL de WV DMV."},"87":{"q":"El examen de habilidades de la CDL de Virginia Occidental se compone de qué tres partes, en orden?","options":["Inspección del vehículo previa al viaje, control básico del vehículo y manejo en carretera","Conocimientos escritos, examen de visión y manejo en carretera","Verificación de frenos de aire, prueba de acoplamiento y prueba de tiempo de reacción","Maniobras de retroceso, incorporación a la autopista y estacionamiento en paralelo"],"explanation":"El examen de habilidades de la CDL de Virginia Occidental consta de tres partes: la inspección del vehículo previa al viaje, el examen de habilidades de control básico del vehículo y el examen de manejo en carretera. Fuente: WV Commercial Driver's License Manual (secciones del Skills Test)."},"88":{"q":"¿Quién debe proporcionar el vehículo utilizado para el examen de habilidades (manejo) de la CDL de Virginia Occidental?","options":["El solicitante, que debe aportar un vehículo representativo de la clase que se está examinando","La DMV, que proporciona un camión de prueba estándar","El parque vehicular de la Division of Highways","Cualquier vehículo es aceptable, incluido un automóvil de pasajeros"],"explanation":"El solicitante debe proporcionar el vehículo para el examen de habilidades, y este debe ser representativo de la clase de CDL para la cual el solicitante se está examinando. Fuente: WV Commercial Driver's License Manual; página CDL de WV DMV."},"89":{"q":"Un solicitante de CDL por primera vez en Virginia Occidental debe completar el Entry-Level Driver Training (ELDT) antes de tomar qué examen?","options":["El examen de habilidades (manejo) de la CDL","El examen de visión","El examen de renovación de la Clase D","La verificación de antecedentes con huellas dactilares"],"explanation":"El ELDT (teórico y detrás del volante) debe completarse antes del examen de habilidades de la CDL para solicitantes de Clase A/B por primera vez y para ciertos endosos. Fuente: página CDL de WV DMV; regla ELDT de FMCSA (49 CFR Part 380), vigente desde el 7 de febrero de 2022."},"90":{"q":"Según la regla federal ELDT aplicada en Virginia Occidental, ¿un conductor se considera solicitante de CDL 'por primera vez' (y debe completar el ELDT) si nunca había tenido una CDL antes de qué fecha?","options":["7 de febrero de 2022","1 de enero de 2020","1 de octubre de 2021","23 de junio de 2025"],"explanation":"Los requisitos del ELDT no son retroactivos: una persona que nunca había tenido una CDL (o el endoso S, P o H correspondiente) antes del 7 de febrero de 2022 es un solicitante por primera vez que debe completar el ELDT. Fuente: página CDL de WV DMV; regla final ELDT de FMCSA."},"91":{"q":"¿Dónde debe figurar un proveedor de capacitación ELDT de Virginia Occidental para que la capacitación cuente para la elegibilidad de la CDL?","options":["En el FMCSA Training Provider Registry (TPR)","Solo en la lista de proveedores de la West Virginia DMV","En el registro de contratistas de la Division of Highways estatal","En el National CDL Examiner Directory"],"explanation":"El ELDT debe completarse a través de un proveedor que figure en el FMCSA Training Provider Registry (TPR) para que cumpla con el requisito de la CDL en Virginia Occidental. Fuente: página CDL de WV DMV; FMCSA TPR (tpr.fmcsa.dot.gov)."},"92":{"q":"En Virginia Occidental, ¿cuál es la edad mínima para obtener una CDL para operación intraestatal (solo dentro del estado)?","options":["18 años","21 años","19 años","16 años"],"explanation":"El solicitante debe tener al menos 18 años para obtener una CDL de Virginia Occidental para operación intraestatal; la operación interestatal y los materiales peligrosos requieren tener 21 años. Fuente: página CDL de WV DMV; WV Code Chapter 17E."},"93":{"q":"¿Cuál es la edad mínima para operar un vehículo motorizado comercial en el comercio interestatal o para transportar materiales peligrosos según las reglas de CDL de Virginia Occidental?","options":["21 años","18 años","19 años","25 años"],"explanation":"Virginia Occidental exige que el conductor tenga al menos 21 años para operar de forma interestatal o para transportar materiales peligrosos con carteles (placards); los de 18 a 20 años están limitados a la operación intraestatal. Fuente: página CDL de WV DMV; FMCSA 49 CFR 391.11."},"94":{"q":"Según el ciclo estándar 'Drive for Five' de Virginia Occidental, ¿por cuánto tiempo es válida generalmente una CDL?","options":["Cinco años, venciendo en el cumpleaños del titular en un año en que su edad sea divisible entre cinco","Cuatro años, en una fecha fija de renovación","Ocho años a partir de la fecha de emisión","Dos años, coincidiendo con la tarjeta médica del DOT"],"explanation":"Las CDL de Virginia Occidental se renuevan en el ciclo estándar de cinco años, venciendo en el cumpleaños del solicitante en un año en el que la edad del solicitante sea divisible exactamente entre cinco. Fuente: WV Code 17E-1-12; WV DMV."},"95":{"q":"Una CDL de Virginia Occidental emitida a un conductor menor de 21 años vence en qué momento?","options":["30 días después del cumpleaños del solicitante en el año en que el solicitante cumple 21 años","En el cumpleaños número 18 del conductor","Cinco años a partir de la fecha de emisión, independientemente de la edad","Inmediatamente al cumplir 21 años"],"explanation":"Una CDL de Virginia Occidental emitida a una persona que no ha alcanzado los 21 años vence 30 días después del cumpleaños del solicitante en el año en que el solicitante cumple 21 años, ya que la elegibilidad para interestatal/hazmat cambia a los 21. Fuente: WV Code Chapter 17E; WV DMV."},"96":{"q":"¿Qué documento usa un solicitante de Virginia Occidental para autocertificar el tipo de manejo comercial que espera realizar?","options":["El WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3)","El certificado médico federal Form MCSA-5876","La solicitud de licencia de operador Clase D","El formulario de registro prorrateado IRP"],"explanation":"Los solicitantes autocertifican su tipo de operación en el WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3); el Form MCSA-5876 es el certificado del examinador médico, que es independiente. Fuente: formularios CDL de WV DMV."},"97":{"q":"¿Durante cuánto tiempo se considera vigente un DOT Medical Examiner's Certificate según las reglas de CDL de Virginia Occidental?","options":["No está vigente si tiene más de dos años (y puede emitirse por un período más corto)","Es válido por cinco años","Es válido por un año solamente","Nunca vence una vez que está en archivo"],"explanation":"Un Medical Examiner's Certificate de más de dos años no está vigente; un examinador puede emitirlo por dos años o por un intervalo más corto según la condición del conductor. Fuente: página CDL de WV DMV; FMCSA 49 CFR 391.45."},"98":{"q":"¿Qué sucede generalmente con los privilegios de CDL de un conductor de Virginia Occidental si se permite que caduque un Medical Examiner's Certificate requerido?","options":["La CDL se degrada de modo que la persona pierde los privilegios de manejo comercial hasta que haya un certificado válido en archivo","Nada cambia hasta la siguiente renovación de cinco años","El conductor se reclasifica automáticamente como conductor excepted","El conductor recibe una prórroga automática de un año"],"explanation":"Si la certificación médica de un conductor non-excepted caduca, Virginia Occidental degrada la CDL, retirando los privilegios comerciales hasta que se proporcione un certificado vigente. Fuente: página CDL de WV DMV; disposiciones de certificación médica de FMCSA 49 CFR 383.73."},"99":{"q":"En Virginia Occidental, ¿qué conjunto de documentos forma parte del requisito básico para solicitar una CDL?","options":["Prueba de identidad/estatus legal, prueba de residencia en Virginia Occidental, verificación del Seguro Social y la solicitud de CDL completada","Solo un pasaporte y una tarjeta de crédito","Solo un título del vehículo y prueba de seguro","Una carta del empleador y un diploma de secundaria"],"explanation":"Los solicitantes de CDL de Virginia Occidental deben presentar prueba de identidad y de ciudadanía estadounidense o residencia permanente legal, prueba de residencia en Virginia Occidental, verificación del número de Seguro Social y una solicitud de CDL completada (además de los documentos médicos/de autocertificación). Fuente: página CDL de WV DMV."}},"hi":{"0":{"q":"वेस्ट वर्जीनिया के राजमार्गों पर जहां लेन की न्यूनतम चौड़ाई दस फीट है (नामित और इंटरस्टेट मार्गों सहित), वहां किसी वाहन या उसके भार की अधिकतम स्वीकार्य बाहरी चौड़ाई कितनी है?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"explanation":"W.Va. Code 17C-17-2 के तहत, कुल बाहरी चौड़ाई 96 inches से अधिक नहीं हो सकती, सिवाय इसके कि 102 inches (8 feet 6 inches) का वाहन U.S. DOT द्वारा नामित राजमार्गों पर या किसी भी ऐसे राजमार्ग पर चल सकता है जहां लेन की न्यूनतम चौड़ाई 10 feet हो। स्रोत: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits।"},"1":{"q":"वेस्ट वर्जीनिया के राजमार्गों पर किसी वाहन की, उसके भार सहित, अधिकतम वैध ऊंचाई कितनी है?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"W.Va. Code 17C-17-4 प्रावधान करता है कि कोई वाहन, किसी भी भार सहित, वेस्ट वर्जीनिया के किसी भी मार्ग पर 13 feet 6 inches की ऊंचाई से अधिक नहीं हो सकता। स्रोत: W.Va. Code 17C-17-4; WV DOT Legal Size and Weight Limits।"},"2":{"q":"वेस्ट वर्जीनिया में, एक सिंगल एक्सल पर अधिकतम सकल भार कितना है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"वेस्ट वर्जीनिया एक सिंगल एक्सल को 20,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। स्रोत: W.Va. Code 17C-17-8 / 17C-17-9; WV DOT Legal Size and Weight Limits।"},"3":{"q":"वेस्ट वर्जीनिया में, एक टैंडम एक्सल समूह पर अनुमत अधिकतम सकल भार कितना है?","options":["20,000 pounds","32,000 pounds","34,000 pounds","40,000 pounds"],"explanation":"वेस्ट वर्जीनिया एक टैंडम एक्सल को 34,000 pounds तक सीमित करता है, जो संघीय एक्सल-भार मानक से मेल खाता है। स्रोत: W.Va. Code 17C-17-8a / 17C-17-9; WV DOT Legal Size and Weight Limits।"},"4":{"q":"वेस्ट वर्जीनिया में परमिट के बिना इंटरस्टेट (इंटरस्टेट और रक्षा राजमार्गों की राष्ट्रीय प्रणाली) पर चलने वाले किसी वाहन या संयोजन के लिए अधिकतम वैध सकल वाहन भार कितना है?","options":["73,280 pounds","80,000 pounds","88,000 pounds","90,000 pounds"],"explanation":"W.Va. Code 17C-17-9 कहता है कि इंटरस्टेट और रक्षा राजमार्गों की राष्ट्रीय प्रणाली पर अधिकतम सकल भार 80,000 pounds से अधिक नहीं होगा (ब्रिज फॉर्मूला के अधीन)। स्रोत: W.Va. Code 17C-17-9।"},"5":{"q":"वेस्ट वर्जीनिया में किसी ट्रक ट्रैक्टर-सेमीट्रेलर संयोजन में, जब किंगपिन-से-रियर-एक्सल दूरी की शर्त पूरी हो जाती है, तो अनुमत अधिकतम सेमीट्रेलर लंबाई कितनी है?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"W.Va. Code 17C-17-4 एक सेमीट्रेलर को 48 feet तक सीमित करता है, लेकिन 53 feet तक की अनुमति देता है जहां ट्रक ट्रैक्टर के रियर एक्सल से सेमीट्रेलर के फ्रंट एक्सल तक की एक्सल दूरी 37 feet से अधिक न हो। स्रोत: W.Va. Code 17C-17-4।"},"6":{"q":"वेस्ट वर्जीनिया के उन राजमार्गों पर जिनकी लेन 10 feet से कम चौड़ी हैं (जैसे कुछ स्थानीय सेवा मार्ग), अधिकतम वैध वाहन चौड़ाई कितनी है?","options":["7 feet 6 inches","8 feet (96 inches)","8 feet 6 inches","9 feet"],"explanation":"102-inch (8'6\") की छूट केवल नामित मार्गों या 10 feet या उससे अधिक चौड़ी लेन पर लागू होती है; 10 feet से कम चौड़ी लेन वाली सड़कों पर चौड़ाई 96-inch (8-foot) की सीमा पर वापस आ जाती है। स्रोत: W.Va. Code 17C-17-2; WV DOT Legal Size and Weight Limits।"},"7":{"q":"वेस्ट वर्जीनिया के उन राजमार्गों पर जो इंटरस्टेट या अन्यथा नामित मार्ग नहीं हैं, वाहनों के संयोजन की अधिकतम कुल लंबाई कितनी है?","options":["53 feet","55 feet","65 feet","75 feet"],"explanation":"W.Va. Code 17C-17-4 एक साथ जुड़े वाहनों के संयोजन को, आगे और पीछे के बंपर सहित, गैर-नामित राजमार्गों पर 55 feet की कुल लंबाई तक सीमित करता है। स्रोत: W.Va. Code 17C-17-4।"},"8":{"q":"वेस्ट वर्जीनिया में किसी एकल मोटर वाहन (सीधे ट्रक) की अधिकतम चरम कुल लंबाई कितनी है?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"W.Va. Code 17C-17-4 किसी एकल मोटर वाहन को, उसके भार सहित, 40 feet की चरम कुल माप तक सीमित करता है (कुछ मोटर होम और स्कूल बसों के लिए 45 feet की अनुमति है)। स्रोत: W.Va. Code 17C-17-4।"},"9":{"q":"वेस्ट वर्जीनिया द्वारा संघीय ब्रिज भार प्रावधानों को अपनाने के तहत, टैंडम एक्सल के दो लगातार सेट प्रत्येक 34,000 pounds ले जा सकते हैं बशर्ते लगातार टैंडम सेटों के पहले और अंतिम एक्सल के बीच की दूरी कम से कम कितने फीट हो?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"W.Va. Code 17C-17-9 टैंडम एक्सल के दो लगातार सेटों को प्रत्येक 34,000 pounds ले जाने की अनुमति देता है बशर्ते ऐसे लगातार टैंडम सेटों के पहले और अंतिम एक्सल के बीच की कुल दूरी 36 feet या उससे अधिक हो। स्रोत: W.Va. Code 17C-17-9।"},"10":{"q":"वेस्ट वर्जीनिया का ओवरवेट (सिंगल-ट्रिप) परमिट आम तौर पर केवल तभी जारी किया जा सकता है जब भार किस शर्त को पूरा करता हो?","options":["भार अविभाज्य है","वाहक वेस्ट वर्जीनिया में स्थित है","वाहन में छह या अधिक एक्सल हैं","यात्रा केवल इंटरस्टेट पर होती है"],"explanation":"वेस्ट वर्जीनिया ओवरवेट परमिट केवल उन अविभाज्य भारों के लिए जारी करता है जिन्हें कानूनी सीमा तक घटाया नहीं जा सकता (समुद्री कंटेनरीकृत माल एक उल्लेखनीय अपवाद है)। स्रोत: WV DOT Division of Highways Hauling Permits / Permit Types।"},"11":{"q":"कोई मोटर वाहक वेस्ट वर्जीनिया के राज्य-स्वामित्व वाले मार्गों के लिए ओवरसाइज़/ओवरवेट हॉलिंग परमिट कैसे प्राप्त करता है?","options":["केवल किसी काउंटी कोर्टहाउस में व्यक्तिगत रूप से","West Virginia DOT/Division of Highways की ऑनलाइन हॉलिंग परमिट प्रणाली के माध्यम से","West Virginia State Police बैरक से","वेस्ट वर्जीनिया में परमिट की आवश्यकता नहीं है"],"explanation":"इंटरस्टेट, टर्नपाइक, U.S., WV, और काउंटी मार्गों के लिए ओवरसाइज़/ओवरवेट परमिट WV DOT Division of Highways की ऑनलाइन हॉलिंग परमिट प्रणाली के माध्यम से प्राप्त किए जाते हैं। स्रोत: WV DOT Hauling Permits; wv.gotpermits.com।"},"12":{"q":"U.S. और WV राज्य मार्गों (गैर-इंटरस्टेट) पर, वेस्ट वर्जीनिया अपनी वैध एक्सल और सकल भार सीमाओं पर कितनी भार सहनशीलता लागू करता है?","options":["कोई सहनशीलता नहीं (शून्य)","5 percent","10 percent","15 percent"],"explanation":"U.S. और WV मार्गों तथा स्थानीय सेवा मार्गों पर, वेस्ट वर्जीनिया वैध भार सीमाओं से अधिक 10 percent सहनशीलता की अनुमति देता है, जबकि इंटरस्टेट राजमार्ग शून्य सहनशीलता की अनुमति देते हैं। स्रोत: WV DOT Legal Size and Weight Limits।"},"13":{"q":"वेस्ट वर्जीनिया के स्थानीय सेवा मार्गों (गैर-नामित काउंटी सड़कों) पर, परमिट की आवश्यकता होने से पहले अधिकतम वैध सकल वाहन भार कितना है?","options":["60,000 pounds","65,000 pounds","73,280 pounds","80,000 pounds"],"explanation":"जबकि इंटरस्टेट और U.S./WV मार्ग 80,000 pounds तक की अनुमति देते हैं, वेस्ट वर्जीनिया के स्थानीय सेवा मार्गों की वैध सकल भार सीमा 65,000 pounds की कम है। स्रोत: WV DOT Legal Size and Weight Limits।"},"14":{"q":"वेस्ट वर्जीनिया के ओवरवेट-और-ओवरसाइज़ वार्षिक ब्लैंकेट परमिट के तहत इंटरस्टेट के अलावा अन्य मार्गों पर चलने वाले किसी वाहन पर कौन सा अधिकतम अनुमत सकल भार लागू होता है?","options":["80,000 pounds","90,000 pounds","110,000 pounds","120,000 pounds"],"explanation":"वेस्ट वर्जीनिया के ओवरवेट/ओवरसाइज़ वार्षिक (ब्लैंकेट) परमिट के तहत, गैर-इंटरस्टेट मार्गों पर अधिकतम सकल भार 90,000 pounds है (इंटरस्टेट पर 110,000 pounds)। स्रोत: WV DOT Permit Types (Annual/Blanket Permits)।"},"15":{"q":"वेस्ट वर्जीनिया के ओवरवेट वार्षिक (ब्लैंकेट) परमिट के तहत, एक टैंडम एक्सल पर अधिकतम अनुमत भार कितना है?","options":["34,000 pounds","40,000 pounds","45,000 pounds","50,000 pounds"],"explanation":"वेस्ट वर्जीनिया के ओवरवेट ब्लैंकेट परमिट एक सिंगल एक्सल पर 28,000 pounds तक, एक टैंडम एक्सल पर 45,000 pounds तक, और एक ट्राइडेम एक्सल पर 50,000 pounds तक की अनुमति देते हैं। स्रोत: WV DOT Permit Types (Annual/Blanket Permits)।"},"16":{"q":"वेस्ट वर्जीनिया की किसी नामित 'कोल रिसोर्स ट्रांसपोर्टेशन रोड' पर, परमिट के तहत कोयला ढोने वाले वाहन को लगभग किस अधिकतम सकल भार तक चलाया जा सकता है?","options":["80,000 pounds","90,000 pounds","120,000 pounds","150,000 pounds"],"explanation":"W.Va. Code Chapter 17C, Article 17A के तहत, नामित कोल रिसोर्स ट्रांसपोर्टेशन रोड पर कोयला ढोने वाले वाहन 120,000 pounds तक के अधिक सकल भार पर चल सकते हैं (5 percent भिन्नता के साथ), जो 17C-17-9 की सीमाओं से अधिक है। स्रोत: W.Va. Code 17C-17A; WV PSC coal resource transportation permitting।"},"17":{"q":"वेस्ट वर्जीनिया के ओवरवेट वार्षिक (ब्लैंकेट) परमिट के तहत किसी सिंगल एक्सल पर अधिकतम अनुमत भार कितना है?","options":["20,000 pounds","24,000 pounds","28,000 pounds","34,000 pounds"],"explanation":"वेस्ट वर्जीनिया का ओवरवेट ब्लैंकेट परमिट किसी सिंगल एक्सल पर 28,000 pounds तक की अनुमति देता है (20,000-pound की वैध सीमा के मुकाबले)। स्रोत: WV DOT Permit Types (Annual/Blanket Permits)।"},"18":{"q":"वेस्ट वर्जीनिया के ओवरसाइज़ सिंगल-ट्रिप परमिट के लिए, आम तौर पर किन घंटों के दौरान ओवरसाइज़ आवाजाही वैध नहीं होती?","options":["सूर्यास्त से सूर्योदय तक (रात का समय)","कार्यदिवसों पर दोपहर से 2 p.m. तक","सोमवार को किसी भी समय","केवल सुबह के व्यस्त समय के दौरान"],"explanation":"वेस्ट वर्जीनिया का ओवरसाइज़ परमिट आम तौर पर सूर्यास्त से सूर्योदय तक के रात के घंटों के दौरान वैध नहीं होता, और छुट्टियों पर कोई यात्रा अनुमत नहीं है। स्रोत: WV DOT Hauling Permits / Permit conditions।"},"19":{"q":"एक स्टीयरिंग एक्सल और एक टैंडम एक्सल समूह वाला वेस्ट वर्जीनिया का सिंगल-यूनिट (सीधा) ट्रक, अनुमत सहनशीलता लागू करने से पहले, आम तौर पर किस अधिकतम सकल वाहन भार तक सीमित है?","options":["48,000 pounds","54,000 pounds","60,000 pounds","66,000 pounds"],"explanation":"एक स्टीयरिंग एक्सल और टैंडम में दो एक्सल वाला वेस्ट वर्जीनिया का सिंगल-यूनिट ट्रक 60,000 pounds के अधिकतम सकल भार तक सीमित है (गैर-इंटरस्टेट मार्गों पर 10 percent सहनशीलता से पहले)। स्रोत: WV DOT Legal Size and Weight Limits।"},"20":{"q":"वेस्ट वर्जीनिया में, 26,001 pounds या उससे अधिक के सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के संयोजन को चलाने के लिए कौन सी CDL श्रेणी आवश्यक है, जहां खींचे जा रहे वाहन का GVWR 10,000 pounds से अधिक है?","options":["Class A","Class B","Class C","Class D"],"explanation":"वेस्ट वर्जीनिया संघीय वर्गीकरण को अपनाता है: एक Class A CDL 26,001 lbs या उससे अधिक के GCWR वाले वाहनों के किसी भी संयोजन को कवर करता है, बशर्ते खींची जा रही इकाई का GVWR 10,000 lbs से अधिक हो। स्रोत: WV DMV Commercial Driver's License page और WV CDL Manual।"},"21":{"q":"वेस्ट वर्जीनिया के नियमों के तहत, 26,001 pounds या उससे अधिक के GVWR वाले एकल वाहन (या ऐसा वाहन जो 10,000 pounds से अधिक न होने वाली इकाई को खींच रहा हो) के लिए कौन सी CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","Class E"],"explanation":"वेस्ट वर्जीनिया में एक Class B CDL 26,001 lbs या उससे अधिक के GVWR वाले एकल वाहन को अधिकृत करता है, जिसमें 10,000 lbs या उससे कम के GVWR वाली इकाई को खींचना शामिल है। स्रोत: WV DMV CDL page और WV CDL Manual।"},"22":{"q":"एक वेस्ट वर्जीनिया चालक 26,001 pounds से कम का ऐसा वाहन चलाता है जो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या जिसका उपयोग प्लेकार्ड वाली खतरनाक सामग्री के परिवहन के लिए किया जाता है। कौन सी CDL श्रेणी लागू होती है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं"],"explanation":"एक Class C CDL उन वाहनों को कवर करता है जो Class A या B भार सीमा को पूरा नहीं करते लेकिन 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए हैं या प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाते हैं। स्रोत: WV DMV CDL page और WV CDL Manual।"},"23":{"q":"वेस्ट वर्जीनिया CDL पर कौन सा एंडोर्समेंट कोड प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री के परिवहन को अधिकृत करता है?","options":["N","H","T","X"],"explanation":"'H' एंडोर्समेंट प्लेकार्ड वाली खतरनाक सामग्री के परिवहन को अधिकृत करता है। 'X' कोड एक संयुक्त Tank-प्लस-HazMat एंडोर्समेंट है। स्रोत: WV CDL Manual, Endorsements section।"},"24":{"q":"वेस्ट वर्जीनिया CDL पर, स्थायी रूप से लगे टैंक में तरल या गैसीय सामग्री ढोने वाले टैंक वाहन को चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["T (Doubles/Triples)","N (Tank)","P (Passenger)","H (HazMat)"],"explanation":"थोक में तरल या गैस ले जाने वाले टैंक वाहनों के लिए 'N' (Tank) एंडोर्समेंट आवश्यक है। 'T' एंडोर्समेंट डबल और ट्रिपल ट्रेलरों के लिए है, जो एक अलग प्राधिकरण है। स्रोत: WV CDL Manual, Endorsements section।"},"25":{"q":"एक वेस्ट वर्जीनिया CDL धारक डबल या ट्रिपल ट्रेलर खींचना चाहता है। कौन सा एंडोर्समेंट जोड़ा जाना चाहिए?","options":["N","S","T","P"],"explanation":"'T' एंडोर्समेंट डबल और ट्रिपल ट्रेलर संयोजनों के संचालन को अधिकृत करता है और इसके लिए एक नॉलेज टेस्ट पास करना आवश्यक है। स्रोत: WV CDL Manual, Endorsements section।"},"26":{"q":"वेस्ट वर्जीनिया में किराए पर बस में यात्रियों को ले जाने के लिए (उदाहरण के लिए, ट्रांज़िट या मोटरकोच), कौन सा CDL एंडोर्समेंट आवश्यक है?","options":["S endorsement","P endorsement","N endorsement","H endorsement"],"explanation":"16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए 'P' (Passenger) एंडोर्समेंट आवश्यक है और इसके लिए एक प्रतिनिधि वाहन में नॉलेज टेस्ट और रोड स्किल्स टेस्ट दोनों आवश्यक हैं। स्रोत: WV CDL Manual, Endorsements section।"},"27":{"q":"वेस्ट वर्जीनिया चालक को स्कूल बस चलाने के लिए Passenger (P) एंडोर्समेंट के अलावा कौन सा एंडोर्समेंट आवश्यक होता है?","options":["S endorsement","T endorsement","N endorsement","X endorsement"],"explanation":"स्कूल बस चलाने के लिए 'S' (School Bus) एंडोर्समेंट आवश्यक है और इसे 'P' एंडोर्समेंट के अतिरिक्त प्राप्त किया जाता है; इसके लिए स्कूल बस में नॉलेज टेस्ट और रोड स्किल्स टेस्ट आवश्यक है। स्रोत: WV CDL Manual, Endorsements section।"},"28":{"q":"इंट्रास्टेट ड्राइविंग (केवल वेस्ट वर्जीनिया के भीतर संचालन) के लिए वेस्ट वर्जीनिया CDL जारी करने हेतु न्यूनतम आयु क्या है?","options":["16 years","18 years","21 years","25 years"],"explanation":"इंट्रास्टेट (वेस्ट वर्जीनिया के भीतर) वाणिज्य के लिए वैध CDL प्राप्त करने हेतु आवेदक की आयु कम से कम 18 वर्ष होनी चाहिए। स्रोत: WV CDL Manual / WV DMV CDL requirements।"},"29":{"q":"इंटरस्टेट ड्राइविंग (राज्य की सीमाओं के पार) के लिए वेस्ट वर्जीनिया CDL जारी करने हेतु आवश्यक न्यूनतम आयु क्या है?","options":["18 years","19 years","21 years","23 years"],"explanation":"वेस्ट वर्जीनिया द्वारा अपनाए गए संघीय नियमों के अनुसार, इंटरस्टेट वाणिज्य में वाणिज्यिक मोटर वाहन चलाने या खतरनाक सामग्री ले जाने के लिए चालक की आयु कम से कम 21 वर्ष होनी चाहिए। स्रोत: WV CDL Manual / 49 CFR 391.11 जैसा कि WV DMV द्वारा लागू किया गया है।"},"30":{"q":"वेस्ट वर्जीनिया Commercial Learner's Permit (CLP) प्राप्त करने के बाद, CDL रोड स्किल्स टेस्ट देने के लिए पात्र होने से पहले आवेदक को इसे कितने समय तक रखना आवश्यक है?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 7 days","कम से कम 60 days"],"explanation":"वेस्ट वर्जीनिया द्वारा अपनाए गए संघीय कानून के अनुसार आवेदक को स्किल्स (रोड) टेस्ट देने से पहले CLP को कम से कम 14 days तक रखना आवश्यक है। स्रोत: WV DMV CDL page; 49 CFR 383.25।"},"31":{"q":"नवीनीकरण के संबंध में, कौन सा कथन वेस्ट वर्जीनिया Commercial Learner's Permit (CLP) का सबसे अच्छा वर्णन करता है?","options":["यह नवीनीकरण योग्य नहीं है और इसकी वैधता एक वर्ष से अधिक नहीं हो सकती","इसे असीमित बार नवीनीकृत किया जा सकता है","यह नियमित लाइसेंस की तरह पांच वर्ष के लिए वैध है","जारी होने के बाद यह कभी समाप्त नहीं होता"],"explanation":"WV DMV CDL page कहता है कि Commercial Learner's Permit की वैधता एक वर्ष से अधिक नहीं हो सकती और यह नवीनीकरण योग्य नहीं है। स्रोत: WV DMV Commercial Driver's License page।"},"32":{"q":"वेस्ट वर्जीनिया CLP पर वाणिज्यिक मोटर वाहन चलाते समय, परमिट धारक के साथ निम्नलिखित में से कौन होना चाहिए?","options":["उस वाहन प्रकार के लिए वैध CDL का धारक, जो चालक के बगल में बैठा हो","वाहन की किसी भी सीट पर 21 वर्ष से अधिक का कोई भी लाइसेंस प्राप्त चालक","केवल एक DMV परीक्षक","कोई नहीं; CLP अकेले ड्राइविंग की अनुमति देता है"],"explanation":"एक CLP धारक किसी CMV को केवल तभी चला सकता है जब उसके साथ उस श्रेणी/प्रकार के वाहन के लिए वैध CDL का धारक हो जो परमिट धारक के बगल की सीट पर बैठा हो। स्रोत: WV DMV CDL page; 49 CFR 383.25।"},"33":{"q":"वेस्ट वर्जीनिया CDL नॉलेज (लिखित) टेस्ट पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["70%","75%","80%","90%"],"explanation":"वेस्ट वर्जीनिया प्रत्येक CDL नॉलेज टेस्ट पास करने के लिए न्यूनतम 80% अंक की आवश्यकता रखता है (HazMat टेस्ट लिखित रूप में देना होता है)। स्रोत: WV DMV CDL testing requirements।"},"34":{"q":"वेस्ट वर्जीनिया द्वारा HazMat (H) एंडोर्समेंट जारी करने से पहले, आवेदक को कौन सी संघीय जांच पास करनी होती है?","options":["एक Transportation Security Administration (TSA) सुरक्षा खतरा मूल्यांकन","एक क्रेडिट इतिहास समीक्षा","बिना फिंगरप्रिंट के केवल-राज्य आपराधिक रिकॉर्ड जांच","केवल-दृष्टि चिकित्सा जांच"],"explanation":"वेस्ट वर्जीनिया द्वारा अपनाए गए संघीय कानून के अनुसार HazMat एंडोर्समेंट के आवेदकों को एंडोर्समेंट जारी या नवीनीकृत होने से पहले एक TSA सुरक्षा खतरा मूल्यांकन पास करना होता है, जिसमें फिंगरप्रिंटिंग और पृष्ठभूमि जांच शामिल है। स्रोत: WV CDL Manual; 49 CFR 1572 (TSA)।"},"35":{"q":"वेस्ट वर्जीनिया CDL पर HazMat (H) एंडोर्समेंट प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 years","21 years","25 years","19 years"],"explanation":"चूंकि खतरनाक सामग्री परिवहन के लिए संघीय नियमों के तहत इंटरस्टेट-योग्य स्थिति आवश्यक है, आवेदक की आयु HazMat एंडोर्समेंट प्राप्त करने के लिए कम से कम 21 वर्ष होनी चाहिए। स्रोत: WV CDL Manual; TSA/FMCSA HazMat requirements।"},"36":{"q":"वेस्ट वर्जीनिया में पहली बार CDL के आवेदकों को Entry-Level Driver Training (ELDT) ऐसे प्रदाता के माध्यम से पूरी करनी होती है जो:","options":["FMCSA Training Provider Registry (TPR) पर सूचीबद्ध है","केवल West Virginia State Police द्वारा अनुमोदित है","आवेदक की पसंद का कोई भी निजी ड्राइविंग स्कूल","TSA द्वारा प्रमाणित है"],"explanation":"ELDT FMCSA Training Provider Registry (TPR) पर सूचीबद्ध प्रदाता के साथ पूरी होनी चाहिए। यह उन लोगों पर लागू होती है जो पहली बार Class A या B CDL प्राप्त कर रहे हैं, B को A में अपग्रेड कर रहे हैं, या पहली बार P, S, या H एंडोर्समेंट चाह रहे हैं (Feb 7, 2022 को या उसके बाद)। स्रोत: FMCSA ELDT rule; WV DMV CDL page।"},"37":{"q":"निम्नलिखित में से कौन सी उन चार चिकित्सा स्व-प्रमाणन श्रेणियों में से एक है जिनमें से वेस्ट वर्जीनिया CDL आवेदक को चुनना होता है?","options":["Non-Excepted Interstate (NI)","Recreational Interstate (RI)","Commercial Exempt (CE)","Limited Local (LL)"],"explanation":"चार स्व-प्रमाणन श्रेणियां हैं Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। गैर-अपवादित श्रेणियों के चालकों के पास एक वैध DOT चिकित्सा परीक्षक प्रमाणपत्र होना चाहिए। स्रोत: WV DMV CDL self-certification; FMCSA।"},"38":{"q":"एक वेस्ट वर्जीनिया CDL चालक जो 'Non-Excepted Interstate (NI)' के रूप में प्रमाणित करता है, उसे कौन सा दस्तावेज़ प्रदान करना होता है?","options":["एक वैध चिकित्सा परीक्षक प्रमाणपत्र (DOT medical card)","केवल एक मोटर वाहन बीमा बाइंडर","एक हस्ताक्षरित नियोक्ता छूट पत्र","आवेदन के अलावा कुछ अतिरिक्त नहीं"],"explanation":"गैर-अपवादित श्रेणी (NI या NA) में प्रमाणित करने वाले चालकों को FMCSA National Registry के किसी परीक्षक से एक वैध चिकित्सा परीक्षक प्रमाणपत्र प्राप्त करना और जमा करना होता है; अपवादित श्रेणियों (EI, EA) के लिए DOT medical card आवश्यक नहीं है। स्रोत: WV DMV CDL self-certification; FMCSA।"},"39":{"q":"वेस्ट वर्जीनिया CDL या CLP के लिए आवेदन करते समय, DMV को वेस्ट वर्जीनिया निवास के कितने प्रमाण चाहिए?","options":["निवास का एक प्रमाण","निवास के दो प्रमाण","निवास के तीन प्रमाण","निवास के किसी प्रमाण की आवश्यकता नहीं है"],"explanation":"वेस्ट वर्जीनिया CDL/CLP आवेदन के लिए पहचान/वैध उपस्थिति का एक प्रमाण, Social Security number का एक प्रमाण, और वेस्ट वर्जीनिया निवास के दो प्रमाण आवश्यक हैं। स्रोत: WV DMV acceptable documents / driver license requirements।"},"40":{"q":"वेस्ट वर्जीनिया कानून के तहत, किस रक्त अल्कोहल सांद्रता (BAC) पर किसी चालक को बहुत अधिक अल्कोहल के साथ वाणिज्यिक मोटर वाहन (CMV) चलाते हुए माना जाता है, जिससे अयोग्यता शुरू हो जाती है?","options":["0.08% या अधिक","0.02% या अधिक","0.10% या अधिक","0.04% या अधिक"],"explanation":"वेस्ट वर्जीनिया CMV अल्कोहल सीमा 0.04% (\"भार के अनुसार एक प्रतिशत का चार सौवां या अधिक\") निर्धारित करता है, जो व्यक्तिगत वाहनों के लिए 0.08% सीमा का आधा है। स्रोत: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)(2)।"},"41":{"q":"वेस्ट वर्जीनिया में, 0.04% से कम किसी भी पता लगाने योग्य मात्रा में अल्कोहल पाए जाने वाले CMV चालक को:","options":["तुरंत 1 year के लिए अयोग्य कर दिया जाना चाहिए","24 hours के लिए आउट-ऑफ-सर्विस रखा जाना चाहिए","किसी आउट-ऑफ-सर्विस अवधि के बिना $2,500 का जुर्माना लगाया जाना चाहिए","बिना किसी दंड के केवल एक चेतावनी जारी की जानी चाहिए"],"explanation":"0.04% से कम किसी भी पता लगाने योग्य मापनीय अल्कोहल वाले CMV चालक को 24 hours के लिए आउट-ऑफ-सर्विस रखा जाता है, भले ही यह अयोग्यता वाली 0.04% सीमा से कम हो। स्रोत: WV CDL Manual Section 1.3 और Implied Consent provisions; WV Code 17E-1-13।"},"42":{"q":"वेस्ट वर्जीनिया में किसी CMV चालक के पहले प्रमुख अपराध, जैसे DUI या 0.04% BAC, के लिए अयोग्यता अवधि क्या है, जब प्लेकार्ड वाली खतरनाक सामग्री का परिवहन नहीं किया जा रहा हो?","options":["60 days","3 years","1 year","6 months"],"explanation":"पहला प्रमुख अपराध (DUI, 0.04% BAC, इनकार, घटनास्थल छोड़ना, किसी अपराध में वाहन का उपयोग करना, आदि) के परिणामस्वरूप वेस्ट वर्जीनिया में 1-year की CDL अयोग्यता होती है। स्रोत: WV CDL Manual, Disqualification Offenses; WV Code 17E-1-13(b)।"},"43":{"q":"यदि कोई वेस्ट वर्जीनिया CMV चालक प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करते समय पहला प्रमुख अपराध करता है, तो अयोग्यता अवधि है:","options":["3 years","1 year","5 years","180 days"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री (49 CFR Part 172, Subpart F के अनुसार) का परिवहन करने वाले CMV को चलाते समय किया गया पहला प्रमुख अपराध 1 year के बजाय 3 years की बढ़ी हुई अयोग्यता वहन करता है। स्रोत: WV CDL Manual; WV Code 17E-1-13(b)(1)(C)।"},"44":{"q":"वेस्ट वर्जीनिया में दूसरे प्रमुख अपराध (एक अलग घटना में) के लिए अयोग्यता अवधि क्या है?","options":["10 years","आजीवन","3 years","5 years"],"explanation":"एक अलग घटना में दूसरा प्रमुख अपराध वेस्ट वर्जीनिया में आजीवन CDL अयोग्यता का परिणाम होता है। DMV कुछ शर्तों के तहत न्यूनतम अवधि के बाद पुनर्बहाली की अनुमति दे सकता है, लेकिन इसे आजीवन अयोग्यता के रूप में लगाया जाता है। स्रोत: WV CDL Manual; WV Code 17E-1-13(b)(1)(D)।"},"45":{"q":"वेस्ट वर्जीनिया में, CMV चलाते समय एक निर्दिष्ट रासायनिक (द्वितीयक) परीक्षण से इनकार करने पर पहली बार इनकार के लिए क्या अयोग्यता होती है?","options":["60 days","1 year","90 days","30 days"],"explanation":"परीक्षण से इनकार को एक प्रमुख अपराध की तरह माना जाता है: पहली बार इनकार चालक को 1 year के लिए अयोग्य कर देता है (प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करने पर 3 years), और दूसरी बार आजीवन अयोग्यता का परिणाम होता है। स्रोत: WV CDL Manual; WV Code 17E-1-13(b)(3)।"},"46":{"q":"वेस्ट वर्जीनिया के Implied Consent Law के तहत, राज्य में ड्राइविंग के विशेषाधिकार को स्वीकार करके, एक चालक को किसके लिए सहमति दी हुई माना जाता है?","options":["किसी भी ट्रैफ़िक स्टॉप पर वाहन की तलाशी","एक अनिवार्य DUI शिक्षा पाठ्यक्रम","यादृच्छिक सड़क किनारे ड्रग-डॉग निरीक्षण","उनके शरीर में अल्कोहल की मात्रा निर्धारित करने के लिए एक रासायनिक परीक्षण"],"explanation":"वेस्ट वर्जीनिया का Implied Consent Law का अर्थ है कि कोई भी व्यक्ति जो राज्य में ड्राइव करता है, उसने अल्कोहल की मात्रा के लिए निर्दिष्ट रासायनिक परीक्षण लेने के लिए सहमति दी है। इनकार करने पर ड्राइविंग विशेषाधिकार कम से कम 1 year, आजीवन तक के लिए निलंबित हो जाते हैं। स्रोत: WV CDL Manual, Implied Consent Law; WV Code 17C-5-4।"},"47":{"q":"वेस्ट वर्जीनिया के Implied Consent Law के तहत, रासायनिक परीक्षण से इनकार करने पर चालक के मोटर वाहन चलाने के विशेषाधिकार को कितनी न्यूनतम अवधि के लिए निलंबित कर दिया जाता है?","options":["कम से कम 90 days","कम से कम 30 days","कम से कम 1 year","कम से कम 6 months"],"explanation":"वेस्ट वर्जीनिया के Implied Consent Law के तहत निर्दिष्ट रासायनिक परीक्षण से इनकार करने पर मोटर वाहन चलाने के विशेषाधिकार को कम से कम 1 year, और आजीवन तक की अवधि के लिए निलंबित कर दिया जाता है। स्रोत: WV CDL Manual, Implied Consent Law।"},"48":{"q":"वेस्ट वर्जीनिया में 3-year की अवधि के भीतर कितने गंभीर ट्रैफ़िक उल्लंघन 60 days की अयोग्यता शुरू करते हैं?","options":["1 (पहला उल्लंघन)","3 (3 years के भीतर तीसरा)","2 (3 years के भीतर दूसरा)","4 (3 years के भीतर चौथा)"],"explanation":"3-year की अवधि के भीतर दूसरा गंभीर ट्रैफ़िक उल्लंघन 60-day की अयोग्यता का परिणाम होता है। अकेला पहला गंभीर उल्लंघन अयोग्य नहीं करता। स्रोत: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)।"},"49":{"q":"वेस्ट वर्जीनिया में 3-year की अवधि के भीतर तीसरे गंभीर ट्रैफ़िक उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["120 days","60 days","1 year","90 days"],"explanation":"3-year की अवधि के भीतर तीसरा या उसके बाद का गंभीर ट्रैफ़िक उल्लंघन 120-day की अयोग्यता का परिणाम होता है। स्रोत: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)।"},"50":{"q":"निम्नलिखित में से किसे वेस्ट वर्जीनिया CDL अयोग्यता उद्देश्यों के लिए \"गंभीर ट्रैफ़िक उल्लंघन\" के रूप में वर्गीकृत किया गया है?","options":["निर्धारित सीमा से 5 mph अधिक गाड़ी चलाना","अत्यधिक गति (निर्धारित सीमा से 15 mph या अधिक)","एक पार्किंग उल्लंघन","एक समाप्त पंजीकरण स्टिकर"],"explanation":"गंभीर ट्रैफ़िक उल्लंघनों में अत्यधिक गति (निर्धारित सीमा से 15 mph या अधिक), लापरवाह ड्राइविंग, अनुचित या अनियमित लेन परिवर्तन, बहुत पास से पीछा करना, और गाड़ी चलाते समय टेक्स्टिंग शामिल हैं। पार्किंग उल्लंघन शामिल नहीं हैं। स्रोत: WV CDL Manual Section 1.3.3; WV Code 17E-1-13(c)।"},"51":{"q":"वेस्ट वर्जीनिया में, गैर-खतरनाक माल ले जाने वाले CMV को चलाते समय आउट-ऑफ-सर्विस आदेश के उल्लंघन के पहले दोषसिद्धि के लिए अयोग्यता अवधि क्या है?","options":["90 days","60 days","180 days","1 year"],"explanation":"CMV चलाते समय आउट-ऑफ-सर्विस आदेश के उल्लंघन के लिए पहली दोषसिद्धि वेस्ट वर्जीनिया में 180-day की अयोग्यता का परिणाम होती है। स्रोत: WV CDL Manual; WV Code 17E-1-13(e)(1)(A)।"},"52":{"q":"वेस्ट वर्जीनिया में गैर-खतरनाक सामग्री का परिवहन करते समय 10-year की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["180 days","2 years","3 years","1 year"],"explanation":"10 years के भीतर एक अलग घटना में दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन (गैर-खतरनाक) 2-year की अयोग्यता का परिणाम होता है। 10 years के भीतर तीसरा या उसके बाद का 3 years का परिणाम होता है। स्रोत: WV CDL Manual; WV Code 17E-1-13(e)(1)(B)।"},"53":{"q":"वेस्ट वर्जीनिया में, प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करते समय अथवा 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाते समय 10 years के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन का परिणाम क्या अयोग्यता होती है?","options":["2 years","180 days","1 year","3 years"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री का परिवहन करते समय या 16+ यात्रियों को ले जाते समय 10 years के भीतर दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन एक बढ़ी हुई 3-year की अयोग्यता वहन करता है (गैर-खतरनाक के लिए 2 years के मुकाबले)। स्रोत: WV CDL Manual; WV Code 17E-1-13(e)(2)(B)।"},"54":{"q":"वेस्ट वर्जीनिया में CMV चलाते समय पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["30 days","120 days","60 days","180 days"],"explanation":"CMV चलाते समय पहला रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन वेस्ट वर्जीनिया में 60-day की अयोग्यता का परिणाम होता है। स्रोत: WV CDL Manual; WV Code 17E-1-13(d)।"},"55":{"q":"वेस्ट वर्जीनिया में, रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघनों के लिए अयोग्यता अवधि पहले अपराध के लिए 60 days से बढ़कर 3 years के भीतर दूसरे और तीसरे अपराध के लिए क्या हो जाती है?","options":["दूसरे के लिए 120 days; तीसरे के लिए 1 year","दूसरे के लिए 90 days; तीसरे के लिए 180 days","दूसरे के लिए 60 days; तीसरे के लिए 120 days","दूसरे के लिए 180 days; तीसरे के लिए 2 years"],"explanation":"रेलरोड क्रॉसिंग उल्लंघन चालक को 60 days (पहला), 120 days (3 years के भीतर दूसरा), और 1 year (3 years के भीतर तीसरा या उसके बाद का) के लिए अयोग्य करते हैं। स्रोत: WV CDL Manual; WV Code 17E-1-13(d)।"},"56":{"q":"राज्य द्वारा अपनाए गए वेस्ट वर्जीनिया और संघीय नियमों के तहत, CMV चलाते समय टेक्स्टिंग के लिए कितनी दोषसिद्धियों के बाद किसी CMV चालक का CDL अयोग्य हो जाता है?","options":["1 दोषसिद्धि (पहला अपराध)","3 years के भीतर 4 या अधिक दोषसिद्धियां","5 years के भीतर 3 या अधिक दोषसिद्धियां","3 years के भीतर 2 या अधिक दोषसिद्धियां"],"explanation":"CMV चलाते समय टेक्स्टिंग एक गंभीर उल्लंघन है: 3 years के भीतर दूसरी दोषसिद्धि के बाद CDL 60 days के लिए और 3 years के भीतर तीन या अधिक के लिए 120 days के लिए अयोग्य हो जाता है। पहली दोषसिद्धि अयोग्य नहीं करती लेकिन एक नागरिक दंड वहन करती है। स्रोत: WV CDL Manual Section 2.9.5; WV Code 17E-1-13(c)(9)।"},"57":{"q":"गाड़ी चलाते समय टेक्स्ट करने या हैंड-हेल्ड मोबाइल फोन का उपयोग करने वाले CMV चालक के लिए अधिकतम संघीय नागरिक दंड (वेस्ट वर्जीनिया में अपनाया गया) क्या है?","options":["$2,750 तक","$500 तक","$11,000 तक","$5,000 तक"],"explanation":"प्रत्येक टेक्स्टिंग/हैंड-हेल्ड फोन उल्लंघन CMV चालक को $2,750 तक के नागरिक दंड के अधीन करता है। (जो नियोक्ता इसकी अनुमति देते हैं या इसकी मांग करते हैं उन पर $11,000 तक का जुर्माना लगाया जा सकता है।) स्रोत: WV CDL Manual Sections 2.9.4 और 2.9.5।"},"58":{"q":"एक वेस्ट वर्जीनिया CDL धारक जिसका व्यक्तिगत-वाहन लाइसेंस अल्कोहल, नियंत्रित-पदार्थ, या अपराध उल्लंघन के लिए निलंबित किया गया है, वह पहले उल्लंघन पर कितने समय के लिए CDL विशेषाधिकार खो देता है?","options":["1 year","60 days","90 days","6 months"],"explanation":"यदि किसी CDL धारक के व्यक्तिगत-वाहन विशेषाधिकार अल्कोहल, नियंत्रित-पदार्थ, या अपराध उल्लंघन के लिए रद्द, निरस्त, या निलंबित किए जाते हैं, तो CDL 1 year के लिए खो जाता है; दूसरा ऐसा उल्लंघन (व्यक्तिगत वाहन या CMV) आजीवन हानि का परिणाम होता है। स्रोत: WV CDL Manual Section 1.3; WV Code 17E-1-13(b)।"},"59":{"q":"वेस्ट वर्जीनिया के चालक पॉइंट सिस्टम के तहत, कितने पॉइंट तक पहुंचने पर ड्राइविंग विशेषाधिकार निलंबित हो जाते हैं?","options":["6 या अधिक पॉइंट","20 या अधिक पॉइंट","8 या अधिक पॉइंट","12 या अधिक पॉइंट"],"explanation":"वेस्ट वर्जीनिया DMV पॉइंट सिस्टम 12 या अधिक पॉइंट तक पहुंचने पर ड्राइविंग विशेषाधिकार निलंबित कर देता है। उदाहरण के लिए, सीमा से 20 mph या अधिक गति 6 पॉइंट है, और लापरवाह ड्राइविंग 6 पॉइंट है। स्रोत: WV CDL Manual / WV Driver's Licensing Handbook, Point System।"},"60":{"q":"वेस्ट वर्जीनिया के एक अविभाजित (NONDIVIDED) राजमार्ग पर, जब आप चमकती रोशनी दिखा रहे किसी रुके हुए आपातकालीन या सेवा वाहन से सुरक्षित रूप से लेन बदलकर दूर नहीं जा सकते, तो राज्य के Move Over कानून के तहत आप उसे अधिकतम किस गति से पार कर सकते हैं?","options":["15 mph","25 mph","10 mph","20 mph"],"explanation":"वेस्ट वर्जीनिया Code 17C-14-9a (Move Over कानून) के अनुसार जो चालक लेन नहीं बदल सकता, उसे किसी स्थिर अधिकृत आपातकालीन या सेवा वाहन को पार करते समय किसी भी अविभाजित राजमार्ग या सड़क पर गति को घटाकर सुरक्षित स्तर पर लाना होगा जो 15 mph से अधिक न हो। स्रोत: WV Code 17C-14-9a।"},"61":{"q":"वेस्ट वर्जीनिया के एक विभाजित (DIVIDED) राजमार्ग पर जहाँ आप सुरक्षित रूप से किसी गैर-निकटवर्ती लेन में नहीं जा सकते, चेतावनी रोशनी दिखा रहे किसी रुके हुए आपातकालीन वाहन को आप अधिकतम किस गति से पार कर सकते हैं?","options":["15 mph","35 mph","25 mph","20 mph"],"explanation":"WV Code 17C-14-9a के तहत जो चालक लेन बदलने में असमर्थ है, उसे किसी स्थिर आपातकालीन या सेवा वाहन को पार करते समय किसी भी विभाजित राजमार्ग पर गति को घटाकर सुरक्षित स्तर पर लाना होगा जो 25 mph से अधिक न हो। स्रोत: WV Code 17C-14-9a।"},"62":{"q":"वेस्ट वर्जीनिया CDL मैनुअल के अनुसार, एक प्लेकार्ड लगा HazMat वाहन, क्लोरीन भार, या एक कार्गो टैंक को रेलमार्ग क्रॉसिंग पर सबसे नज़दीकी रेल से कितनी दूरी पर रुकना चाहिए?","options":["10 और 25 फीट के बीच","15 और 50 फीट के बीच","5 और 15 फीट के बीच","25 और 75 फीट के बीच"],"explanation":"WV CDL मैनुअल (Section 9.6.12) कहता है कि जिस वाहन पर प्लेकार्ड लगा है, जो किसी भी मात्रा में क्लोरीन ले जाता है, या जिसमें खतरनाक पदार्थों के लिए उपयोग किए जाने वाले कार्गो टैंक हैं, उसे सबसे नज़दीकी रेल से 15 से 50 फीट पहले रुकना चाहिए। स्रोत: WV CDL मैनुअल, Sec. 9.6.12।"},"63":{"q":"वेस्ट वर्जीनिया में एक बस चालक को रेलमार्ग क्रॉसिंग से कितनी दूरी पहले बस रोकनी चाहिए?","options":["20 और 40 फीट के बीच","कम से कम 50 फीट","10 और 30 फीट के बीच","15 और 50 फीट के बीच"],"explanation":"WV CDL मैनुअल (Section 4.3.5) बस चालकों को निर्देश देता है कि वे रेलमार्ग क्रॉसिंग से 15 और 50 फीट के बीच बस रोकें, फिर ट्रेनों के लिए दोनों दिशाओं में सुनें और देखें। स्रोत: WV CDL मैनुअल, Sec. 4.3.5।"},"64":{"q":"जब तक अन्यथा न दर्शाया गया हो, वेस्ट वर्जीनिया के एक इंटरस्टेट राजमार्ग पर अधिकतम निर्धारित गति सीमा क्या है?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"WV CDL मैनुअल की निर्दिष्ट-गति तालिका इंटरस्टेट राजमार्गों को 70 mph पर सूचीबद्ध करती है (जब तक अन्यथा न दर्शाया गया हो)। स्रोत: WV CDL मैनुअल, निर्दिष्ट गति तालिका; WV Code 17C-6-1।"},"65":{"q":"जब तक अन्यथा न दर्शाया गया हो, वेस्ट वर्जीनिया के व्यावसायिक या आवासीय क्षेत्र में अधिकतम गति सीमा क्या है?","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"वेस्ट वर्जीनिया किसी भी व्यावसायिक या आवासीय जिले में 25 mph की अधिकतम सीमा निर्धारित करता है, जैसा कि WV CDL मैनुअल की निर्दिष्ट-गति तालिका में दिखाया गया है। स्रोत: WV Code 17C-6-1; WV CDL मैनुअल।"},"66":{"q":"वेस्ट वर्जीनिया के एक स्कूल ज़ोन में जब बच्चे मौजूद हों, तब अधिकतम गति सीमा क्या है?","options":["20 mph","25 mph","15 mph","10 mph"],"explanation":"WV Code 17C-6-1 स्कूल ज़ोन में अवकाश (recess) के दौरान या जब बच्चे स्कूल जा रहे हों या स्कूल से निकल रहे हों, तब 15 mph निर्धारित करता है; WV CDL मैनुअल में भी यही आंकड़ा सूचीबद्ध है। स्रोत: WV Code 17C-6-1; WV CDL मैनुअल।"},"67":{"q":"वेस्ट वर्जीनिया में एक खुले देहाती राजमार्ग पर (जो इंटरस्टेट या नियंत्रित-पहुँच सड़क नहीं है), जब तक अन्यथा न दर्शाया गया हो, डिफ़ॉल्ट अधिकतम गति सीमा क्या है?","options":["60 mph","65 mph","50 mph","55 mph"],"explanation":"WV CDL मैनुअल की निर्दिष्ट-गति तालिका खुले राजमार्गों को 55 mph पर सूचीबद्ध करती है जब तक अन्यथा न दर्शाया गया हो, जो WV Code 17C-6-1 के अनुरूप है। स्रोत: WV Code 17C-6-1; WV CDL मैनुअल।"},"68":{"q":"वेस्ट वर्जीनिया Code 17C-12-7 के तहत, जब आप किसी रुके हुए स्कूल बस से मिलते हैं या उसे पार करते हैं जिसकी चेतावनी संकेत रोशनी बच्चों को चढ़ाने या उतारने के लिए चमक रही हो, तो आपको:","options":["बस तक पहुँचने से पहले रुकना चाहिए और तब तक आगे नहीं बढ़ना चाहिए जब तक रोशनी बंद न हो या चालक संकेत न दे","10 mph तक धीमा करें और सावधानी से पार करें","केवल तभी रुकें जब आप बस के समान दिशा में यात्रा कर रहे हों","दूर वाली लेन में जाएँ और घटी हुई गति से जारी रखें"],"explanation":"WV Code 17C-12-7 के अनुसार किसी भी दिशा से चमकती चेतावनी रोशनी वाली स्कूल बस से मिलने या उसे पार करने वाले चालक को बस तक पहुँचने से पहले रुकना होगा और तब तक आगे नहीं बढ़ना होगा जब तक बस आगे न बढ़े, रोशनी बंद न हो, या बस चालक संकेत न दे। स्रोत: WV Code 17C-12-7।"},"69":{"q":"वेस्ट वर्जीनिया के स्कूल-बस कानून के तहत, किस प्रकार के मार्ग पर एक चालक को उस स्कूल बस के लिए रुकना नहीं पड़ता जो किसी अलग मार्ग पर है जहाँ पैदल चलने वालों को पार करने की अनुमति नहीं है?","options":["कोई भी चार-लेन राजमार्ग","केंद्र मोड़ लेन वाली कोई भी सड़क","एक नियंत्रित-पहुँच राजमार्ग","रंगे हुए मध्यभाग वाली एक दो-लेन सड़क"],"explanation":"WV Code 17C-12-7 प्रावधान करता है कि नियंत्रित-पहुँच राजमार्ग पर चालक को किसी अलग मार्ग पर, या राजमार्ग से सटी हुई, स्कूल बस के लिए रुकने की आवश्यकता नहीं है, जहाँ पैदल चलने वालों को पार करने की अनुमति नहीं है। एक मात्र रंगी हुई रेखा या केंद्र लेन इस अपवाद को सक्रिय नहीं करती। स्रोत: WV Code 17C-12-7।"},"70":{"q":"वेस्ट वर्जीनिया राजमार्ग के किनारे पर एक व्यावसायिक वाहन रोकने के बाद, आपको कितने मिनट के भीतर अपने आपातकालीन चेतावनी उपकरण रखने चाहिए?","options":["5 मिनट","10 मिनट","15 मिनट","30 मिनट"],"explanation":"WV CDL मैनुअल कहता है कि यदि आपको किसी सड़क या किनारे पर रुकना पड़े तो आपको अपने आपातकालीन चेतावनी उपकरण दस मिनट के भीतर रखने चाहिए। स्रोत: WV CDL मैनुअल, Sec. 2.5।"},"71":{"q":"जब किसी एक-तरफ़ा (ONE-WAY) या विभाजित (DIVIDED) वेस्ट वर्जीनिया राजमार्ग पर रुके हों, तो तीन परावर्तक त्रिकोण कहाँ रखे जाने चाहिए?","options":["आगे और पीछे 10 फीट, 100 फीट, और 100 फीट पर","पीछे की ओर 50 फीट, 100 फीट, और 500 फीट पर","आने वाले यातायात की ओर 10 फीट, 50 फीट, और 150 फीट पर","आने वाले यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर"],"explanation":"WV CDL मैनुअल निर्देश देता है कि एक-तरफ़ा या विभाजित राजमार्ग पर चेतावनी उपकरण वाहन से आने वाले यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर रखे जाएँ। स्रोत: WV CDL मैनुअल, Sec. 2.5।"},"72":{"q":"यदि किसी वेस्ट वर्जीनिया चालक के पास परावर्तक त्रिकोण नहीं हैं, तो CDL मैनुअल खड़े-वाहन चेतावनी के विकल्प के रूप में किन चेतावनी उपकरणों को स्वीकार करता है?","options":["कम से कम 6 फ़्यूज़ी या 3 तरल-दहन फ्लेयर","कम से कम 2 फ़्यूज़ी या 1 तरल-दहन फ्लेयर","एक अकेला घूमने वाला एम्बर बीकन","कम से कम 4 सड़क शंकु"],"explanation":"WV CDL मैनुअल खड़े वाहनों के लिए चेतावनी उपकरणों के रूप में तीन परावर्तक त्रिकोण या कम से कम 6 फ़्यूज़ी या 3 तरल-दहन फ्लेयर सूचीबद्ध करता है। स्रोत: WV CDL मैनुअल, वाहन-निरीक्षण/आपातकालीन-उपकरण अनुभाग।"},"73":{"q":"वेस्ट वर्जीनिया कुछ प्लेकार्ड वाले भारों के आसपास फ्लेयर या खुली-लौ चेतावनी उपकरणों के उपयोग पर प्रतिबंध क्यों लगाता है?","options":["वे रात में देखे जाने के लिए बहुत मंद हैं","वे केवल विभाजित राजमार्गों पर ही वैध हैं","वे Class 3 ज्वलनशील तरल जैसे ज्वलनशील कार्गो को जला सकते हैं","वे वाहन की बैटरी को खत्म कर देते हैं"],"explanation":"WV CDL मैनुअल का 'No Flares!' नियम कहता है कि Class 3 ज्वलनशील तरल जैसे ज्वलनशील सामग्री ढोने वाले वाहनों के आसपास जलते फ्लेयर या फ़्यूज़ नहीं, बल्कि परावर्तक त्रिकोण या लाल विद्युत रोशनी का उपयोग करें। स्रोत: WV CDL मैनुअल, Sec. 9.6.4।"},"74":{"q":"वेस्ट वर्जीनिया के लेन-उपयोग नियम के तहत, ट्रक यातायात सहित सभी चालकों को सामान्यतः कहाँ चलना चाहिए?","options":["मर्जिंग के लिए दाहिनी लेन को खाली रखने हेतु केंद्र लेन में","सबसे दाहिनी लेन में, सिवाय जब पार करते समय, मुड़ते समय, या रुकावटों से बचते समय हो","जिस लेन में सबसे कम यातायात हो उसमें","बाईं लेन में ताकि दाहिनी लेन धीमे वाहनों के लिए छोड़ी जा सके"],"explanation":"वेस्ट वर्जीनिया (Chapter 17C, Article 7) के अनुसार ट्रकों सहित चालकों को डिफ़ॉल्ट रूप से सबसे दाहिनी लेन में चलना होगा, सिवाय जब आगे निकलते/पार करते हों, जब दाहिनी लेन बंद हो, जब सामान्य यातायात गति से नीचे चल रहे हों, या जब मुड़ने की तैयारी कर रहे हों। स्रोत: WV Code Ch. 17C, Art. 7।"},"75":{"q":"वेस्ट वर्जीनिया के एक तीन-लेन (THREE-lane) राजमार्ग पर, एक ट्रक लेन का उपयोग कैसे कर सकता है?","options":["यह तीनों लेन में से किसी का भी स्वतंत्र रूप से उपयोग कर सकता है","इसे केवल मध्य लेन का उपयोग करना चाहिए","यह बाईं दो लेन का उपयोग कर सकता है और दाहिनी लेन में पार कर सकता है","इसे दाहिनी लेन में रहना चाहिए लेकिन पार करने के लिए मध्य लेन का उपयोग कर सकता है"],"explanation":"वेस्ट वर्जीनिया लेन नियमों के तहत, तीन-लेन मार्ग पर ट्रक दाहिनी लेन तक सीमित हैं लेकिन पार करने के लिए मध्य लेन में जा सकते हैं। स्रोत: WV Code Ch. 17C, Art. 7।"},"76":{"q":"वेस्ट वर्जीनिया के एक चार-लेन (FOUR-lane) राजमार्ग पर, सेमीट्रेलर खींचने वाला एक ट्रक ट्रैक्टर किन लेन का उपयोग कर सकता है?","options":["दाहिनी ओर की दो लेन","केवल सबसे दाहिनी लेन","सबसे बाईं को छोड़कर कोई भी लेन","बाईं ओर की दो लेन"],"explanation":"वेस्ट वर्जीनिया सेमीट्रेलर खींचने वाले ट्रक ट्रैक्टरों को चार-लेन राजमार्ग पर दाहिनी ओर की दो लेन में चलने की अनुमति देता है। स्रोत: WV Code Ch. 17C, Art. 7।"},"77":{"q":"10 फीट या उससे चौड़ी लेन वाले Interstate, US, और WV मार्गों पर वेस्ट वर्जीनिया की कानूनी अधिकतम वाहन चौड़ाई (बिना परमिट के) क्या है?","options":["8 फीट 0 इंच","9 फीट 0 इंच","8 फीट 6 इंच","10 फीट 0 इंच"],"explanation":"WV Division of Highways की कानूनी आकार सीमाएँ Interstate, US, WV, और स्थानीय मार्गों पर जहाँ लेन 10 फीट या उससे अधिक हों, अधिकतम चौड़ाई 8 फीट 6 इंच निर्धारित करती हैं (संकरे स्थानीय मार्गों पर 8 फीट)। स्रोत: WVDOT/Division of Highways Legal Size and Weight Limits।"},"78":{"q":"वेस्ट वर्जीनिया के एक INTERSTATE राजमार्ग पर एक वाहन के लिए कानूनी अधिकतम सकल वजन (बिना परमिट के) क्या है?","options":["65,000 pounds","80,000 pounds","73,280 pounds","90,000 pounds"],"explanation":"इंटरस्टेट राजमार्गों पर वेस्ट वर्जीनिया की कानूनी सकल वजन सीमा 80,000 pounds है (शून्य सहनशीलता); स्थानीय सेवा मार्ग 65,000 pounds तक सीमित हैं। स्रोत: WVDOT Legal Size and Weight Limits।"},"79":{"q":"वेस्ट वर्जीनिया टर्नपाइक (I-77) के बारे में व्यावसायिक चालकों के लिए कौन-सा कथन सही है?","options":["ट्रैक्टर-ट्रेलरों को टर्नपाइक से पूरी तरह प्रतिबंधित किया गया है","यह बिना टोल प्लाज़ा वाला एक मुफ्त इंटरस्टेट है","ट्रक इसका उपयोग केवल सूर्योदय और सूर्यास्त के बीच ही कर सकते हैं","यह एक टोल वाला पर्वत-ढलान राजमार्ग है जहाँ ट्रक मेनलाइन प्लाज़ा पर टोल चुकाते हैं"],"explanation":"वेस्ट वर्जीनिया टर्नपाइक I-77 को खड़ी पर्वत ढलानों (लगभग 5% तक) के ऊपर ले जाता है और यह एक टोल सड़क है जिसमें मेनलाइन टोल प्लाज़ा (Ghent, Pax, Chelyan) हैं जहाँ ट्रक आकार/एक्सल के आधार पर टोल चुकाते हैं; इसमें runaway-truck रैंप भी हैं। स्रोत: WV Parkways Authority / WVDOT Turnpike पृष्ठ।"},"80":{"q":"वेस्ट वर्जीनिया में कौन-सी राज्य एजेंसी Commercial Driver's Licenses (CDLs) जारी करती है?","options":["West Virginia Division of Motor Vehicles (DMV)","West Virginia State Police","West Virginia Public Service Commission","West Virginia Division of Highways"],"explanation":"वेस्ट वर्जीनिया में, CDLs को West Virginia Division of Motor Vehicles (DMV) द्वारा जारी किया जाता है, जो ज्ञान परीक्षाएँ संचालित करता है और आवेदनों को संसाधित करता है। स्रोत: WV DMV Commercial Driver's License पृष्ठ (transportation.wv.gov/DMV/Motor-Carriers/CDL)।"},"81":{"q":"वेस्ट वर्जीनिया द्वारा एक पूर्ण CDL जारी करने से पहले, एक आवेदक को सबसे पहले कौन-सा प्रमाणपत्र प्राप्त करना और धारण करना चाहिए?","options":["एक Commercial Learner's Permit (CLP)","एक Class D ऑपरेटर लाइसेंस समर्थन","एक संघीय इंटरस्टेट संचालन प्राधिकरण","एक अस्थायी हार्डशिप ड्राइविंग परमिट"],"explanation":"वेस्ट वर्जीनिया के अनुसार आवेदकों को सबसे पहले DMV से एक Commercial Learner's Permit (CLP) प्राप्त करना होगा, जो कौशल परीक्षा से पहले पर्यवेक्षित अभ्यास को अधिकृत करता है। स्रोत: WV DMV CDL पृष्ठ।"},"82":{"q":"वेस्ट वर्जीनिया में, CDL रोड स्किल्स टेस्ट देने के लिए पात्र होने से पहले एक आवेदक को कितने समय तक Commercial Learner's Permit (CLP) धारण करना चाहिए?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"वेस्ट वर्जीनिया (संघीय मानक का पालन करते हुए) के अनुसार आवेदक द्वारा रोड स्किल्स टेस्ट देने से पहले CLP को न्यूनतम 14 दिन तक धारण करना आवश्यक है। स्रोत: WV DMV CDL पृष्ठ; WV में अपनाए गए अनुसार 49 CFR 383.25।"},"83":{"q":"व्यावसायिक संचालन के प्रकार को स्व-प्रमाणित (self-certifying) करते समय, एक वेस्ट वर्जीनिया CDL/CLP आवेदक को कितनी श्रेणियों में से चुनना चाहिए?","options":["चार श्रेणियाँ","दो श्रेणियाँ","तीन श्रेणियाँ","पाँच श्रेणियाँ"],"explanation":"वेस्ट वर्जीनिया के अनुसार आवेदकों को व्यावसायिक मोटर वाहन संचालन की चार श्रेणियों में से एक के लिए स्व-प्रमाणित करना होगा: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। स्रोत: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3)।"},"84":{"q":"किस वेस्ट वर्जीनिया स्व-प्रमाणन श्रेणी के लिए चालक को एक वैध DOT Medical Examiner's Certificate फ़ाइल में बनाए रखना आवश्यक है?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)","केवल राज्य के भीतर संचालन करने वाला कोई भी चालक छूट प्राप्त है"],"explanation":"जो चालक non-excepted स्थिति (NI या NA) के लिए स्व-प्रमाणन करते हैं उन्हें एक वैध FMCSA Medical Examiner's Certificate बनाए रखना होगा; excepted स्थितियाँ (EI, EA) उस आवश्यकता से छूट प्राप्त हैं। स्रोत: WV DMV Medical Self-Certification Affidavit (Form DMV-CDL-3); FMCSA 49 CFR 383.71।"},"85":{"q":"June 23, 2025 से प्रभावी, एक वेस्ट वर्जीनिया non-excepted CDL चालक की DOT चिकित्सा जानकारी सामान्यतः DMV को कैसे प्रदान की जाती है?","options":["प्रमाणित चिकित्सा परीक्षक परीक्षा परिणामों को एक सुरक्षित इलेक्ट्रॉनिक डेटाबेस में दर्ज करता है जो DMV को प्रेषित होता है","चालक प्रत्येक परीक्षा के बाद DMV को एक कागज़ी चिकित्सा कार्ड डाक से भेजता है","चालक का नियोक्ता चिकित्सा कार्ड को DMV को फ़ैक्स करता है","चिकित्सा कार्ड केवल लाइसेंस नवीनीकरण के समय सत्यापित किया जाता है"],"explanation":"June 23, 2025 से, वेस्ट वर्जीनिया अब कागज़ी चिकित्सा प्रमाणपत्र स्वीकार नहीं करता; प्रमाणित चिकित्सा परीक्षक परीक्षा परिणामों को इलेक्ट्रॉनिक रूप से एक सुरक्षित डेटाबेस में दर्ज करता है जो DMV को भेजा जाता है। स्रोत: बेहतर CDL चिकित्सा प्रमाणन प्रक्रिया पर WV DMV घोषणा (June 2025)।"},"86":{"q":"एक वेस्ट वर्जीनिया CDL ज्ञान (लिखित) परीक्षा पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["80 प्रतिशत","70 प्रतिशत","75 प्रतिशत","90 प्रतिशत"],"explanation":"वेस्ट वर्जीनिया के अनुसार CDL ज्ञान परीक्षा उत्तीर्ण करने के लिए कम से कम 80 प्रतिशत सही होना आवश्यक है। स्रोत: WV Commercial Driver's License मैनुअल; WV DMV CDL परीक्षण नियम।"},"87":{"q":"वेस्ट वर्जीनिया CDL कौशल परीक्षा किन तीन भागों से क्रम में बनी है?","options":["यात्रा-पूर्व वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","लिखित ज्ञान, दृष्टि जाँच, और सड़क पर ड्राइविंग","एयर ब्रेक जाँच, कपलिंग परीक्षण, और प्रतिक्रिया-समय परीक्षण","बैकिंग पैंतरेबाज़ी, राजमार्ग मर्ज, और समानांतर पार्किंग"],"explanation":"वेस्ट वर्जीनिया CDL कौशल परीक्षा में तीन भाग होते हैं: यात्रा-पूर्व वाहन निरीक्षण, बुनियादी वाहन नियंत्रण कौशल परीक्षा, और सड़क पर ड्राइविंग परीक्षा। स्रोत: WV Commercial Driver's License मैनुअल (Skills Test अनुभाग)।"},"88":{"q":"वेस्ट वर्जीनिया CDL कौशल (रोड) परीक्षा के लिए उपयोग किया जाने वाला वाहन किसे प्रदान करना चाहिए?","options":["आवेदक, जिसे परीक्षण की जा रही श्रेणी का एक प्रतिनिधि वाहन उपलब्ध कराना होगा","DMV, जो एक मानक परीक्षण ट्रक प्रदान करता है","Division of Highways मोटर पूल","यात्री कार सहित कोई भी वाहन स्वीकार्य है"],"explanation":"आवेदक को कौशल परीक्षा के लिए वाहन प्रदान करना होगा, और यह उस CDL श्रेणी का प्रतिनिधि होना चाहिए जिसके लिए आवेदक परीक्षण दे रहा है। स्रोत: WV Commercial Driver's License मैनुअल; WV DMV CDL पृष्ठ।"},"89":{"q":"एक पहली बार के वेस्ट वर्जीनिया CDL आवेदक को कौन-सी परीक्षा देने से पहले Entry-Level Driver Training (ELDT) पूरा करना चाहिए?","options":["CDL कौशल (रोड) परीक्षा","दृष्टि जाँच","Class D नवीनीकरण परीक्षा","फ़िंगरप्रिंट पृष्ठभूमि जाँच"],"explanation":"पहली बार के Class A/B आवेदकों और कुछ समर्थनों के लिए CDL कौशल परीक्षा से पहले ELDT (सिद्धांत और पहिये के पीछे) पूरा किया जाना चाहिए। स्रोत: WV DMV CDL पृष्ठ; FMCSA ELDT नियम (49 CFR Part 380), February 7, 2022 से प्रभावी।"},"90":{"q":"वेस्ट वर्जीनिया में लागू संघीय ELDT नियम के तहत, एक चालक को 'पहली बार' का CDL आवेदक माना जाता है (और उसे ELDT पूरा करना होगा) यदि उसने किस तारीख से पहले कभी CDL धारण नहीं किया था?","options":["February 7, 2022","January 1, 2020","October 1, 2021","June 23, 2025"],"explanation":"ELDT आवश्यकताएँ पूर्वव्यापी नहीं हैं: जिस व्यक्ति ने February 7, 2022 से पहले कभी CDL (या संबंधित S, P, या H समर्थन) धारण नहीं किया था, वह एक पहली बार का आवेदक है जिसे ELDT पूरा करना होगा। स्रोत: WV DMV CDL पृष्ठ; FMCSA ELDT अंतिम नियम।"},"91":{"q":"प्रशिक्षण को CDL पात्रता की ओर गिने जाने के लिए एक वेस्ट वर्जीनिया ELDT प्रशिक्षण प्रदाता को कहाँ सूचीबद्ध होना चाहिए?","options":["FMCSA Training Provider Registry (TPR) पर","केवल West Virginia DMV विक्रेता सूची पर","राज्य Division of Highways ठेकेदार सूची पर","National CDL Examiner Directory पर"],"explanation":"ELDT को वेस्ट वर्जीनिया में CDL आवश्यकता को संतुष्ट करने के लिए FMCSA Training Provider Registry (TPR) पर सूचीबद्ध प्रदाता के माध्यम से पूरा किया जाना चाहिए। स्रोत: WV DMV CDL पृष्ठ; FMCSA TPR (tpr.fmcsa.dot.gov)।"},"92":{"q":"वेस्ट वर्जीनिया में, इंट्रास्टेट (केवल राज्य के भीतर) संचालन के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"इंट्रास्टेट संचालन के लिए एक वेस्ट वर्जीनिया CDL प्राप्त करने हेतु आवेदक की आयु कम से कम 18 वर्ष होनी चाहिए; इंटरस्टेट संचालन और खतरनाक पदार्थों के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: WV DMV CDL पृष्ठ; WV Code Chapter 17E।"},"93":{"q":"वेस्ट वर्जीनिया CDL नियमों के तहत इंटरस्टेट वाणिज्य में व्यावसायिक मोटर वाहन संचालित करने या खतरनाक पदार्थ ढोने के लिए न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"वेस्ट वर्जीनिया के अनुसार इंटरस्टेट संचालन या प्लेकार्ड वाले खतरनाक पदार्थ परिवहन के लिए चालक की आयु कम से कम 21 वर्ष होनी चाहिए; 18-20 वर्ष के लोग इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: WV DMV CDL पृष्ठ; FMCSA 49 CFR 391.11।"},"94":{"q":"वेस्ट वर्जीनिया के मानक 'Drive for Five' चक्र के तहत, एक CDL सामान्यतः कितनी अवधि के लिए वैध होता है?","options":["पाँच वर्ष, जो धारक के उस जन्मदिन पर समाप्त होता है जिस वर्ष उनकी आयु पाँच से विभाज्य हो","चार वर्ष, एक निश्चित नवीनीकरण तिथि पर","जारी होने की तारीख से आठ वर्ष","दो वर्ष, DOT चिकित्सा कार्ड से मेल खाते हुए"],"explanation":"वेस्ट वर्जीनिया CDLs को मानक पाँच-वर्षीय चक्र पर नवीनीकृत किया जाता है, जो आवेदक के उस जन्मदिन पर समाप्त होता है जिस वर्ष आवेदक की आयु समान रूप से पाँच से विभाज्य होती है। स्रोत: WV Code 17E-1-12; WV DMV।"},"95":{"q":"21 वर्ष से कम आयु के चालक को जारी किया गया एक वेस्ट वर्जीनिया CDL किस समय समाप्त होता है?","options":["जिस वर्ष आवेदक 21 वर्ष का होता है, उस वर्ष आवेदक के जन्मदिन के 30 दिन बाद","चालक के 18वें जन्मदिन पर","आयु की परवाह किए बिना जारी होने की तारीख से पाँच वर्ष","21 वर्ष के होते ही तुरंत"],"explanation":"जिस व्यक्ति ने 21 वर्ष की आयु प्राप्त नहीं की है, उसे जारी किया गया एक वेस्ट वर्जीनिया CDL उस वर्ष आवेदक के जन्मदिन के 30 दिन बाद समाप्त होता है जिस वर्ष आवेदक 21 वर्ष का होता है, क्योंकि इंटरस्टेट/hazmat पात्रता 21 वर्ष पर बदल जाती है। स्रोत: WV Code Chapter 17E; WV DMV।"},"96":{"q":"एक वेस्ट वर्जीनिया आवेदक किस दस्तावेज़ का उपयोग उस व्यावसायिक ड्राइविंग के प्रकार को स्व-प्रमाणित करने के लिए करता है जिसे वह करने की अपेक्षा करता है?","options":["WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3)","संघीय Form MCSA-5876 चिकित्सा प्रमाणपत्र","Class D ऑपरेटर लाइसेंस आवेदन","IRP apportioned पंजीकरण फ़ॉर्म"],"explanation":"आवेदक अपने संचालन प्रकार को WV Commercial Driver Licensee Medical Self-Certification Affidavit (Form DMV-CDL-3) पर स्व-प्रमाणित करते हैं; Form MCSA-5876 अलग चिकित्सा परीक्षक का प्रमाणपत्र है। स्रोत: WV DMV CDL फ़ॉर्म।"},"97":{"q":"वेस्ट वर्जीनिया CDL नियमों के तहत एक DOT Medical Examiner's Certificate कितने समय तक वर्तमान (current) माना जाता है?","options":["यदि दो वर्ष से अधिक पुराना हो तो यह वर्तमान नहीं है (और इसे कम अवधि के लिए जारी किया जा सकता है)","यह पाँच वर्ष के लिए वैध है","यह केवल एक वर्ष के लिए वैध है","एक बार फ़ाइल में होने के बाद यह कभी समाप्त नहीं होता"],"explanation":"दो वर्ष से अधिक पुराना Medical Examiner's Certificate वर्तमान नहीं है; एक परीक्षक चालक की स्थिति के आधार पर इसे दो वर्ष के लिए या कम अंतराल के लिए जारी कर सकता है। स्रोत: WV DMV CDL पृष्ठ; FMCSA 49 CFR 391.45।"},"98":{"q":"यदि एक आवश्यक Medical Examiner's Certificate को समाप्त (lapse) होने दिया जाए तो एक वेस्ट वर्जीनिया चालक के CDL विशेषाधिकारों के साथ आम तौर पर क्या होता है?","options":["CDL को डाउनग्रेड कर दिया जाता है जिससे व्यक्ति वैध प्रमाणपत्र फ़ाइल में होने तक व्यावसायिक ड्राइविंग विशेषाधिकार खो देता है","अगले पाँच-वर्षीय नवीनीकरण तक कुछ नहीं बदलता","चालक को स्वचालित रूप से एक excepted चालक के रूप में पुनर्वर्गीकृत किया जाता है","चालक को एक वर्ष का स्वचालित विस्तार मिलता है"],"explanation":"यदि किसी non-excepted चालक का चिकित्सा प्रमाणन समाप्त हो जाता है, तो वेस्ट वर्जीनिया CDL को डाउनग्रेड कर देता है, और एक वर्तमान प्रमाणपत्र प्रदान किए जाने तक व्यावसायिक विशेषाधिकार हटा देता है। स्रोत: WV DMV CDL पृष्ठ; FMCSA 49 CFR 383.73 चिकित्सा प्रमाणन प्रावधान।"},"99":{"q":"वेस्ट वर्जीनिया में, दस्तावेज़ों का कौन-सा सेट CDL के लिए आवेदन करने की मूल आवश्यकता का हिस्सा है?","options":["पहचान/वैध स्थिति का प्रमाण, West Virginia निवास का प्रमाण, Social Security सत्यापन, और पूर्ण CDL आवेदन","केवल एक पासपोर्ट और एक क्रेडिट कार्ड","केवल एक वाहन शीर्षक और बीमा का प्रमाण","एक नियोक्ता पत्र और एक हाई स्कूल डिप्लोमा"],"explanation":"वेस्ट वर्जीनिया CDL आवेदकों को पहचान और अमेरिकी नागरिकता या वैध स्थायी निवास का प्रमाण, West Virginia निवास का प्रमाण, Social Security नंबर सत्यापन, और एक पूर्ण CDL आवेदन (साथ ही चिकित्सा/स्व-प्रमाणन दस्तावेज़) प्रस्तुत करने होंगे। स्रोत: WV DMV CDL पृष्ठ।"}},"ar":{"0":{"q":"على الطرق السريعة في ويست فرجينيا التي يبلغ الحد الأدنى لعرض حارتها عشرة أقدام (بما في ذلك المسارات المخصصة ومسارات الطرق السريعة بين الولايات)، ما هو الحد الأقصى المسموح به للعرض الخارجي للمركبة أو حمولتها؟","options":["8 أقدام (96 إنشًا)","8 أقدام و6 إنشات (102 إنش)","9 أقدام (108 إنشات)","10 أقدام (120 إنشًا)"],"explanation":"بموجب W.Va. Code 17C-17-2، لا يجوز أن يتجاوز العرض الخارجي الإجمالي 96 إنشًا، باستثناء أن المركبة التي يبلغ عرضها 102 إنش (8 أقدام و6 إنشات) يجوز تشغيلها على الطرق السريعة المخصصة من قبل U.S. DOT أو أي طريق سريع يبلغ الحد الأدنى لعرض حارته 10 أقدام. المصدر: W.Va. Code 17C-17-2؛ WV DOT Legal Size and Weight Limits."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك حمولتها، على الطرق السريعة في ويست فرجينيا؟","options":["12 قدمًا و6 إنشات","13 قدمًا","13 قدمًا و6 إنشات","14 قدمًا"],"explanation":"ينص W.Va. Code 17C-17-4 على أن المركبة، بما في ذلك أي حمولة، لا يجوز أن يتجاوز ارتفاعها 13 قدمًا و6 إنشات على أي مسار في ويست فرجينيا. المصدر: W.Va. Code 17C-17-4؛ WV DOT Legal Size and Weight Limits."},"2":{"q":"في ويست فرجينيا، ما هو الحد الأقصى للوزن الإجمالي على محور مفرد؟","options":["18,000 رطل","20,000 رطل","22,400 رطل","34,000 رطل"],"explanation":"تحدّ ويست فرجينيا المحور المفرد بـ 20,000 رطل، بما يتوافق مع المعيار الفيدرالي. المصدر: W.Va. Code 17C-17-8 / 17C-17-9؛ WV DOT Legal Size and Weight Limits."},"3":{"q":"في ويست فرجينيا، ما هو الحد الأقصى للوزن الإجمالي المسموح به على مجموعة محاور مزدوجة؟","options":["20,000 رطل","32,000 رطل","34,000 رطل","40,000 رطل"],"explanation":"تحدّ ويست فرجينيا المحور المزدوج بـ 34,000 رطل، بما يطابق المعيار الفيدرالي لوزن المحور. المصدر: W.Va. Code 17C-17-8a / 17C-17-9؛ WV DOT Legal Size and Weight Limits."},"4":{"q":"ما هو الحد الأقصى القانوني للوزن الإجمالي للمركبة بالنسبة لمركبة أو تشكيلة تعمل على الطريق السريع بين الولايات (الشبكة الوطنية للطرق السريعة بين الولايات وطرق الدفاع) في ويست فرجينيا، في غياب تصريح؟","options":["73,280 رطلًا","80,000 رطل","88,000 رطل","90,000 رطل"],"explanation":"ينص W.Va. Code 17C-17-9 على أن الحد الأقصى للوزن الإجمالي على الشبكة الوطنية للطرق السريعة بين الولايات وطرق الدفاع لا يجوز أن يتجاوز 80,000 رطل (مع مراعاة معادلة الجسر). المصدر: W.Va. Code 17C-17-9."},"5":{"q":"في تشكيلة جرّار شاحنة-نصف مقطورة في ويست فرجينيا، ما هو الحد الأقصى لطول نصف المقطورة المسموح به عند استيفاء شرط المسافة بين محور الارتكاز (kingpin) والمحور الخلفي؟","options":["45 قدمًا","48 قدمًا","53 قدمًا","57 قدمًا"],"explanation":"يحدّ W.Va. Code 17C-17-4 نصف المقطورة بـ 48 قدمًا، لكنه يسمح بما يصل إلى 53 قدمًا حيث لا تزيد المسافة بين المحور الخلفي لجرّار الشاحنة والمحور الأمامي لنصف المقطورة عن 37 قدمًا. المصدر: W.Va. Code 17C-17-4."},"6":{"q":"على الطرق السريعة في ويست فرجينيا التي يقل عرض حاراتها عن 10 أقدام (مثل بعض مسارات الخدمة المحلية)، ما هو الحد الأقصى القانوني لعرض المركبة؟","options":["7 أقدام و6 إنشات","8 أقدام (96 إنشًا)","8 أقدام و6 إنشات","9 أقدام"],"explanation":"ينطبق السماح بـ 102 إنش (8 أقدام و6 إنشات) فقط على المسارات المخصصة أو الحارات التي يبلغ عرضها 10 أقدام أو أكثر؛ وعلى الطرق التي يقل عرض حاراتها عن 10 أقدام يعود العرض إلى حد الـ 96 إنشًا (8 أقدام). المصدر: W.Va. Code 17C-17-2؛ WV DOT Legal Size and Weight Limits."},"7":{"q":"ما هو الحد الأقصى للطول الإجمالي لتشكيلة من المركبات على الطرق السريعة في ويست فرجينيا التي ليست بين الولايات أو من المسارات المخصصة بطريقة أخرى؟","options":["53 قدمًا","55 قدمًا","65 قدمًا","75 قدمًا"],"explanation":"يحدّ W.Va. Code 17C-17-4 تشكيلة من المركبات المقترنة معًا، بما في ذلك المصدّات الأمامية والخلفية، بطول إجمالي قدره 55 قدمًا على الطرق السريعة غير المخصصة. المصدر: W.Va. Code 17C-17-4."},"8":{"q":"ما هو الحد الأقصى للطول الإجمالي الأقصى لمركبة آلية مفردة (شاحنة مستقيمة) في ويست فرجينيا؟","options":["35 قدمًا","40 قدمًا","45 قدمًا","48 قدمًا"],"explanation":"يحدّ W.Va. Code 17C-17-4 المركبة الآلية المفردة، بما في ذلك حمولتها، بـ 40 قدمًا كأقصى بُعد إجمالي (يُسمح بـ 45 قدمًا لبعض المنازل المتنقلة والحافلات المدرسية). المصدر: W.Va. Code 17C-17-4."},"9":{"q":"بموجب اعتماد ويست فرجينيا لأحكام وزن الجسر الفيدرالية، يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما 34,000 رطل بشرط أن تكون المسافة بين المحور الأول والأخير من مجموعتي المحاور المزدوجة المتتاليتين لا تقل عن كم قدمًا؟","options":["30 قدمًا","34 قدمًا","36 قدمًا","40 قدمًا"],"explanation":"يسمح W.Va. Code 17C-17-9 لمجموعتين متتاليتين من المحاور المزدوجة بحمل 34,000 رطل لكل منهما بشرط أن تكون المسافة الإجمالية بين المحور الأول والأخير من مجموعتي المحاور المزدوجة المتتاليتين هذه 36 قدمًا أو أكثر. المصدر: W.Va. Code 17C-17-9."},"10":{"q":"لا يجوز عمومًا إصدار تصريح الوزن الزائد (للرحلة الواحدة) في ويست فرجينيا إلا عندما تستوفي الحمولة أي شرط؟","options":["الحمولة غير قابلة للتجزئة","الناقل مقره في ويست فرجينيا","تحتوي المركبة على ستة محاور أو أكثر","تحدث الرحلة فقط على الطرق السريعة بين الولايات"],"explanation":"تصدر ويست فرجينيا تصاريح الوزن الزائد فقط للحمولات غير القابلة للتجزئة التي لا يمكن تقليلها إلى الحدود القانونية (الحاويات المخصصة للشحن البحري استثناء مذكور). المصدر: WV DOT Division of Highways Hauling Permits / Permit Types."},"11":{"q":"كيف يحصل ناقل آلي على تصريح نقل للحجم الزائد/الوزن الزائد للمسارات المملوكة لولاية ويست فرجينيا؟","options":["شخصيًا فقط في محكمة المقاطعة","من خلال نظام تصاريح النقل عبر الإنترنت التابع لـ West Virginia DOT/Division of Highways","من ثكنات شرطة ولاية ويست فرجينيا","التصاريح غير مطلوبة في ويست فرجينيا"],"explanation":"يتم الحصول على تصاريح الحجم الزائد/الوزن الزائد لمسارات الطرق السريعة بين الولايات والطريق السريع برسوم (Turnpike) ومسارات U.S. وWV والمقاطعات من خلال نظام تصاريح النقل عبر الإنترنت التابع لـ WV DOT Division of Highways. المصدر: WV DOT Hauling Permits؛ wv.gotpermits.com."},"12":{"q":"على مسارات U.S. وWV (غير بين الولايات)، ما هو هامش التسامح في الوزن الذي تطبقه ويست فرجينيا على حدودها القانونية لوزن المحور والوزن الإجمالي؟","options":["لا تسامح (صفر)","5 بالمئة","10 بالمئة","15 بالمئة"],"explanation":"على مسارات U.S. وWV ومسارات الخدمة المحلية، تسمح ويست فرجينيا بهامش تسامح قدره 10 بالمئة فوق حدود الوزن القانونية، في حين أن الطرق السريعة بين الولايات تسمح بتسامح صفري. المصدر: WV DOT Legal Size and Weight Limits."},"13":{"q":"على مسارات الخدمة المحلية في ويست فرجينيا (طرق المقاطعات غير المخصصة)، ما هو الحد الأقصى القانوني للوزن الإجمالي للمركبة قبل أن يُطلب تصريح؟","options":["60,000 رطل","65,000 رطل","73,280 رطلًا","80,000 رطل"],"explanation":"في حين تسمح الطرق السريعة بين الولايات ومسارات U.S./WV بما يصل إلى 80,000 رطل، فإن مسارات الخدمة المحلية في ويست فرجينيا تحمل حدًا قانونيًا أقل للوزن الإجمالي قدره 65,000 رطل. المصدر: WV DOT Legal Size and Weight Limits."},"14":{"q":"ما هو الحد الأقصى للوزن الإجمالي المصرّح به الذي ينطبق على مركبة تعمل بموجب تصريح شامل سنوي للوزن الزائد والحجم الزائد في ويست فرجينيا على مسارات غير الطريق السريع بين الولايات؟","options":["80,000 رطل","90,000 رطل","110,000 رطل","120,000 رطل"],"explanation":"بموجب تصريح سنوي (شامل) للوزن الزائد/الحجم الزائد في ويست فرجينيا، يبلغ الحد الأقصى للوزن الإجمالي 90,000 رطل على المسارات غير بين الولايات (110,000 رطل على الطريق السريع بين الولايات). المصدر: WV DOT Permit Types (Annual/Blanket Permits)."},"15":{"q":"بموجب تصريح سنوي (شامل) للوزن الزائد في ويست فرجينيا، ما هو الحد الأقصى للوزن المصرّح به على محور مزدوج؟","options":["34,000 رطل","40,000 رطل","45,000 رطل","50,000 رطل"],"explanation":"تسمح تصاريح ويست فرجينيا الشاملة للوزن الزائد بما يصل إلى 28,000 رطل على محور مفرد، و45,000 رطل على محور مزدوج، و50,000 رطل على محور ثلاثي. المصدر: WV DOT Permit Types (Annual/Blanket Permits)."},"16":{"q":"على \"طريق نقل موارد الفحم\" المخصص في ويست فرجينيا، يجوز تشغيل مركبة تنقل الفحم بموجب تصريح حتى حد أقصى للوزن الإجمالي يقارب أي رقم؟","options":["80,000 رطل","90,000 رطل","120,000 رطل","150,000 رطل"],"explanation":"بموجب W.Va. Code Chapter 17C, Article 17A، يجوز للمركبات التي تنقل الفحم على طرق نقل موارد الفحم المخصصة أن تعمل بوزن إجمالي أكبر يصل إلى 120,000 رطل (مع تباين 5 بالمئة)، متجاوزةً الحدود الواردة في 17C-17-9. المصدر: W.Va. Code 17C-17A؛ WV PSC coal resource transportation permitting."},"17":{"q":"ما هو الحد الأقصى للوزن المصرّح به على محور مفرد بموجب تصريح سنوي (شامل) للوزن الزائد في ويست فرجينيا؟","options":["20,000 رطل","24,000 رطل","28,000 رطل","34,000 رطل"],"explanation":"يسمح التصريح الشامل للوزن الزائد في ويست فرجينيا بما يصل إلى 28,000 رطل على محور مفرد (مقابل الحد القانوني البالغ 20,000 رطل). المصدر: WV DOT Permit Types (Annual/Blanket Permits)."},"18":{"q":"بالنسبة لتصريح الرحلة الواحدة للحجم الزائد في ويست فرجينيا، خلال أي ساعات لا تكون حركة الحجم الزائد صالحة عمومًا؟","options":["من الغروب إلى الشروق (الليل)","من الظهر إلى الساعة 2 ظهرًا في أيام الأسبوع","في أي وقت يوم الإثنين","فقط خلال ساعة الذروة الصباحية"],"explanation":"لا يكون تصريح الحجم الزائد في ويست فرجينيا صالحًا عمومًا خلال ساعات الليل من الغروب إلى الشروق، ولا يُسمح بأي تنقل في أيام العطل. المصدر: WV DOT Hauling Permits / Permit conditions."},"19":{"q":"شاحنة وحدة مفردة (مستقيمة) في ويست فرجينيا ذات محور توجيه واحد ومجموعة محاور مزدوجة تكون محدودة عمومًا بأي حد أقصى للوزن الإجمالي للمركبة قبل تطبيق هامش التسامح المسموح به؟","options":["48,000 رطل","54,000 رطل","60,000 رطل","66,000 رطل"],"explanation":"شاحنة الوحدة المفردة في ويست فرجينيا ذات محور توجيه واحد ومحورين مزدوجين تكون محدودة بحد أقصى للوزن الإجمالي قدره 60,000 رطل (قبل هامش التسامح البالغ 10 بالمئة على المسارات غير بين الولايات). المصدر: WV DOT Legal Size and Weight Limits."},"20":{"q":"في ويست فرجينيا، أي فئة من رخص CDL مطلوبة لتشغيل تشكيلة من المركبات بتصنيف وزن مجموع للتشكيلة (GCWR) يبلغ 26,001 رطل أو أكثر، حيث يكون للمركبة المقطورة تصنيف وزن إجمالي (GVWR) يزيد عن 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعتمد ويست فرجينيا التصنيف الفيدرالي: تشمل رخصة CDL من الفئة A أي تشكيلة من المركبات بتصنيف GCWR قدره 26,001 رطل أو أكثر، بشرط أن يكون للوحدة المقطورة تصنيف GVWR يتجاوز 10,000 رطل. المصدر: WV DMV Commercial Driver's License page وWV CDL Manual."},"21":{"q":"بموجب قواعد ويست فرجينيا، تتطلب مركبة مفردة بتصنيف GVWR قدره 26,001 رطل أو أكثر (أو مثل هذه المركبة وهي تقطر وحدة لا تتجاوز 10,000 رطل) أي فئة من رخص CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"تُجيز رخصة CDL من الفئة B في ويست فرجينيا قيادة مركبة مفردة بتصنيف GVWR قدره 26,001 رطل أو أكثر، بما في ذلك قطر وحدة بتصنيف GVWR قدره 10,000 رطل أو أقل. المصدر: WV DMV CDL page وWV CDL Manual."},"22":{"q":"يقود سائق في ويست فرجينيا مركبة يقل وزنها عن 26,001 رطل ومصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو تُستخدم لنقل مواد خطرة تتطلب لوحات تحذيرية (placards). أي فئة من رخص CDL تنطبق؟","options":["الفئة A","الفئة B","الفئة C","لا حاجة إلى CDL"],"explanation":"تشمل رخصة CDL من الفئة C المركبات التي لا تستوفي عتبات الوزن للفئة A أو B لكنها مصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو لنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: WV DMV CDL page وWV CDL Manual."},"23":{"q":"أي رمز تصديق (endorsement) على رخصة CDL في ويست فرجينيا يُجيز نقل المواد الخطرة التي تتطلب لوحات تحذيرية؟","options":["N","H","T","X"],"explanation":"يُجيز تصديق 'H' نقل المواد الخطرة ذات اللوحات التحذيرية. الرمز 'X' هو تصديق مركّب يجمع بين الصهريج (Tank) والمواد الخطرة (HazMat). المصدر: WV CDL Manual, Endorsements section."},"24":{"q":"على رخصة CDL في ويست فرجينيا، أي تصديق مطلوب لتشغيل مركبة صهريج تنقل مواد سائلة أو غازية في خزان مثبّت بشكل دائم؟","options":["T (مقطورات مزدوجة/ثلاثية)","N (صهريج)","P (ركاب)","H (مواد خطرة)"],"explanation":"تصديق 'N' (الصهريج) مطلوب لمركبات الصهريج التي تنقل السوائل أو الغازات بالجملة. تصديق 'T' مخصص للمقطورات المزدوجة والثلاثية، وهو تصريح منفصل. المصدر: WV CDL Manual, Endorsements section."},"25":{"q":"يرغب حامل رخصة CDL في ويست فرجينيا في قطر مقطورات مزدوجة أو ثلاثية. أي تصديق يجب إضافته؟","options":["N","S","T","P"],"explanation":"يُجيز تصديق 'T' تشغيل تشكيلات المقطورات المزدوجة والثلاثية ويتطلب اجتياز اختبار معرفي. المصدر: WV CDL Manual, Endorsements section."},"26":{"q":"لنقل الركاب مقابل أجر على حافلة في ويست فرجينيا (على سبيل المثال، حافلة نقل عام أو حافلة سياحية)، أي تصديق CDL مطلوب؟","options":["تصديق S","تصديق P","تصديق N","تصديق H"],"explanation":"تصديق 'P' (الركاب) مطلوب لتشغيل مركبة مصممة لنقل 16 راكبًا أو أكثر ويتطلب كلًا من اختبار معرفي واختبار مهارات على الطريق في مركبة تمثيلية. المصدر: WV CDL Manual, Endorsements section."},"27":{"q":"أي تصديق تتطلبه ويست فرجينيا من السائق لتشغيل حافلة مدرسية، بالإضافة إلى تصديق الركاب (P)؟","options":["تصديق S","تصديق T","تصديق N","تصديق X"],"explanation":"تصديق 'S' (الحافلة المدرسية) مطلوب لقيادة حافلة مدرسية ويُحصل عليه بالإضافة إلى تصديق 'P'؛ ويتطلب اختبارًا معرفيًا واختبار مهارات على الطريق في حافلة مدرسية. المصدر: WV CDL Manual, Endorsements section."},"28":{"q":"ما هو الحد الأدنى للعمر لإصدار رخصة CDL في ويست فرجينيا للقيادة داخل الولاية (التشغيل ضمن ويست فرجينيا فقط)؟","options":["16 عامًا","18 عامًا","21 عامًا","25 عامًا"],"explanation":"يجب أن يكون عمر المتقدم 18 عامًا على الأقل للحصول على رخصة CDL صالحة للتجارة داخل الولاية (ضمن ويست فرجينيا). المصدر: WV CDL Manual / WV DMV CDL requirements."},"29":{"q":"ما هو الحد الأدنى للعمر المطلوب لإصدار رخصة CDL في ويست فرجينيا للقيادة بين الولايات (عبر حدود الولايات)؟","options":["18 عامًا","19 عامًا","21 عامًا","23 عامًا"],"explanation":"تتطلب القواعد الفيدرالية التي اعتمدتها ويست فرجينيا أن يكون عمر السائق 21 عامًا على الأقل لتشغيل مركبة تجارية آلية في التجارة بين الولايات أو لنقل مواد خطرة. المصدر: WV CDL Manual / 49 CFR 391.11 كما تطبقه WV DMV."},"30":{"q":"بعد الحصول على تصريح متعلّم تجاري (CLP) في ويست فرجينيا، كم مدة يجب على المتقدم الاحتفاظ به قبل أن يصبح مؤهلًا لإجراء اختبار مهارات القيادة على الطريق لرخصة CDL؟","options":["14 يومًا كحد أدنى","30 يومًا كحد أدنى","7 أيام كحد أدنى","60 يومًا كحد أدنى"],"explanation":"يتطلب القانون الفيدرالي الذي اعتمدته ويست فرجينيا أن يحتفظ المتقدم بتصريح CLP لمدة 14 يومًا على الأقل قبل إجراء اختبار المهارات (على الطريق). المصدر: WV DMV CDL page؛ 49 CFR 383.25."},"31":{"q":"فيما يتعلق بالتجديد، أي عبارة تصف على أفضل وجه تصريح المتعلّم التجاري (CLP) في ويست فرجينيا؟","options":["غير قابل للتجديد ولا يجوز أن تتجاوز صلاحيته عامًا واحدًا","يمكن تجديده عددًا غير محدود من المرات","صالح لمدة خمس سنوات مثل الرخصة العادية","لا تنتهي صلاحيته أبدًا بمجرد إصداره"],"explanation":"تنص صفحة WV DMV CDL على أن تصريح المتعلّم التجاري لا يجوز أن تتجاوز صلاحيته عامًا واحدًا وأنه غير قابل للتجديد. المصدر: WV DMV Commercial Driver's License page."},"32":{"q":"أثناء قيادة مركبة تجارية آلية بموجب تصريح CLP في ويست فرجينيا، يجب أن يكون حامل التصريح مصحوبًا بأي مما يلي؟","options":["حامل رخصة CDL صالحة لذلك النوع من المركبات، جالسًا بجانب السائق","أي سائق مرخّص يزيد عمره عن 21 عامًا في أي مقعد من المركبة","فاحص DMV فقط","لا أحد؛ يسمح تصريح CLP بالقيادة المنفردة"],"explanation":"يجوز لحامل تصريح CLP تشغيل مركبة تجارية آلية فقط عندما يكون مصحوبًا بحامل رخصة CDL صالحة لتلك الفئة/النوع من المركبات يشغل المقعد المجاور لحامل التصريح. المصدر: WV DMV CDL page؛ 49 CFR 383.25."},"33":{"q":"ما هو الحد الأدنى لدرجة النجاح في اختبارات المعرفة (الكتابية) لرخصة CDL في ويست فرجينيا؟","options":["70%","75%","80%","90%"],"explanation":"تتطلب ويست فرجينيا درجة لا تقل عن 80% للنجاح في كل اختبار معرفي لرخصة CDL (يجب أن يُجرى اختبار المواد الخطرة بشكل كتابي). المصدر: WV DMV CDL testing requirements."},"34":{"q":"قبل أن تتمكن ويست فرجينيا من إصدار تصديق المواد الخطرة (H)، ما هو الفحص الفيدرالي الذي يجب أن يجتازه المتقدم؟","options":["تقييم تهديد أمني من إدارة أمن النقل (TSA)","مراجعة سجل الائتمان","فحص سجلات جنائية على مستوى الولاية فقط دون بصمات أصابع","فحص طبي للنظر فقط"],"explanation":"يتطلب القانون الفيدرالي الذي اعتمدته ويست فرجينيا من المتقدمين لتصديق المواد الخطرة اجتياز تقييم تهديد أمني من TSA، يشمل أخذ البصمات وفحص الخلفية، قبل إصدار التصديق أو تجديده. المصدر: WV CDL Manual؛ 49 CFR 1572 (TSA)."},"35":{"q":"ما هو الحد الأدنى للعمر للحصول على تصديق المواد الخطرة (H) على رخصة CDL في ويست فرجينيا؟","options":["18 عامًا","21 عامًا","25 عامًا","19 عامًا"],"explanation":"نظرًا لأن نقل المواد الخطرة يتطلب وضع التأهيل للتجارة بين الولايات بموجب القواعد الفيدرالية، يجب أن يكون عمر المتقدم 21 عامًا على الأقل للحصول على تصديق المواد الخطرة. المصدر: WV CDL Manual؛ TSA/FMCSA HazMat requirements."},"36":{"q":"يجب على المتقدمين لأول مرة للحصول على رخصة CDL في ويست فرجينيا إكمال تدريب السائق المبتدئ (ELDT) من خلال مزوّد يكون:","options":["مدرجًا في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA","معتمدًا فقط من شرطة ولاية ويست فرجينيا","أي مدرسة قيادة خاصة يختارها المتقدم","معتمدًا من TSA"],"explanation":"يجب إكمال تدريب ELDT مع مزوّد مدرج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA. وينطبق على من يحصلون على رخصة CDL من الفئة A أو B لأول مرة، أو يرفّعون من B إلى A، أو يسعون للحصول على تصديق P أو S أو H لأول مرة (في أو بعد 7 فبراير 2022). المصدر: FMCSA ELDT rule؛ WV DMV CDL page."},"37":{"q":"أي مما يلي يُعد واحدة من فئات التصديق الذاتي الطبي الأربع التي يجب على متقدم رخصة CDL في ويست فرجينيا الاختيار من بينها؟","options":["غير معفى بين الولايات (NI)","ترفيهي بين الولايات (RI)","تجاري معفى (CE)","محلي محدود (LL)"],"explanation":"فئات التصديق الذاتي الأربع هي: غير معفى بين الولايات (NI)، ومعفى بين الولايات (EI)، وغير معفى داخل الولاية (NA)، ومعفى داخل الولاية (EA). يجب على السائقين في الفئات غير المعفاة حمل شهادة فاحص طبي صالحة من DOT. المصدر: WV DMV CDL self-certification؛ FMCSA."},"38":{"q":"يجب على سائق رخصة CDL في ويست فرجينيا الذي يصدّق على فئة 'غير معفى بين الولايات (NI)' تقديم أي مستند؟","options":["شهادة فاحص طبي صالحة (بطاقة DOT الطبية)","وثيقة تأمين على المركبة فقط","خطاب إعفاء موقّع من صاحب العمل","لا شيء إضافي بخلاف الطلب"],"explanation":"يجب على السائقين الذين يصدّقون على فئة غير معفاة (NI أو NA) الحصول على شهادة فاحص طبي صالحة من فاحص مدرج في السجل الوطني لـ FMCSA وتقديمها؛ أما الفئات المعفاة (EI وEA) فلا تتطلب بطاقة DOT الطبية. المصدر: WV DMV CDL self-certification؛ FMCSA."},"39":{"q":"عند التقدم للحصول على رخصة CDL أو تصريح CLP في ويست فرجينيا، كم عدد إثباتات الإقامة في ويست فرجينيا التي تطلبها DMV؟","options":["إثبات إقامة واحد","إثباتا إقامة","ثلاثة إثباتات إقامة","لا يُطلب إثبات إقامة"],"explanation":"تتطلب ويست فرجينيا إثباتًا واحدًا للهوية/الوجود القانوني، وإثباتًا واحدًا لرقم الضمان الاجتماعي، وإثباتين للإقامة في ويست فرجينيا لطلب رخصة CDL/تصريح CLP. المصدر: WV DMV acceptable documents / driver license requirements."},"40":{"q":"بموجب قانون ويست فرجينيا، عند أي تركيز للكحول في الدم (BAC) يُعتبر السائق مشغّلًا لمركبة تجارية آلية (CMV) بكمية كحول مفرطة، مما يستوجب فقدان الأهلية؟","options":["0.08% أو أكثر","0.02% أو أكثر","0.10% أو أكثر","0.04% أو أكثر"],"explanation":"تحدد ويست فرجينيا حد الكحول للمركبة التجارية الآلية عند 0.04% (\"أربعة من مئة من واحد بالمئة أو أكثر، بالوزن\")، أي نصف حد الـ 0.08% للمركبات الشخصية. المصدر: WV CDL Manual, Disqualification Offenses؛ WV Code 17E-1-13(b)(2)."},"41":{"q":"في ويست فرجينيا، سائق المركبة التجارية الآلية الذي يتبيّن أن لديه أي كمية كحول قابلة للكشف أقل من 0.04% يجب أن:","options":["تُسحب أهليته فورًا لمدة سنة واحدة","يُوضع خارج الخدمة لمدة 24 ساعة","يُغرّم 2,500 دولار دون فترة إيقاف عن الخدمة","يُمنح تحذيرًا فقط دون أي عقوبة"],"explanation":"سائق المركبة التجارية الآلية الذي لديه أي كمية كحول قابلة للقياس والكشف أقل من 0.04% يُوضع خارج الخدمة لمدة 24 ساعة، رغم أنها أقل من عتبة الـ 0.04% المستوجِبة لفقدان الأهلية. المصدر: WV CDL Manual Section 1.3 وأحكام الموافقة الضمنية؛ WV Code 17E-1-13."},"42":{"q":"ما هي فترة فقدان الأهلية في ويست فرجينيا عن أول مخالفة جسيمة لسائق مركبة تجارية آلية، مثل القيادة تحت تأثير الكحول (DUI) أو بلوغ BAC قدره 0.04%، عند عدم نقل مواد خطرة تتطلب لوحات تحذيرية؟","options":["60 يومًا","3 سنوات","سنة واحدة","6 أشهر"],"explanation":"تؤدي أول مخالفة جسيمة (القيادة تحت تأثير الكحول، أو BAC قدره 0.04%، أو الرفض، أو مغادرة موقع الحادث، أو استخدام مركبة في جناية، إلخ) إلى فقدان أهلية رخصة CDL لمدة سنة واحدة في ويست فرجينيا. المصدر: WV CDL Manual, Disqualification Offenses؛ WV Code 17E-1-13(b)."},"43":{"q":"إذا ارتكب سائق مركبة تجارية آلية في ويست فرجينيا أول مخالفة جسيمة أثناء نقل مواد خطرة يُطلب وضع لوحات تحذيرية لها، فإن فترة فقدان الأهلية تكون:","options":["3 سنوات","سنة واحدة","5 سنوات","180 يومًا"],"explanation":"تحمل أول مخالفة جسيمة تُرتكب أثناء تشغيل مركبة تجارية آلية تنقل مواد خطرة ذات لوحات تحذيرية (وفقًا لـ 49 CFR Part 172, Subpart F) فقدان أهلية مشدّدًا قدره 3 سنوات بدلًا من سنة واحدة. المصدر: WV CDL Manual؛ WV Code 17E-1-13(b)(1)(C)."},"44":{"q":"ما هي فترة فقدان الأهلية في ويست فرجينيا عن مخالفة جسيمة ثانية (في حادثة منفصلة)؟","options":["10 سنوات","مدى الحياة","3 سنوات","5 سنوات"],"explanation":"تؤدي مخالفة جسيمة ثانية في حادثة منفصلة إلى فقدان أهلية رخصة CDL مدى الحياة في ويست فرجينيا. قد تسمح DMV بإعادة الترخيص بعد فترة دنيا ضمن شروط معينة، لكنها تُفرض بوصفها فقدان أهلية مدى الحياة. المصدر: WV CDL Manual؛ WV Code 17E-1-13(b)(1)(D)."},"45":{"q":"في ويست فرجينيا، يؤدي رفض الخضوع لاختبار كيميائي (ثانوي) محدد أثناء تشغيل مركبة تجارية آلية إلى أي فقدان للأهلية عن أول رفض؟","options":["60 يومًا","سنة واحدة","90 يومًا","30 يومًا"],"explanation":"يُعامَل رفض الاختبار كمخالفة جسيمة: أول رفض يُفقد السائق أهليته لمدة سنة واحدة (3 سنوات في حال نقل مواد خطرة ذات لوحات تحذيرية)، والثاني يؤدي إلى فقدان أهلية مدى الحياة. المصدر: WV CDL Manual؛ WV Code 17E-1-13(b)(3)."},"46":{"q":"بموجب قانون الموافقة الضمنية في ويست فرجينيا، بقبول امتياز القيادة في الولاية، يُعتبر السائق قد وافق على:","options":["تفتيش المركبة عند أي توقيف مروري","دورة تثقيفية إلزامية حول القيادة تحت تأثير الكحول","فحوصات عشوائية بكلاب كشف المخدرات على جانب الطريق","اختبار كيميائي لتحديد محتوى الكحول في جسمه"],"explanation":"يعني قانون الموافقة الضمنية في ويست فرجينيا أن أي شخص يقود في الولاية قد وافق على إجراء الاختبار الكيميائي المحدد لمحتوى الكحول. يؤدي الرفض إلى تعليق امتيازات القيادة لمدة سنة واحدة على الأقل، وقد تصل إلى مدى الحياة. المصدر: WV CDL Manual, Implied Consent Law؛ WV Code 17C-5-4."},"47":{"q":"بموجب قانون الموافقة الضمنية في ويست فرجينيا، يؤدي رفض اختبار كيميائي إلى تعليق امتياز السائق في تشغيل مركبة آلية لأي فترة دنيا؟","options":["90 يومًا على الأقل","30 يومًا على الأقل","سنة واحدة على الأقل","6 أشهر على الأقل"],"explanation":"يؤدي رفض الاختبار الكيميائي المحدد بموجب قانون الموافقة الضمنية في ويست فرجينيا إلى تعليق امتياز تشغيل مركبة آلية لفترة لا تقل عن سنة واحدة، وقد تصل إلى مدى الحياة. المصدر: WV CDL Manual, Implied Consent Law."},"48":{"q":"كم عدد المخالفات المرورية الجسيمة خلال فترة 3 سنوات التي تستوجب فقدان الأهلية لمدة 60 يومًا في ويست فرجينيا؟","options":["1 (المخالفة الأولى)","3 (الثالثة خلال 3 سنوات)","2 (الثانية خلال 3 سنوات)","4 (الرابعة خلال 3 سنوات)"],"explanation":"تؤدي مخالفة مرورية جسيمة ثانية خلال فترة 3 سنوات إلى فقدان الأهلية لمدة 60 يومًا. أما المخالفة الجسيمة الأولى وحدها فلا تستوجب فقدان الأهلية. المصدر: WV CDL Manual Section 1.3.3؛ WV Code 17E-1-13(c)."},"49":{"q":"ما هي فترة فقدان الأهلية في ويست فرجينيا عن مخالفة مرورية جسيمة ثالثة خلال فترة 3 سنوات؟","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"تؤدي مخالفة مرورية جسيمة ثالثة أو لاحقة خلال فترة 3 سنوات إلى فقدان الأهلية لمدة 120 يومًا. المصدر: WV CDL Manual Section 1.3.3؛ WV Code 17E-1-13(c)."},"50":{"q":"أي مما يلي يُصنّف بوصفه \"مخالفة مرورية جسيمة\" لأغراض فقدان الأهلية لرخصة CDL في ويست فرجينيا؟","options":["القيادة بسرعة تزيد 5 mph عن الحد المقرر","السرعة المفرطة (15 mph أو أكثر فوق الحد المقرر)","مخالفة وقوف","ملصق تسجيل منتهي الصلاحية"],"explanation":"تشمل المخالفات المرورية الجسيمة السرعة المفرطة (15 mph أو أكثر فوق الحد المقرر)، والقيادة المتهورة، وتغيير الحارات بشكل غير سليم أو متقلب، والاتباع عن قرب مفرط، والمراسلة النصية أثناء القيادة. وتُستثنى مخالفات الوقوف. المصدر: WV CDL Manual Section 1.3.3؛ WV Code 17E-1-13(c)."},"51":{"q":"في ويست فرجينيا، ما هي فترة فقدان الأهلية عن أول إدانة بانتهاك أمر إيقاف عن الخدمة أثناء تشغيل مركبة تجارية آلية تحمل بضائع غير خطرة؟","options":["90 يومًا","60 يومًا","180 يومًا","سنة واحدة"],"explanation":"تؤدي أول إدانة بانتهاك أمر إيقاف عن الخدمة أثناء تشغيل مركبة تجارية آلية إلى فقدان الأهلية لمدة 180 يومًا في ويست فرجينيا. المصدر: WV CDL Manual؛ WV Code 17E-1-13(e)(1)(A)."},"52":{"q":"ما هي فترة فقدان الأهلية عن انتهاك ثانٍ لأمر إيقاف عن الخدمة خلال فترة 10 سنوات أثناء نقل مواد غير خطرة في ويست فرجينيا؟","options":["180 يومًا","سنتان","3 سنوات","سنة واحدة"],"explanation":"يؤدي انتهاك ثانٍ لأمر إيقاف عن الخدمة في حادثة منفصلة خلال 10 سنوات (مواد غير خطرة) إلى فقدان الأهلية لمدة سنتين. أما انتهاك ثالث أو لاحق خلال 10 سنوات فيؤدي إلى 3 سنوات. المصدر: WV CDL Manual؛ WV Code 17E-1-13(e)(1)(B)."},"53":{"q":"في ويست فرجينيا، يؤدي انتهاك ثانٍ لأمر إيقاف عن الخدمة خلال 10 سنوات أثناء نقل مواد خطرة ذات لوحات تحذيرية أو تشغيل مركبة مصممة لنقل 16 راكبًا أو أكثر إلى أي فقدان للأهلية؟","options":["سنتان","180 يومًا","سنة واحدة","3 سنوات"],"explanation":"يحمل انتهاك ثانٍ لأمر إيقاف عن الخدمة خلال 10 سنوات أثناء نقل مواد خطرة ذات لوحات تحذيرية أو نقل 16 راكبًا أو أكثر فقدان أهلية مشدّدًا قدره 3 سنوات (مقابل سنتين للمواد غير الخطرة). المصدر: WV CDL Manual؛ WV Code 17E-1-13(e)(2)(B)."},"54":{"q":"ما هي فترة فقدان الأهلية في ويست فرجينيا عن أول مخالفة لمعبر السكة الحديدية المتقاطع مع الطريق أثناء تشغيل مركبة تجارية آلية؟","options":["30 يومًا","120 يومًا","60 يومًا","180 يومًا"],"explanation":"تؤدي أول مخالفة لمعبر السكة الحديدية المتقاطع مع الطريق أثناء تشغيل مركبة تجارية آلية إلى فقدان الأهلية لمدة 60 يومًا في ويست فرجينيا. المصدر: WV CDL Manual؛ WV Code 17E-1-13(d)."},"55":{"q":"في ويست فرجينيا، تتصاعد فترات فقدان الأهلية عن مخالفات معبر السكة الحديدية المتقاطع مع الطريق من 60 يومًا عن أول مخالفة إلى ماذا عن المخالفة الثانية والثالثة خلال 3 سنوات؟","options":["120 يومًا للثانية؛ سنة واحدة للثالثة","90 يومًا للثانية؛ 180 يومًا للثالثة","60 يومًا للثانية؛ 120 يومًا للثالثة","180 يومًا للثانية؛ سنتان للثالثة"],"explanation":"تُفقد مخالفات معبر السكة الحديدية السائق أهليته لمدة 60 يومًا (الأولى)، و120 يومًا (الثانية خلال 3 سنوات)، وسنة واحدة (الثالثة أو اللاحقة خلال 3 سنوات). المصدر: WV CDL Manual؛ WV Code 17E-1-13(d)."},"56":{"q":"بموجب القواعد الفيدرالية وقواعد ويست فرجينيا التي اعتمدتها الولاية، تُسحب أهلية رخصة CDL لسائق مركبة تجارية آلية بعد كم إدانة بالمراسلة النصية أثناء قيادة مركبة تجارية آلية؟","options":["إدانة واحدة (المخالفة الأولى)","4 إدانات أو أكثر خلال 3 سنوات","3 إدانات أو أكثر خلال 5 سنوات","إدانتان أو أكثر خلال 3 سنوات"],"explanation":"المراسلة النصية أثناء قيادة مركبة تجارية آلية مخالفة جسيمة: تُسحب أهلية رخصة CDL لمدة 60 يومًا بعد إدانة ثانية خلال 3 سنوات و120 يومًا عن ثلاث إدانات أو أكثر خلال 3 سنوات. الإدانة الأولى لا تستوجب فقدان الأهلية لكنها تحمل عقوبة مدنية. المصدر: WV CDL Manual Section 2.9.5؛ WV Code 17E-1-13(c)(9)."},"57":{"q":"ما هو الحد الأقصى للعقوبة المدنية الفيدرالية (المعتمدة في ويست فرجينيا) لسائق مركبة تجارية آلية يراسل نصيًا أو يستخدم هاتفًا محمولًا باليد أثناء القيادة؟","options":["حتى 2,750 دولارًا","حتى 500 دولار","حتى 11,000 دولار","حتى 5,000 دولار"],"explanation":"تُعرّض كل مخالفة مراسلة نصية/استخدام هاتف باليد سائق المركبة التجارية الآلية لعقوبة مدنية تصل إلى 2,750 دولارًا. (قد يُغرّم أصحاب العمل الذين يسمحون بها أو يطلبونها حتى 11,000 دولار.) المصدر: WV CDL Manual Sections 2.9.4 and 2.9.5."},"58":{"q":"حامل رخصة CDL في ويست فرجينيا الذي تُعلّق رخصة مركبته الشخصية بسبب مخالفة تتعلق بالكحول أو مادة خاضعة للرقابة أو جناية يفقد امتيازات CDL لأي مدة عن أول مخالفة؟","options":["سنة واحدة","60 يومًا","90 يومًا","6 أشهر"],"explanation":"إذا أُلغيت امتيازات المركبة الشخصية لحامل رخصة CDL أو سُحبت أو عُلّقت بسبب مخالفات تتعلق بالكحول أو مادة خاضعة للرقابة أو جناية، تُفقد رخصة CDL لمدة سنة واحدة؛ وتؤدي مخالفة ثانية من هذا النوع (مركبة شخصية أو مركبة تجارية آلية) إلى فقدان مدى الحياة. المصدر: WV CDL Manual Section 1.3؛ WV Code 17E-1-13(b)."},"59":{"q":"بموجب نظام النقاط للسائقين في ويست فرجينيا، يؤدي بلوغ كم نقطة إلى تعليق امتيازات القيادة؟","options":["6 نقاط أو أكثر","20 نقطة أو أكثر","8 نقاط أو أكثر","12 نقطة أو أكثر"],"explanation":"يعلّق نظام النقاط في WV DMV امتيازات القيادة عند بلوغ 12 نقطة أو أكثر. فعلى سبيل المثال، تجاوز السرعة بمقدار 20 mph أو أكثر فوق الحد يساوي 6 نقاط، والقيادة المتهورة تساوي 6 نقاط. المصدر: WV CDL Manual / WV Driver's Licensing Handbook, Point System."},"60":{"q":"على طريق سريع غير مقسّم في ولاية فرجينيا الغربية، عندما لا تستطيع تغيير المسار بأمان بعيدًا عن مركبة طوارئ أو خدمة متوقفة تُظهر أضواء وامضة، ما هي السرعة القصوى التي يمكنك تجاوزها بها بموجب قانون الولاية للتنحّي جانبًا (Move Over)؟","options":["15 mph","25 mph","10 mph","20 mph"],"explanation":"يقضي قانون فرجينيا الغربية West Virginia Code 17C-14-9a (قانون التنحّي جانبًا Move Over) بأن على السائق الذي لا يستطيع التنحّي جانبًا أن يخفّض سرعته إلى مستوى آمن لا يتجاوز 15 mph على أي طريق سريع أو شارع غير مقسّم عند تجاوز مركبة طوارئ أو خدمة مرخّصة متوقفة. المصدر: WV Code 17C-14-9a."},"61":{"q":"على طريق سريع مقسّم في ولاية فرجينيا الغربية حيث لا تستطيع الانتقال بأمان إلى مسار غير مجاور، ما هي السرعة القصوى التي يمكنك تجاوز مركبة طوارئ متوقفة بها تعرض أضواء تحذير؟","options":["15 mph","35 mph","25 mph","20 mph"],"explanation":"بموجب WV Code 17C-14-9a، على السائق الذي لا يستطيع تغيير المسار أن يخفّض سرعته إلى مستوى آمن لا يتجاوز 25 mph على أي طريق سريع مقسّم عند تجاوز مركبة طوارئ أو خدمة متوقفة. المصدر: WV Code 17C-14-9a."},"62":{"q":"بموجب دليل CDL لولاية فرجينيا الغربية، على بُعد كم يجب أن تتوقف مركبة HazMat تحمل لافتات، أو حمولة كلور، أو صهريج شحن، عن أقرب سكة عند معبر السكة الحديدية؟","options":["بين 10 و25 قدمًا","بين 15 و50 قدمًا","بين 5 و15 قدمًا","بين 25 و75 قدمًا"],"explanation":"ينص دليل WV CDL (القسم 9.6.12) على أن المركبة التي تحمل لافتات، أو تنقل أي كمية من الكلور، أو لديها صهاريج شحن مستخدمة للمواد الخطرة يجب أن تتوقف على بُعد 15 إلى 50 قدمًا قبل أقرب سكة. المصدر: WV CDL Manual, Sec. 9.6.12."},"63":{"q":"على بُعد كم يجب أن يوقف سائق الحافلة في ولاية فرجينيا الغربية الحافلة قبل معبر السكة الحديدية؟","options":["بين 20 و40 قدمًا","50 قدمًا على الأقل","بين 10 و30 قدمًا","بين 15 و50 قدمًا"],"explanation":"يوجّه دليل WV CDL (القسم 4.3.5) سائقي الحافلات إلى إيقاف الحافلة بين 15 و50 قدمًا قبل معابر السكك الحديدية، ثم الإنصات والنظر في كلا الاتجاهين بحثًا عن القطارات. المصدر: WV CDL Manual, Sec. 4.3.5."},"64":{"q":"ما هو الحد الأقصى المُعلن للسرعة على طريق سريع بين الولايات (interstate) في فرجينيا الغربية ما لم يُعلن خلاف ذلك؟","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"يُدرج جدول السرعات المحددة في دليل WV CDL الطرق السريعة بين الولايات بسرعة 70 mph (ما لم يُعلن خلاف ذلك). المصدر: جدول السرعات المحددة في WV CDL Manual؛ WV Code 17C-6-1."},"65":{"q":"ما لم يُعلن خلاف ذلك، ما هو الحد الأقصى للسرعة في منطقة تجارية أو سكنية في فرجينيا الغربية؟","options":["30 mph","25 mph","20 mph","35 mph"],"explanation":"تحدّد فرجينيا الغربية سرعة قصوى تبلغ 25 mph في أي منطقة تجارية أو سكنية، كما هو موضّح في جدول السرعات المحددة في دليل WV CDL. المصدر: WV Code 17C-6-1؛ WV CDL Manual."},"66":{"q":"ما هو الحد الأقصى للسرعة في منطقة مدرسية في فرجينيا الغربية أثناء وجود الأطفال؟","options":["20 mph","25 mph","15 mph","10 mph"],"explanation":"يحدّد WV Code 17C-6-1 سرعة 15 mph في المنطقة المدرسية أثناء الاستراحة أو أثناء ذهاب الأطفال إلى المدرسة أو مغادرتها؛ ويُدرج دليل WV CDL الرقم نفسه. المصدر: WV Code 17C-6-1؛ WV CDL Manual."},"67":{"q":"على طريق سريع ريفي مفتوح في فرجينيا الغربية (وليس طريقًا بين الولايات أو طريقًا محدود الوصول)، ما هو الحد الأقصى الافتراضي للسرعة ما لم يُعلن خلاف ذلك؟","options":["60 mph","65 mph","50 mph","55 mph"],"explanation":"يُدرج جدول السرعات المحددة في دليل WV CDL الطرق السريعة المفتوحة بسرعة 55 mph ما لم يُعلن خلاف ذلك، بما يتوافق مع WV Code 17C-6-1. المصدر: WV Code 17C-6-1؛ WV CDL Manual."},"68":{"q":"بموجب قانون فرجينيا الغربية West Virginia Code 17C-12-7، عندما تلتقي بحافلة مدرسية متوقفة أو تتجاوزها وهي تُومض بأضواء إشارة التحذير لتحميل الأطفال أو إنزالهم، يجب عليك:","options":["التوقف قبل الوصول إلى الحافلة وعدم المتابعة حتى تتوقف الأضواء أو يُشير السائق","التباطؤ إلى 10 mph والتجاوز بحذر","التوقف فقط إذا كنت تسير في الاتجاه نفسه للحافلة","الانتقال إلى المسار البعيد والمتابعة بسرعة مخفّضة"],"explanation":"يقضي WV Code 17C-12-7 بأن على السائق الذي يلتقي بحافلة مدرسية ذات أضواء تحذير وامضة أو يتجاوزها من أي اتجاه أن يتوقف قبل الوصول إلى الحافلة وألا يتابع حتى تتحرك الحافلة، أو تتوقف الأضواء، أو يُشير سائق الحافلة. المصدر: WV Code 17C-12-7."},"69":{"q":"بموجب قانون الحافلات المدرسية في فرجينيا الغربية، على أي نوع من الطرق لا يتعيّن على السائق التوقف لحافلة مدرسية موجودة على طريق مختلف لا يُسمح فيه للمشاة بالعبور؟","options":["أي طريق سريع رباعي المسارات","أي طريق به مسار انعطاف وسطي","طريق سريع محدود الوصول","طريق ثنائي المسار به جزيرة وسطية مرسومة"],"explanation":"ينص WV Code 17C-12-7 على أن السائق على طريق سريع محدود الوصول لا يتعيّن عليه التوقف لحافلة مدرسية موجودة على طريق مختلف، أو مجاورة للطريق السريع، حيث لا يُسمح للمشاة بالعبور. أما الخط المرسوم أو المسار الوسطي وحده فلا يُفعّل الاستثناء. المصدر: WV Code 17C-12-7."},"70":{"q":"بعد إيقاف مركبة تجارية على كتف طريق سريع في فرجينيا الغربية، خلال كم دقيقة يجب أن تضع أجهزة التحذير الخاصة بالطوارئ؟","options":["5 دقائق","10 دقائق","15 دقيقة","30 دقيقة"],"explanation":"ينص دليل WV CDL على أنه إذا اضطررت إلى التوقف على طريق أو كتف، فيجب وضع أجهزة التحذير الخاصة بالطوارئ خلال عشر دقائق. المصدر: WV CDL Manual, Sec. 2.5."},"71":{"q":"عند التوقف على طريق سريع باتجاه واحد أو مقسّم في فرجينيا الغربية، أين يجب وضع المثلثات العاكسة الثلاثة؟","options":["10 أقدام و100 قدم و100 قدم عند المقدمة والمؤخرة","50 قدمًا و100 قدم و500 قدم نحو المؤخرة","10 أقدام و50 قدمًا و150 قدمًا نحو حركة المرور القادمة","10 أقدام و100 قدم و200 قدم نحو حركة المرور القادمة"],"explanation":"يوجّه دليل WV CDL إلى أنه على طريق سريع باتجاه واحد أو مقسّم تُوضع أجهزة التحذير على بُعد 10 أقدام و100 قدم و200 قدم من المركبة نحو حركة المرور القادمة. المصدر: WV CDL Manual, Sec. 2.5."},"72":{"q":"إذا لم يكن لدى سائق في فرجينيا الغربية مثلثات عاكسة، فما أجهزة التحذير التي يقبلها دليل CDL كبديل للتحذير من مركبة متوقفة؟","options":["ما لا يقل عن 6 شعلات (fusees) أو 3 شعلات سائلة محترقة","ما لا يقل عن 2 شعلة (fusees) أو 1 شعلة سائلة محترقة","منارة كهرمانية دوّارة واحدة","ما لا يقل عن 4 مخاريط طريق"],"explanation":"يُدرج دليل WV CDL أجهزة التحذير للمركبات المتوقفة على أنها ثلاثة مثلثات عاكسة أو ما لا يقل عن 6 شعلات (fusees) أو 3 شعلات سائلة محترقة. المصدر: WV CDL Manual، قسم فحص المركبة/معدات الطوارئ."},"73":{"q":"لماذا تحظر فرجينيا الغربية استخدام الشعلات أو أجهزة التحذير ذات اللهب المكشوف حول حمولات معينة تحمل لافتات؟","options":["لأنها خافتة جدًا بحيث لا تُرى ليلاً","لأنها قانونية فقط على الطرق السريعة المقسّمة","لأنها يمكن أن تُشعل الشحنات القابلة للاشتعال مثل السوائل القابلة للاشتعال من الفئة 3 (Class 3)","لأنها تستنزف بطارية المركبة"],"explanation":"تقول قاعدة 'No Flares!' في دليل WV CDL باستخدام المثلثات العاكسة أو الأضواء الكهربائية الحمراء، وليس الشعلات أو الفتائل المحترقة، حول المركبات التي تنقل مواد قابلة للاشتعال مثل السوائل القابلة للاشتعال من الفئة 3 (Class 3). المصدر: WV CDL Manual, Sec. 9.6.4."},"74":{"q":"بموجب قاعدة استخدام المسارات في فرجينيا الغربية، أين يجب أن يسير جميع السائقين، بمن فيهم حركة الشاحنات، عادةً؟","options":["في المسار الأوسط لإبقاء المسار الأيمن خاليًا للاندماج","في المسار الأيمن الأقصى باستثناء حالات التجاوز أو الانعطاف أو تجنّب العوائق","في أي مسار به أقل حركة مرور","في المسار الأيسر لترك المسار الأيمن للمركبات الأبطأ"],"explanation":"تقضي فرجينيا الغربية (الفصل 17C، المادة 7) بأن على السائقين، بمن فيهم الشاحنات، الالتزام افتراضيًا بالمسار الأيمن الأقصى باستثناء حالات التجاوز/المرور، أو عندما يكون المسار الأيمن مغلقًا، أو عند السير بسرعة أقل من سرعة المرور العادية، أو عند الاستعداد للانعطاف. المصدر: WV Code Ch. 17C, Art. 7."},"75":{"q":"على طريق سريع ثلاثي المسارات في فرجينيا الغربية، كيف يجوز للشاحنة استخدام المسارات؟","options":["يجوز لها استخدام أي من المسارات الثلاثة بحرية","يجب عليها استخدام المسار الأوسط فقط","يجوز لها استخدام المسارين الأيسرين والتجاوز في المسار الأيمن","يجب أن تبقى في المسار الأيمن ولكن يجوز لها استخدام المسار الأوسط للتجاوز"],"explanation":"بموجب قواعد المسارات في فرجينيا الغربية، تُقيّد الشاحنات على الطريق ثلاثي المسارات بالمسار الأيمن ولكن يجوز لها الانتقال إلى المسار الأوسط للتجاوز. المصدر: WV Code Ch. 17C, Art. 7."},"76":{"q":"على طريق سريع رباعي المسارات في فرجينيا الغربية، ما المسارات التي يجوز لجرّار شاحنة يسحب نصف مقطورة استخدامها؟","options":["المساران الأيمنان","المسار الأيمن الأقصى فقط","أي مسار باستثناء الأيسر الأقصى","المساران الأيسران"],"explanation":"تسمح فرجينيا الغربية لجرّارات الشاحنات التي تسحب نصف مقطورات بالعمل في المسارين الأيمنين على طريق سريع رباعي المسارات. المصدر: WV Code Ch. 17C, Art. 7."},"77":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة (بدون تصريح) في فرجينيا الغربية على طرق Interstate وUS وWV ذات مسارات بعرض 10 أقدام أو أكثر؟","options":["8 أقدام و0 إنش","9 أقدام و0 إنش","8 أقدام و6 إنشات","10 أقدام و0 إنش"],"explanation":"تحدّد قيود الحجم القانونية لشعبة الطرق السريعة في فرجينيا الغربية (WV Division of Highways) أقصى عرض بـ 8 أقدام و6 إنشات على طرق Interstate وUS وWV والطرق المحلية ذات المسارات بعرض 10 أقدام أو أكثر (8 أقدام على الطرق المحلية الأضيق). المصدر: WVDOT/Division of Highways Legal Size and Weight Limits."},"78":{"q":"ما هو الحد الأقصى القانوني للوزن الإجمالي (بدون تصريح) لمركبة على طريق سريع بين الولايات (INTERSTATE) في فرجينيا الغربية؟","options":["65,000 pounds","80,000 pounds","73,280 pounds","90,000 pounds"],"explanation":"يبلغ الحد القانوني للوزن الإجمالي في فرجينيا الغربية على الطرق السريعة بين الولايات 80,000 pounds (بلا هامش تسامح)؛ بينما تقتصر طرق الخدمة المحلية على 65,000 pounds. المصدر: WVDOT Legal Size and Weight Limits."},"79":{"q":"أي عبارة عن الطريق السريع West Virginia Turnpike (I-77) صحيحة بالنسبة للسائقين التجاريين؟","options":["تُمنع الشاحنات والمقطورات من Turnpike بالكامل","إنه طريق سريع بين الولايات مجاني بلا محطات رسوم","يجوز للشاحنات استخدامه فقط بين شروق الشمس وغروبها","إنه طريق سريع جبلي برسوم حيث تدفع الشاحنات رسومًا عند محطات الرسوم الرئيسية"],"explanation":"يحمل الطريق السريع West Virginia Turnpike المسار I-77 عبر منحدرات جبلية شديدة (تصل إلى نحو 5%) وهو طريق برسوم به محطات رسوم رئيسية (Ghent وPax وChelyan) حيث تدفع الشاحنات رسومًا بناءً على الحجم/المحاور؛ كما يحتوي على منحدرات هروب للشاحنات. المصدر: صفحات WV Parkways Authority / WVDOT Turnpike."},"80":{"q":"أي وكالة حكومية تُصدر رخص القيادة التجارية (CDLs) في ولاية فرجينيا الغربية؟","options":["شعبة المركبات الآلية في فرجينيا الغربية (DMV)","شرطة ولاية فرجينيا الغربية","لجنة الخدمة العامة في فرجينيا الغربية","شعبة الطرق السريعة في فرجينيا الغربية"],"explanation":"في فرجينيا الغربية، تُصدر رخص CDL من قِبل شعبة المركبات الآلية في فرجينيا الغربية (DMV)، التي تُدير اختبارات المعرفة وتعالج الطلبات. المصدر: صفحة رخصة القيادة التجارية في WV DMV (transportation.wv.gov/DMV/Motor-Carriers/CDL)."},"81":{"q":"قبل أن تُصدر فرجينيا الغربية رخصة CDL كاملة، يجب على مقدّم الطلب أولاً الحصول على أي اعتماد والاحتفاظ به؟","options":["تصريح متعلّم القيادة التجارية (CLP)","تظهير على رخصة مشغّل من الفئة D","صلاحية تشغيل اتحادية بين الولايات","تصريح قيادة مؤقت لحالة المشقة"],"explanation":"تشترط فرجينيا الغربية على مقدّمي الطلبات الحصول أولاً على تصريح متعلّم القيادة التجارية (CLP) من DMV، الذي يُجيز التدريب تحت الإشراف قبل اختبار المهارات. المصدر: صفحة CDL في WV DMV."},"82":{"q":"في فرجينيا الغربية، كم يجب أن يحتفظ مقدّم الطلب بتصريح متعلّم القيادة التجارية (CLP) قبل أن يصبح مؤهلاً لأداء اختبار مهارات القيادة على الطريق لرخصة CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","7 أيام على الأقل","60 يومًا على الأقل"],"explanation":"تشترط فرجينيا الغربية (متّبعةً المعيار الاتحادي) الاحتفاظ بتصريح CLP لمدة 14 يومًا كحد أدنى قبل أن يتمكّن مقدّم الطلب من أداء اختبار المهارات على الطريق. المصدر: صفحة CDL في WV DMV؛ 49 CFR 383.25 كما هي معتمدة في WV."},"83":{"q":"عند التصديق الذاتي على نوع العملية التجارية، من بين كم فئة يجب أن يختار مقدّم طلب CDL/CLP في فرجينيا الغربية؟","options":["أربع فئات","فئتان","ثلاث فئات","خمس فئات"],"explanation":"تشترط فرجينيا الغربية على مقدّمي الطلبات التصديق الذاتي على إحدى أربع فئات لتشغيل المركبات التجارية الآلية: غير المُستثناة بين الولايات (NI)، والمُستثناة بين الولايات (EI)، وغير المُستثناة داخل الولاية (NA)، والمُستثناة داخل الولاية (EA). المصدر: إقرار التصديق الذاتي الطبي لـ WV DMV (Form DMV-CDL-3)."},"84":{"q":"أي فئة من فئات التصديق الذاتي في فرجينيا الغربية تتطلّب من السائق الاحتفاظ بشهادة فاحص طبي صالحة من DOT في الملف؟","options":["غير المُستثناة بين الولايات (NI)","المُستثناة بين الولايات (EI)","المُستثناة داخل الولاية (EA)","أي سائق يعمل داخل الولاية فقط يكون معفى"],"explanation":"يجب على السائقين الذين يصدّقون ذاتيًا على حالة غير مُستثناة (NI أو NA) الاحتفاظ بشهادة فاحص طبي صالحة من FMCSA؛ أما الحالات المُستثناة (EI، EA) فمعفاة من هذا الشرط. المصدر: إقرار التصديق الذاتي الطبي لـ WV DMV (Form DMV-CDL-3)؛ FMCSA 49 CFR 383.71."},"85":{"q":"اعتبارًا من June 23, 2025، كيف تُقدَّم عادةً المعلومات الطبية من DOT لسائق CDL غير مُستثنى في فرجينيا الغربية إلى DMV؟","options":["يُدخل الفاحص الطبي المعتمد نتائج الفحص في قاعدة بيانات إلكترونية آمنة تُرسَل إلى DMV","يُرسل السائق بطاقة طبية ورقية بالبريد إلى DMV بعد كل فحص","يُرسل صاحب عمل السائق البطاقة الطبية بالفاكس إلى DMV","يتم التحقق من البطاقة الطبية فقط عند تجديد الرخصة"],"explanation":"اعتبارًا من June 23, 2025، لم تعد فرجينيا الغربية تقبل الشهادات الطبية الورقية؛ إذ يُدخل الفاحص الطبي المعتمد نتائج الفحص إلكترونيًا في قاعدة بيانات آمنة تُرسَل إلى DMV. المصدر: إعلان WV DMV بشأن تحسين عملية التصديق الطبي لـ CDL (June 2025)."},"86":{"q":"ما هي الدرجة الدنيا للنجاح في اختبار المعرفة (الكتابي) لرخصة CDL في فرجينيا الغربية؟","options":["80 في المئة","70 في المئة","75 في المئة","90 في المئة"],"explanation":"تشترط فرجينيا الغربية الإجابة بشكل صحيح على 80 في المئة على الأقل لاجتياز اختبار معرفة CDL. المصدر: دليل رخصة القيادة التجارية في فرجينيا الغربية؛ قواعد اختبار CDL في WV DMV."},"87":{"q":"يتألف اختبار مهارات CDL في فرجينيا الغربية من أي ثلاثة أجزاء، بالترتيب؟","options":["فحص المركبة قبل الرحلة، والتحكّم الأساسي بالمركبة، والقيادة على الطريق","المعرفة الكتابية، وفحص النظر، والقيادة على الطريق","فحص فرامل الهواء، واختبار الاقتران، واختبار زمن رد الفعل","مناورات الرجوع للخلف، والاندماج في الطريق السريع، والركن الموازي"],"explanation":"يتألف اختبار مهارات CDL في فرجينيا الغربية من ثلاثة أجزاء: فحص المركبة قبل الرحلة، واختبار مهارات التحكّم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: دليل رخصة القيادة التجارية في فرجينيا الغربية (أقسام اختبار المهارات)."},"88":{"q":"من يجب أن يوفّر المركبة المستخدمة في اختبار مهارات (الطريق) لرخصة CDL في فرجينيا الغربية؟","options":["مقدّم الطلب، الذي يجب أن يوفّر مركبة ممثّلة للفئة التي يُختبر عليها","DMV، التي توفّر شاحنة اختبار قياسية","حظيرة سيارات شعبة الطرق السريعة","أي مركبة مقبولة، بما في ذلك سيارة الركاب"],"explanation":"يجب على مقدّم الطلب توفير المركبة لاختبار المهارات، ويجب أن تكون ممثّلة لفئة CDL التي يُختبر عليها مقدّم الطلب. المصدر: دليل رخصة القيادة التجارية في فرجينيا الغربية؛ صفحة CDL في WV DMV."},"89":{"q":"يجب على مقدّم طلب CDL لأول مرة في فرجينيا الغربية إكمال تدريب السائق المبتدئ (ELDT) قبل أداء أي اختبار؟","options":["اختبار مهارات (الطريق) لـ CDL","فحص النظر","اختبار تجديد الفئة D","فحص الخلفية ببصمات الأصابع"],"explanation":"يجب إكمال ELDT (النظري والتدريب خلف المقود) قبل اختبار مهارات CDL لمقدّمي الطلبات لأول مرة من الفئة A/B وبعض التظهيرات. المصدر: صفحة CDL في WV DMV؛ قاعدة FMCSA ELDT (49 CFR Part 380)، السارية اعتبارًا من February 7, 2022."},"90":{"q":"بموجب قاعدة ELDT الاتحادية المطبّقة في فرجينيا الغربية، يُعامَل السائق بوصفه مقدّم طلب CDL 'لأول مرة' (ويجب عليه إكمال ELDT) إذا لم يكن قد حمل رخصة CDL من قبل قبل أي تاريخ؟","options":["February 7, 2022","January 1, 2020","October 1, 2021","June 23, 2025"],"explanation":"متطلبات ELDT ليست بأثر رجعي: فالشخص الذي لم يكن قد حمل رخصة CDL (أو التظهير ذي الصلة S أو P أو H) من قبل February 7, 2022 يُعد مقدّم طلب لأول مرة يجب عليه إكمال ELDT. المصدر: صفحة CDL في WV DMV؛ القاعدة النهائية لـ FMCSA ELDT."},"91":{"q":"أين يجب أن يكون مزوّد تدريب ELDT في فرجينيا الغربية مُدرَجًا حتى يُحتسب التدريب ضمن أهلية CDL؟","options":["في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","في قائمة موردي WV DMV فقط","في قائمة متعاقدي شعبة الطرق السريعة في الولاية","في الدليل الوطني لفاحصي CDL"],"explanation":"يجب إكمال ELDT من خلال مزوّد مُدرَج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR) حتى يفي بمتطلب CDL في فرجينيا الغربية. المصدر: صفحة CDL في WV DMV؛ FMCSA TPR (tpr.fmcsa.dot.gov)."},"92":{"q":"في فرجينيا الغربية، ما هو الحد الأدنى للعمر للحصول على رخصة CDL للتشغيل داخل الولاية (داخل الولاية فقط)؟","options":["18 عامًا","21 عامًا","19 عامًا","16 عامًا"],"explanation":"يجب أن يكون عمر مقدّم الطلب 18 عامًا على الأقل للحصول على رخصة CDL في فرجينيا الغربية للتشغيل داخل الولاية؛ أما التشغيل بين الولايات والمواد الخطرة فيتطلبان عمر 21 عامًا. المصدر: صفحة CDL في WV DMV؛ WV Code Chapter 17E."},"93":{"q":"ما هو الحد الأدنى للعمر لتشغيل مركبة تجارية آلية في التجارة بين الولايات أو لنقل المواد الخطرة بموجب قواعد CDL في فرجينيا الغربية؟","options":["21 عامًا","18 عامًا","19 عامًا","25 عامًا"],"explanation":"تشترط فرجينيا الغربية أن يكون عمر السائق 21 عامًا على الأقل للتشغيل بين الولايات أو لنقل المواد الخطرة التي تحمل لافتات؛ أما من تتراوح أعمارهم بين 18 و20 عامًا فيقتصرون على التشغيل داخل الولاية. المصدر: صفحة CDL في WV DMV؛ FMCSA 49 CFR 391.11."},"94":{"q":"بموجب دورة 'Drive for Five' القياسية في فرجينيا الغربية، تكون رخصة CDL صالحة عمومًا لأي مدة؟","options":["خمس سنوات، تنتهي صلاحيتها في عيد ميلاد حاملها في سنة يكون فيها عمره قابلاً للقسمة على خمسة","أربع سنوات، في تاريخ تجديد ثابت","ثماني سنوات من تاريخ الإصدار","سنتان، بما يطابق بطاقة DOT الطبية"],"explanation":"تُجدّد رخص CDL في فرجينيا الغربية وفق دورة الخمس سنوات القياسية، وتنتهي صلاحيتها في عيد ميلاد مقدّم الطلب في سنة يكون فيها عمره قابلاً للقسمة على خمسة بالتساوي. المصدر: WV Code 17E-1-12؛ WV DMV."},"95":{"q":"رخصة CDL في فرجينيا الغربية صادرة لسائق دون سن 21 تنتهي صلاحيتها عند أي نقطة؟","options":["بعد 30 يومًا من عيد ميلاد مقدّم الطلب في السنة التي يبلغ فيها 21 عامًا","في عيد ميلاد السائق الثامن عشر","بعد خمس سنوات من تاريخ الإصدار بغض النظر عن العمر","فور بلوغ 21 عامًا مباشرة"],"explanation":"رخصة CDL في فرجينيا الغربية الصادرة لشخص لم يبلغ سن 21 تنتهي صلاحيتها بعد 30 يومًا من عيد ميلاد مقدّم الطلب في السنة التي يبلغ فيها 21 عامًا، لأن أهلية التشغيل بين الولايات/المواد الخطرة تتغيّر عند سن 21. المصدر: WV Code Chapter 17E؛ WV DMV."},"96":{"q":"أي مستند يستخدمه مقدّم الطلب في فرجينيا الغربية للتصديق الذاتي على نوع القيادة التجارية التي يتوقّع القيام بها؟","options":["إقرار التصديق الذاتي الطبي لحامل رخصة القيادة التجارية في WV (Form DMV-CDL-3)","شهادة الفحص الطبي الاتحادية Form MCSA-5876","طلب رخصة مشغّل من الفئة D","نموذج التسجيل المُوزّع لـ IRP"],"explanation":"يصدّق مقدّمو الطلبات ذاتيًا على نوع تشغيلهم في إقرار التصديق الذاتي الطبي لحامل رخصة القيادة التجارية في WV (Form DMV-CDL-3)؛ أما Form MCSA-5876 فهو شهادة الفاحص الطبي المنفصلة. المصدر: نماذج CDL في WV DMV."},"97":{"q":"لأي مدة تُعتبر شهادة الفاحص الطبي من DOT سارية بموجب قواعد CDL في فرجينيا الغربية؟","options":["لا تكون سارية إذا تجاوز عمرها سنتين (وقد تُصدَر لمدة أقصر)","صالحة لمدة خمس سنوات","صالحة لمدة سنة واحدة فقط","لا تنتهي صلاحيتها أبدًا بمجرد وجودها في الملف"],"explanation":"شهادة الفاحص الطبي التي يتجاوز عمرها سنتين لا تكون سارية؛ ويجوز للفاحص إصدارها لمدة سنتين أو لفترة أقصر بحسب حالة السائق. المصدر: صفحة CDL في WV DMV؛ FMCSA 49 CFR 391.45."},"98":{"q":"ماذا يحدث عمومًا لامتيازات رخصة CDL لسائق في فرجينيا الغربية إذا سُمح بانقضاء شهادة الفاحص الطبي المطلوبة؟","options":["يُخفَّض تصنيف رخصة CDL فيفقد الشخص امتيازات القيادة التجارية حتى تتوفّر شهادة صالحة في الملف","لا يتغيّر شيء حتى التجديد التالي كل خمس سنوات","يُعاد تصنيف السائق تلقائيًا كسائق مُستثنى","يحصل السائق على تمديد تلقائي لمدة سنة واحدة"],"explanation":"إذا انقضت الشهادة الطبية لسائق غير مُستثنى، تُخفّض فرجينيا الغربية تصنيف رخصة CDL، فتُزيل الامتيازات التجارية حتى تُقدَّم شهادة سارية. المصدر: صفحة CDL في WV DMV؛ أحكام التصديق الطبي في FMCSA 49 CFR 383.73."},"99":{"q":"في فرجينيا الغربية، أي مجموعة من المستندات تُعد جزءًا من المتطلب الأساسي للتقدّم بطلب للحصول على رخصة CDL؟","options":["إثبات الهوية/الوضع القانوني، وإثبات الإقامة في فرجينيا الغربية، والتحقق من الضمان الاجتماعي، وطلب CDL المكتمل","جواز سفر وبطاقة ائتمان فقط","سند ملكية مركبة وإثبات تأمين فقط","خطاب من صاحب العمل وشهادة الثانوية العامة"],"explanation":"يجب على مقدّمي طلبات CDL في فرجينيا الغربية تقديم إثبات الهوية والمواطنة الأمريكية أو الإقامة الدائمة القانونية، وإثبات الإقامة في فرجينيا الغربية، والتحقق من رقم الضمان الاجتماعي، وطلب CDL مكتمل (إضافة إلى المستندات الطبية/التصديق الذاتي). المصدر: صفحة CDL في WV DMV."}}};
